-- =============================================================
-- 유럽여행 가이드북 새 DB 스키마
-- Supabase SQL Editor에 전체 붙여넣기 후 Run
-- =============================================================

-- 기존 테이블 정리
DROP TABLE IF EXISTS guide_tips CASCADE;
DROP TABLE IF EXISTS guide_accommodations CASCADE;
DROP TABLE IF EXISTS guide_restaurants CASCADE;
DROP TABLE IF EXISTS guide_spots CASCADE;
DROP TABLE IF EXISTS guide_schedules CASCADE;
DROP TABLE IF EXISTS guide_days CASCADE;

-- 1. guide_days (하루 기본 정보)
CREATE TABLE guide_days (
  id           uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  day_number   integer NOT NULL UNIQUE,
  travel_date  date NOT NULL,
  location     text NOT NULL,
  subtitle     text DEFAULT '',
  part_number  integer DEFAULT 1,
  drive_info   text DEFAULT '',
  highlights   text[] DEFAULT '{}',
  cover_image_url text DEFAULT '',
  updated_at   timestamptz DEFAULT now()
);

-- 2. guide_schedules (시간대별 일정)
CREATE TABLE guide_schedules (
  id           uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  day_id       uuid REFERENCES guide_days(id) ON DELETE CASCADE,
  day_number   integer NOT NULL,
  time_slot    text DEFAULT '',
  place_name   text NOT NULL,
  activity     text DEFAULT '',
  cost         text DEFAULT '',
  duration_min integer DEFAULT 0,
  sort_order   integer DEFAULT 0,
  is_confirmed boolean DEFAULT true,
  memo         text DEFAULT ''
);

-- 3. guide_spots (관광지)
CREATE TABLE guide_spots (
  id            uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  day_id        uuid REFERENCES guide_days(id) ON DELETE CASCADE,
  day_number    integer NOT NULL,
  name          text NOT NULL,
  category      text DEFAULT '',
  description   text DEFAULT '',
  opening_hours text DEFAULT '',
  entrance_fee  text DEFAULT '',
  address       text DEFAULT '',
  website       text DEFAULT '',
  tips          text DEFAULT '',
  sort_order    integer DEFAULT 0
);

-- 4. guide_restaurants (식당)
CREATE TABLE guide_restaurants (
  id            uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  day_id        uuid REFERENCES guide_days(id) ON DELETE CASCADE,
  day_number    integer NOT NULL,
  name          text NOT NULL,
  category      text DEFAULT '',
  cuisine       text DEFAULT '',
  description   text DEFAULT '',
  price_range   text DEFAULT '',
  opening_hours text DEFAULT '',
  must_order    text DEFAULT '',
  reservation   boolean DEFAULT false,
  sort_order    integer DEFAULT 0
);

-- 5. guide_accommodations (숙소)
CREATE TABLE guide_accommodations (
  id          uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  day_id      uuid REFERENCES guide_days(id) ON DELETE CASCADE,
  day_number  integer NOT NULL,
  name        text NOT NULL,
  type        text DEFAULT '',
  address     text DEFAULT '',
  check_in    text DEFAULT '',
  check_out   text DEFAULT '',
  cost        text DEFAULT '',
  parking     boolean DEFAULT false,
  ztl_warning boolean DEFAULT false,
  memo        text DEFAULT ''
);

-- 6. guide_tips (팁·경고·체크리스트)
CREATE TABLE guide_tips (
  id          uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  day_id      uuid REFERENCES guide_days(id) ON DELETE CASCADE,
  day_number  integer NOT NULL,
  type        text DEFAULT 'tip',
  title       text DEFAULT '',
  content     text DEFAULT '',
  sort_order  integer DEFAULT 0
);

-- RLS 설정
ALTER TABLE guide_days          ENABLE ROW LEVEL SECURITY;
ALTER TABLE guide_schedules     ENABLE ROW LEVEL SECURITY;
ALTER TABLE guide_spots         ENABLE ROW LEVEL SECURITY;
ALTER TABLE guide_restaurants   ENABLE ROW LEVEL SECURITY;
ALTER TABLE guide_accommodations ENABLE ROW LEVEL SECURITY;
ALTER TABLE guide_tips          ENABLE ROW LEVEL SECURITY;

-- 공개 읽기 정책
CREATE POLICY "public read" ON guide_days          FOR SELECT USING (true);
CREATE POLICY "public read" ON guide_schedules     FOR SELECT USING (true);
CREATE POLICY "public read" ON guide_spots         FOR SELECT USING (true);
CREATE POLICY "public read" ON guide_restaurants   FOR SELECT USING (true);
CREATE POLICY "public read" ON guide_accommodations FOR SELECT USING (true);
CREATE POLICY "public read" ON guide_tips          FOR SELECT USING (true);

-- 쓰기 정책
DO $$ DECLARE t text;
BEGIN FOR t IN SELECT unnest(ARRAY['guide_days','guide_schedules','guide_spots',
  'guide_restaurants','guide_accommodations','guide_tips']) LOOP
  EXECUTE format('CREATE POLICY "anon write" ON %I FOR ALL USING (true) WITH CHECK (true)', t);
END LOOP; END $$;

