  (67, '20:00', '(여행 마지막 2일 전 고별', '드 부르고뉴 (부르고뉴 달팽이) + 피노 누아', '-', 400),
  (68, '09:30', '감싸는 바로크 광장. 아침 태양 아래 황금빛 석재', '-', '', 0),
  (68, '10:00', '드 부르고뉴 + 보자르', '볼드의 묘소 + 플랑드르 화파 회화 + 부르고뉴', '-', 1),
  (68, '12:00', '찾기 (La Chouette de', '-', '', 2),
