  (68, '10:30', '기차역 또는 리옹-생텍쥐페리 공항 반납. 차량', '-', '', 9),
  (68, '12:00', '공항 이동 + 체크인', '3시간 전 공항 도착. 체크인 + 수하물 위탁 (와인', '-', 10)
