-- 관광지 INSERT
INSERT INTO guide_spots (day_id, day_number, name, category, description, opening_hours, entrance_fee, address, tips, sort_order)
SELECT gd.id, s.day_number, s.name, s.category, s.description, s.opening_hours, s.entrance_fee, s.address, s.tips, s.sort_order
FROM guide_days gd
JOIN (VALUES
  (1, '리스카 차량 인수 — 푸조 오픈 유럽', '차량인수', 'Malpensa, Ferno VA 21010 69일 여행의 발인 푸조 3008 가솔린 하이브리드를 인수하는 가장 중요한 첫 번째 미션. 예약번호 11543743, 계약자 Mr. MOON JANGHWAN으로 등록. 차량 인수 시 외관 전체 촬영이 귀국 시 분쟁', '말펜사 공항 내 터미널 1 도착 로비', '무료', 'Terminal 1, Aeroporto di Milano', '①플래시로 사방 찍기 ②흠집·긁힘 발견 시 직원 서명+사진 동시 ③형광 안전조끼·삼각대·구급상자 트렁크 확인 ④국제면허+한국면허+여권 3종 제시', 0),
  (2, '밀라노 두오모', '성당·전망', '09:00~21:00 (마지막 입장 20:00) 1386년 착공, 1965년 완공. 세계에서 세 번째로 큰 고딕 성당. 옥상 테라스에서 알프스까지 보이는 밀라노 전경을 조망. 첨탑 135개가 숲처럼 펼쳐진 광경은 이탈리아 북부 여행의 하이라이트.', '성당 09:00~19:00 / 옥상', 'EUR26 (W45,500)', 'Piazza del Duomo, 20122 Milano MI,', 'Duomo Pass Lift(엘리베이터 포함) 사전 예약 필수. 옥상 통로 너비 30~50cm — 고소공포증 주의. 계단권(14)은 체력 소모 큼, 반드시 엘리베이터권 선택.', 0),
  (2, '갈레리아 비토리오 에마누엘레 II', '쇼핑·건축', '1867년 착공, 1877년 완공. 유럽에서 가장 오래된 쇼핑 아케이드. 철제 유리 돔이 인상적인 신르네상스 양식 건축물. Prada·Louis Vuitton·Versace 1호점과 역사적인 카페 Biffi·Camparino이 입점. 두오모 광장과 Zucca(1867년)에서 에스프레소 2~3 추천.', '24시간 개방 (매장은 10:00~20:00)', '무료', 'Piazza del Duomo, 20123 Milano MI,', '중앙 팔각형 공간 타일의 황소 그림 위에 발뒤꿈치 올리고 세 번 돌면 행운 — 현지 전통. 역사적 카페 Zucca(1867년)에서 에스프레소 2~3 추천.', 1),
  (2, '라 스칼라 극장', '문화·공연', '1778년 개관한 세계 3대 오페라 극장. 카루소·카라스·파바로티 등 전설적 음악가들이 무대에 올랐던 역사적 공간. 신고전주의 외관은 밀라노 문화의 상징. 내부 스칼라 박물관에는 공연 역사 유물·의상·악기 등 소장.', '박물관 10:00~17:30 (화~일, 월', '무료', 'Piazza della Scala, 20121 Milano MI,', '외관 무료. 박물관 9. 광장(Piazza della Scala) 벤치에서 외관 감상 + 레오나르도 다빈치 동상 앞 사진 추천. 갈레리아에서 도보 2분.', 2),
  (2, '브레라 지구', '예술가 골목', '밀라노 최고의 보헤미안 지구. Via Brera·Via Fiori Chiari·Via Madonnina 골목에 갤러리·앤티크숍·편집샵·카페가 즐비. 핀코테카 디 브레라 미술관(라파엘로·카라바조 소장)이 중심. 두오모 북쪽 도보 15분 거리. 오후 햇살에 골목 걸을 때 가장 아름다운 밀라노의 면모.', '미술관: 화~일 08:30~19:15 (월', '무료', 'Via Brera, 20121 Milano MI, 이탈리아', '돌바닥이므로 운동화 필수. 핀코테카 미술관 15(체력 여유 시). 골목 카페에서 카푸치노 한 잔 마시며 현지인처럼 쉬는 것도 좋은 선택.', 3),
  (2, '나빌리오 운하 & 아페리티보', '운하·문화체험', '12세기에 조성된 밀라노 운하 시스템. Naviglio Grande를 따라 색색의 건물·노천 바·갤러리가 이어지는 낭만적인 지구. 17:30~19:30 아페리티보 타임에 Spritz 한 잔 주문하면 뷔페식 안주(스낵·올리브·핑거푸드)가 무료 제공. 석양빛 운하 반영을 바라보며 즐기는 이탈리아 저녁 문화 체험.', '바 17:00~24:00 / 아페리티보', 'EUR20 (W35,000)', 'Alzaia Naviglio Grande, 20144 Milano', '2인 기준 Spritz 2잔 14~20. 안주 뷔페 무료(선착순). Mag Cafe(45.4535, 9.1728) 추천. 소매치기 많은 지역 — 크로스백 앞으로, 핸드폰 테이블 방치 금지.', 4),
  (3, '최후의 만찬', '비용', '레오나르도 다빈치가 1495~1498년에 그린 세계 최고의 걸작 벽화. 산타 마리아 델레 그라치에 수도원 식당 북쪽 벽에 위치. 15분 단위로 30명씩만 입장 가능하므로 사전 예약 필수. 습기에 약한 템페라 기법으로 그려져 항온항습 유지를 위해 2중 에어록을 통과해야 한다.', '화~일 08:15~19:00 (월요일 휴관),', '무료', 'Piazza di Santa Maria delle Grazie 2,', '예약 없이는 입장 절대 불가. 방문 3~6개월 전 예약 권장. 관람 시간은 15분. 사진 촬영 허용(플래시 금지). 영어 오디오 가이드 추가 3.', 0),
  (3, '스포르체스코 성', '비용', '15세기 밀라노 공국의 스포르차 가문이 건설한 거대 요새 성. 내부에 미켈란젤로의 마지막 조각 ''론다니니의 피에타''를 포함한 여러 박물관이 있다. 붉은 벽돌로 지어진 웅장한 외관과 해자 터가 인상적이며, 60대 부부에게는 광장 내 산책만으로도 충분히 즐길 수 있다.', '성내 광장 07:00~19:30 (무료),', '무료', 'Piazza Castello, 20121 Milano', '매월 첫째 화요일 오후 2시 이후 박물관 무료 개방. 성내 광장 벤치에서 잠시 쉬어가기 좋음. 스포르체스코 성에서 셈피오네 공원까지 도보 2분.', 1),
  (3, '셈피오네 공원', '비용', '스포르체스코 성 뒤편에 펼쳐진 약 38만㎡의 광대한 도심 공원. 영국식 정원 양식으로 조성되어 구불구불한 산책로와 연못, 잔디밭이 자연스럽게 어우러진다. 공원 중심부의 평화의 아치(Arco della Pace)까지', '06:30~21:00 (계절별 상이)', '무료', 'Piazza Sempione, 20154 Milano', '공원 내 Bar Bianco 카페에서 휴식 가능. 자갈길이 많으니 편한 신발 필수. 소매치기 주의 — 소지품 관리 철저.', 2),
  (3, '보스코 버티칼레', '비용', '2014년 완공된 세계적으로 유명한 수직 정원 아파트. 높이 110m·76m 두 동에 걸쳐 약 900그루의 나무, 5,000그루의 관목, 11,000여 본의 지피식물이 심어져 있다. 스테파노 보에리 아키텍티 설계. CNN이 선정한 세계에서 가장 아름다운 건물 중 하나.', '외관 상시 관람 가능', '무료', 'Via Gaetano De Castillia 11, 20124', 'Piazza Gae Aulenti에서 서쪽으로 도보 5분. Porta Nuova 방향에서 보는 뷰가 가장 아름다움. 내부 입장 불가 — 외관 촬영 포인트 선점이 관건.', 3),
  (3, '피아자 가에 아울렌티', '비용', '밀라노 Porta Nuova 재개발 지구의 중심 광장. 원형 분수와 현대적 건축물들이 어우러진 밀라노 신도심의 상징. UniCredit Tower를 비롯한 고층 빌딩들이 둘러싼 광장에서 밀라노의 현재와 미래를 한눈에 볼 수 있다. 영업시간     월~금 12:30~14:30,                     휴무', '상시', '무료', 'Piazza Gae Aulenti, 20124 Milano', '광장 주변 카페와 레스토랑 가격이 합리적. Eataly 밀라노 Smeraldo 지점이 근처에 있어 이탈리아 식품 쇼핑 가능.', 4),
  (4, '푸니콜라레 치타', '비용', '08:30~23:30 (5~10분 간격 운행) 베르가모 하부 도시(치타 바사)와 중세 상부 도시(치타 알타)를 연결하는 100년 역사의 케이블카. 편도 약 3분으로 가파른 언덕을 올라가며 도중에 도시 전경이 펼쳐진다. 60대 부부에게 최적의 이동수단 —', '월~토 07:00~00:30 / 일', '무료', 'Viale Vittorio Emanuele II, 24121', 'ATB 앱(Chat&Go;)이나 현장 발매기에서 티켓 구매. 성수기 주말 오전에는 줄이 생기므로 10분 일찍 도착 권장.', 0),
  (4, '피아자 베키아', '비용', '치타 알타의 심장부이자 베르가모 최고의 광장. 12세기 팔라초 델라 라조네(재판소)와 18세기 팔라초 누오보(도서관)가 마주 보고, 중앙에 콘타리니 분수(1780년)가 자리한다. 르 코르뷔지에가 ''세계에서 가장 아름다운 광장''이라 극찬한 곳. 노천카페에서 커피 한 잔 하며 중세 분위기를 만끽하기에 최고.', '상시', '무료', 'Piazza Vecchia, 24129 Bergamo BG', '광장 주변 카페 가격은 시내 대비 다소 높음(에스프레소 2~3). 아침 10시 이전 방문 시 한산함.', 1),
  (4, '산타 마리아 마조레 대성당', '비용', '14:30~18:00 / 일 09:00~13:00, 1137년 착공한 베르가모의 로마네스크 성당. 내부에 플랑드르 태피스트리(16~17세기)와 도니제티 작곡가의 묘소가 있다. 외관의 화려한 대리석 장식과 내부의 금박 장식이 인상적. 옆의 콜레오니 예배당과', '월~토 09:00~12:30,', '무료', 'Piazza Duomo, 24129 Bergamo BG', '내부 사진 촬영 가능. 미사 시간에는 관광 입장 제한될 수 있음.', 2),
  (4, '콜레오니 예배당', '비용', '14:00~18:30 (월요일 휴관, 3~10월 용병대장 바르톨로메오 콜레오니(1400~1475)가 자신의 묘소로 건립한 르네상스 최고 걸작 중 하나. 조반니 안토니오 아마데오가 설계하여 1476년 완공. 흰색·빨간색·검은색 대리석이 기하학 무늬를 이루는', '화~일 09:00~12:30,', '무료', 'Piazza Duomo 1, 24129 Bergamo BG', '산타 마리아 마조레 성당 바로 옆에 위치해 함께 관람 가능. 내부에 콜레오니 기사 조각상과 금도금 장식 천장이 있음.', 3),
  (4, '베네치아 성벽', '비용', '16세기 베네치아 공화국이 오스만 제국 위협에 대비해 축조한 방어 성벽. 전체 길이 약 6km, 두께 최대 40m. 2017년 유네스코 세계문화유산 등재. 성벽 위 산책로에서 베르가모 하부 도시와 롬바르디아 평원의 부부에게는 일부 구간(전망 좋은 포르타 산 자코모~포르타 산탄드레아)만 걷는 것 추천.', '상시 (성벽 위 산책로)', '무료', 'Via Rocca, 24129 Bergamo BG', '치타 알타에서 Porta San Giacomo 방향으로 나가면 성벽 산책 시작. 전체 일주는 약 1~2시간. 60대 부부에게는 일부 구간(전망 좋은 포르타 산 자코모~포르타 산탄드레아)만 걷는 것 추천.', 4),
  (4, '토레 델 캄파노네', '비용', '피아자 베키아에 솟은 54m 높이의 시계탑. 350년 넘게 매일 밤 10시 정각에 100번의 종을 울리는 것으로 유명. 엘리베이터를 타고 전망대에 오르면 베르가모 치타 알타 전체와 롬바르디아 평원, 날씨 좋은 날에는 영업시간    화~일 12:00~14:30,                  휴무', '화~금 09:30~18:00 / 토·일', '무료', 'Piazza Vecchia, 24129 Bergamo BG', '계단(230개) 또는 엘리베이터 선택 가능. 60대 부부에게는 엘리베이터 강력 추천. 전망대 폭이 좁아 혼잡 시 대기 발생.', 5),
  (6, '몬탈레그로 케이블카', '비용', '1934년 개통, 라팔로 해변에서 해발 612m 몬탈레그로 성지까지 2,350m를 7분 만에 오르는 케이블카. 티굴리오 만 전체와 라팔로, 산타 마르게리타, 멀리 포르토피노 반도까지 펼쳐지는 파노라마가 압권. 정상에 1557년 성모 발현을 기념해 세운 몬탈레그로 성지가 있어 순례지로도 유명.', '09:00~12:30, 14:00~18:00', '무료', 'Piazza Solari 2, 16035 Rapallo GE', '오전 9시 개장과 동시에 이용하면 대기 없이 탑승 가능. 바람이 강한 날은 운행 중단될 수 있으니 날씨 확인. 정상 기온이 해변보다 5~8도 낮으므로 가벼운 겉옷 지참.', 0),
  (6, '노스트라 시뇨라 디 몬탈레그로 성지', '비용', '1557년 한 농부에게 성모 마리아가 발현했다는 전설이 깃든 성지. 케이블카 상부역 바로 옆에 위치해 걷지 않고도 방문 가능. 17세기 건설된 바로크 양식 성당 내부에 비잔틴 성화상이 보존되어 있다. 정상 테라스에서의 리구리아 해안 조망은 이탈리아 최고 중 하나.', '07:00~19:00', '무료', 'Via Santuario di Montallegro, 16035', '성지 내부 복장 규정 있음 — 민소매·반바지 금지. 정상 카페(Bar Montallegro)에서 라팔로 만을 바라보며 커피 한 잔.', 1),
  (6, '포르토피노', '비용', '세계적으로 유명한 이탈리아 리비에라의 보석. 이탈리아 어부 마을 특유의 파스텔 톤 건물들이 작은 항구를 에워싼 그림 같은 풍경. 헤밍웨이, 버튼, 테일러 등 세기의 명사들이 사랑한 곳. 차가 없는 마을이라 오직 페리나 도보(산타 마르게리타에서 3km 해안 트레킹)로만 접근 가능. 항구 주변 카페와 부티크 산책이', '상시 (페리 운항 시간 내)', '무료', 'Piazzetta di Portofino, 16034', '포르토피노 내 식사·커피 가격은 라팔로의 2~3배. 음료 한 잔 정도만 즐기고 식사는 라팔로에서 할 것. 카스텔로 브라운(성) 입장은 계단 많아 60대 부부에게 비추. 피아체타 광장 벤치에서 항구 감상이 베스트.', 2),
  (6, '산 조르조 교회', '비용', '항구 언덕 위에 자리한 포르토피노의 수호성인 교회. 1133년 십자군 전사들이 성 게오르기우스의 유해를 모셔와 세운 것이 기원. 교회 앞 테라스에서 항구 전경을 내려다보는 시점이 포르토피노 최고의 포토 스팟. 계단으로 5분이면 도달하므로 60대 부부도 무리 없음.', '09:00~18:00', '무료', 'Via alla Chiesa di San Giorgio, 16034', '교회 앞 잔디밭에서 항구와 바다를 배경으로 사진 촬영 명소. 오후 햇살에 항구 건물들이 황금빛으로 빛나는 시간대가 최고.', 3),
  (7, '몬테로소 알 마레', '비용', '친퀘 테레 5개 마을 중 가장 크고 평탄한 마을. 모래 해변(페지나)과 조약돌 해변이 공존하며 식당·카페가 가장 많아 60대 부부에게 최적. 구도심(Centro)과 신도시(Fegina)를 연결하는 바위 터널을 걸어서 통과하는 것이 포인트. 유럽연합 PDO 인증을 받은 몬테로소 앤초비(Acciughe di Monterosso)의 본고장.', '상시', '무료', 'Via Fegina, 19016 Monterosso al', '역에서 페지나 해변까지 평지. 구도심 진입은 터널 통과 — 계단 없음. 5월은 성수기 시작 전이라 여유로움. 앤초비 기념품 구입 추천.', 0),
  (7, '베르나차', '비용', '친퀘 테레 5개 마을 중 경관이 가장 아름답다고 꼽히는 마을. 기차역에서 내리면 바로 작은 골목길을 따라 5분 걸으면 항구 광장에 도달. 바다로 돌출된 자연 항구를 형형색색 중세 건물들이 에워싼 그림 같은 풍경. 절벽 위 두오리아 성탑(Torre Doria)에서 내려다보는 전경도 장관이나 60대에게는 계단이 많아 선택사항.', '상시', '무료', 'Piazza Marconi, 19018 Vernazza SP', '기차역→항구 광장: 골목길 도보 5분 (계단 거의 없음). 항구 수영 가능(5월은 다소 쌀쌀). 성탑 오르기는 계단 많아 체력 고려.', 1),
  (9, '시에나 대성당', '비용', '13세기 착공한 이탈리아 고딕 건축의 최고 걸작. 흑백 줄무늬 대리석으로 만든 파사드와 56명 교황 흉상이 줄지어 선 내부, 56장의 대리석 상감 바닥화(Pavimento)가 압도적. 니콜라 피사노의 팔각형 설교단(1268년)은 유럽 조각 역사의 분기점으로 평가받는다. OPA SI PASS 구매 시 인접', '10:30~19:00 (계절별 상이, 목요일', '무료', 'Piazza del Duomo 8, 53100 Siena SI', 'OPA SI PASS가 압도적으로 경제적 (단품 합산 35 이상). 대리석 바닥화는 여름(8~9월)에만 전체 공개 — 5월은 부분 공개. 성당 내부 서늘하므로 가벼운 겉옷 지참.', 0),
  (9, '두오모 오페라 박물관', '비용', '두오모 오른쪽 미완성 증축 벽 내부에 자리한 박물관. 두치오 디 부오닌세냐의 ''마에스타(Maest, 1311년)'' 양면 제단화 원작이 핵심 소장품. 시에나 화파 회화의 정수를 감상할 수 있다.', '10:30~19:00', '무료', 'Piazza del Duomo 8, 53100 Siena SI', '마에스타 제단화는 2층 전시실에 위치. 조명이 어두우므로 눈이 익숙해질 시간 필요.', 1),
  (9, '파치아토네 전망대', '비용', '14세기 대성당 증축 계획(더 큰 성당 건설)이 흑사병으로 중단되어 남겨진 미완성 거대 벽 위에 만든 전망대. 토레 델 만자보다 계단이 적으면서 시에나 구시가지 전경을 360도로 감상 가능. 캄포 광장과 시청 탑이 한눈에 보이는 시에나 최고의 전망 포인트 중 하나.', '10:30~18:00', '무료', 'Piazza del Duomo, 53100 Siena SI', '계단 약 130개 — 토레 델 만자(400개) 대비 훨씬 적음. 60대 부부에게 전망 즐기기 최적. 난간 없는 구간 있으므로 주의.', 2),
  (9, '캄포 광장', '비용', 'UNESCO 세계유산. 유럽에서 가장 아름다운 중세 광장으로 꼽히는 부채꼴 형태의 광장. 1293년 이후 시에나 공화국의 중심지로 기능했으며 중앙의 가이아 분수(Fonte Gaia, 1419년 복제품)와 고딕 양식의 팔라초 푸블리코(시청, 1342년)가 광장을 에워싸고 있다.', '24시간', '무료', 'Piazza del Campo, 53100 Siena SI', '광장은 경사져 있어 한쪽에서 반대쪽을 내려다보는 구도 사진 추천. 주변 카페 테라스 이용 시 1인당 5~8 서비스 차지 각오.', 3),
  (9, '산타 마리아 델라 스칼라', '비용', '두오모 광장 맞은편 13세기 창립 중세 병원 건물을 개조한 대형 박물관. 지하 ''필그림 홀(Pellegrinaio)''의 15세기 프레스코 벽화가 핵심. 시에나의 도시 역사와 의료·사회 복지 역사를 입체적으로 전시. 지하 구조물', '10:30~19:30', '무료', 'Piazza del Duomo 2, 53100 Siena SI', '두오모 관람 후 바로 옆이므로 연계 방문 효율적. 지하 구역은 시원하고 조명이 독특해 분위기 있음.', 4),
  (9, '산 도메니코 성당', '비용', '시에나의 수호성인 성녀 카테리나(1347~1380)와 깊이 연결된 고딕 성당. 성녀의 두개골 성유물이 보관된 채플과 15세기 안토니오 소도마의 프레스코화가 있다. 언덕 위에 위치해 두오모와 시에나 서쪽 전경을 영업시간     12:30~14:30, 19:30~22:00              휴무', '07:00~18:30', '무료', 'Piazza San Domenico, 53100 Siena SI', 'Santa Caterina 주차장 에스컬레이터 바로 위에 위치 — 주차 후 첫 방문지로 동선 최적. 내부 성유물 채플은 경건하게 관람.', 5),
  (10, '카펠라 디 비탈레타', '비용', '밀밭과 구릉 한가운데 홀로 선 작은 예배당. 양쪽으로 사이프러스 나무가 줄지어 서 있는 구도가 발도르차 대표 사진으로 전 세계에 알려진 곳. 1480년경 건립. SP146에서 비포장 진입로(약 200m)로 들어가면 도달. 이른 아침 안개가 걷힐 무렵 황금빛 빛살이 드는 시간대가 최고.', '상시 (외관)', '무료', 'SP146, 53026 San Quirico d''Orcia SI', '비포장 진입로 진입 시 저속 운전. 리스카(3008)로 충분히 접근 가능. 해 뜨고 1~2시간 후 역광 없이 촬영 최적.', 0),
  (10, '산 키리코 도르차', '비용', '중세 성벽이 온전히 남아 있는 발도르차의 관문 소도시. 12세기 콜레지아타 성당의 세 개 정문(포르탈레)이 로마네스크·고딕 양식 조각의 걸작으로 꼽힌다. 성벽 안 호르티 레오니니(Horti Leonini) 16세기 이탈리아식 정원은 탁 트인 발도르차 풍경과 함께 산책하기 좋다.', '상시', '무료', 'Piazza della Libert, 53027 San', '성벽 안 주차 불가 — 외곽 무료 주차장 이용. 콜레지아타 성당은 외관 장식이 핵심. 호르티 레오니니는 경사 없는 테라스 정원으로 60대 부부 산책 최적.', 1),
  (10, '바뇨 비뇨니', '비용', '세계에서 유일하게 광장 중앙에 온천 욕조가 있는 마을. 로렌초 데 메디치, 교황 피우스 2세, 성녀 카테리나가 치료 목적으로 방문한 기록이 있는 중세 온천 마을. 현재 광장의 온천수(52°C)는 수영 금지이나, 마을 아래 인공 탕(파르코 데이 물리니)에서 흘러내리는 온천수 체험 가능. 안드레이', '상시', '무료', 'Piazza delle Sorgenti, 53027 Bagno', '광장 온천 수영 절대 불가 (벌금 부과). 주변 온천 스파 호텔에서 유료 이용 가능. 마을 자체가 소규모라 30분이면 충분. 인접 계곡 테라체(Terrace) 뷰 포인트 추천.', 2),
  (10, 'SP146 사이프러스 가로수길', '비용', '산 키리코 도르차에서 피엔차 사이 약 12km 구간의 SP146 지방도. 구불구불한 언덕길을 따라 수백 년 된 사이프러스(Cupressus sempervirens) 나무들이 늘어서며 토스카나의 상징적 풍경을 만들어낸다. 유네스코 세계유산 발도르차의 핵심 경관. 봄철(4~6월) 녹색 밀밭과 사이프러스의 조합이 가장 아름답다.', '상시', '무료', 'SP146, 산 키리코~피엔차 구간', '차창을 열고 천천히 드라이브하며 촬영. 갓길 넓은 곳에서 주차 후 사진 가능. 맞은편 차량 주의 — 폭 좁은 구간 있음.', 3),
  (10, '피엔차', '비용', '교황 피우스 2세(1405~1464)가 르네상스 이상 도시로 설계한 유네스코 세계유산 소도시. 피콜로미니 광장을 중심으로 두오모·팔라초 피콜로미니·팔라초 코뮤날레가 완벽한 르네상스 구성을 이룬다. ''피엔차 페코리노 치즈(DOP)''의 본고장으로 거리 곳곳에 치즈 가게가 늘어서 있다.', '상시', '무료', 'Piazza Pio II, 53026 Pienza SI', '성벽 남쪽 벨베데레에서 발도르차 파노라마가 펼쳐짐 — 필수 방문. 페코리노 치즈 시식 무료 제공 가게 多. 피콜로미니 궁전 내부 투어 7.', 4),
  (11, '피아차 델라 치스테르나', '비용', '13세기 우물(치스테르나)이 중앙에 자리한 산 지미냐노의 심장 광장. 삼각형 모양 광장 주변으로 중세 탑들이 촘촘히 솟아 있어 어느 각도에서 봐도 그림 같은 풍경. 한때 72개에 달했던 탑은 현재 14개가 남아', '상시', '무료', 'Piazza della Cisterna, 53037 San', '광장 모퉁이 카페 테라스에서 탑 배경 사진 촬영. 토요일 오전 장시가 열려 현지 농산물 구경 가능.', 0),
  (11, '두오모', '비용', '12세기 로마네스크 성당. 내부 전체를 덮는 구약성서(왼쪽 벽)·신약성서(오른쪽 벽) 프레스코 연작과 최후의 심판(Barna da Siena, 1380년)이 압도적. 성당 자체보다 내부 그림이 더 유명한 ''그림 박물관'' 같은', '10:00~19:30 (토 10:00~17:30)', '무료', 'Piazza del Duomo, 53037 San', '토요일 오후 단체 관광객 혼잡 — 오전 개장 직후 방문 권장. 내부 사진 허용(플래시 금지).', 1),
  (11, '토레 그로사 전망대', '비용', '산 지미냐노에서 유일하게 일반 공개되는 탑(54m). 계단 218개. 정상에서 나머지 13개 탑과 토스카나 구릉, 날씨 좋은 날 시에나까지 조망 가능.', '10:00~19:30', '무료', 'Piazza del Duomo 2, 53037 San', '계단 218개 — 60대 부부 무리하지 말 것. 중간 층에서 조망만 해도 충분. 파치아토네(시에나)보다 계단 많음.', 2),
  (11, '젤라테리아 돈돌리', '비용', '세르지오 돈돌리가 2006·2010·2015년 세계 젤라토 챔피언십을 제패한 전설적인 젤라테리아. 산 지미냐노 방문객이라면 줄 서서라도 먹어야 하는 필수 코스. 대표 맛: 자프란 크로칸테(Crema di Santa Fina), 리볼라 영업시간    매일 12:00~15:00, 19:00~22:00   휴무', '09:00~22:00', '무료', 'Piazza della Cisterna 4, 53037 San', '토요일 성수기 대기 10~20분 각오. 2스쿱(콘/컵) 추천. 현금만 가능할 수 있음.', 3),
  (12, '몬탈치노 로카 에노테카', '비용', '1361년 시에나 공화국이 건립한 요새 내부에 자리한 공식 에노테카. 브루넬로 디 몬탈치노 DOCG, 로소 디 몬탈치노 DOC를 포함해 수십 종의 몬탈치노 와인을 글라스 단위로 시음 가능. 요새 테라스에서 발도르차 파노라마를 감상하며 마시는 와인이 압권.', '매일 09:00~20:00', '무료', 'Piazzale Fortezza, 53024 Montalcino', '일요일도 정상 운영. 시음 세트(3잔) 약 15. 마음에 드는 와인은 현장 구입 가능. 브루넬로 정규 와인(40~100/병)과 로소(15~25/병) 가격 차이 큼.', 0),
  (12, '산탄티모 수도원', '비용', '15:00~18:30 / 일 15:15~18:30 Castelnuovo dell''Abate SI 카를로 대제가 812년 창건했다는 전설을 품은 토스카나 최고의 로마네스크 수도원. 빛에 따라 색이 변하는', '월~토 10:00~13:00,', '무료', 'Loc. Sant''Antimo, 53024', '일요일 15:15 이후 입장 (오전 미사 후 개방). 수도원 성가 시간표 확인 후 방문 조율 — 그레고리오 성가 생음악 체험 권장. 주변 비포장 주차장 무료.', 1),
  (14, '에르콜라노 고고학 공원', '비용', '09:00~17:00), 마감 90분 전 입장 서기 79년 베수비오 화산 폭발 당시 화쇄류(pyroclastic flow)에 순식간에 매몰되어 폼페이보다 훨씬 완벽하게 보존된 고대 로마 도시. 2층 건물의 목조 구조물, 색채 선명한 프레스코화, 탄화된 가구·음식 등이', '매일 09:00~19:30 (11월~3월', '무료', 'Corso Resina 187, 80056 Ercolano', '폼페이보다 관람객 적고 동선 짧음 — 오전 방문 시 30분 내 입장 가능. 목욕탕(Terme Suburbane) 내부 에로틱 모자이크 유일 보존. 매점·화장실 입구 부근 집중.', 0),
  (14, '폼페이 고고학 공원', '비용', '09:00~17:00), 마감 90분 전 입장 서기 79년 베수비오 화산 폭발로 화산재에 매몰된 인구 2만 명의 로마 도시. 포룸, 원형극장, 목욕탕, 창관(루파나레), 빌라 데이 미스테리의 디오니소스 의식 대형 프레스코 등 고대 일상이 그대로 남아있다.', '매일 09:00~19:30 (동절기', '무료', 'Via Villa dei Misteri 2, 80045 Pompei', '오디오 가이드 앱 ''Pompei Sites'' 무료 다운로드 권장. 마리나 문(입구)→ 포룸 → 아폴로 신전 → 목욕탕 → 루파나레 코스가 핵심 1.5시간 동선. 석조 보도블록 울퉁불퉁 — 편한 운동화 필수. 모자·물·선크림 필수 (그늘 거의 없음).', 1),
  (15, '포지타노', '비용', '아말피 해안 서쪽 끝의 절벽 마을. 분홍·노랑·주황색 파스텔 건물들이 가파른 절벽에 계단식으로 붙어 있는 이탈리아 해안 최고의 포토스팟. 스폰다 해변에서 수영·일광욕 가능. 레몬 향초·그릇·수공예품 쇼핑 거리로도 계단 많으니 내려갈 때만 도보, 올라올 때는 버스 이용.', '마을 상시 개방 / 해변 무료', '무료', '84017 Positano SA', '포지타노 마을 진입로 협소 — 위쪽 주차장(Via G. Marconi)에 주차 후 마을 버스 또는 도보 하강 권장. 60대는 계단 많으니 내려갈 때만 도보, 올라올 때는 버스 이용.', 0),
  (15, '아말피 성 안드레아 대성당', '비용', '9세기 창건, 아랍-노르만 양식의 독특한 이중 계단 외관이 인상적인 아말피의 상징. 예수의 12제자 중 첫 번째 제자 성 안드레아의 유해가 안치되어 있으며, 해상 공화국 시절 지중해를 호령하던 아말피의 영화를 상징한다. 경내 클로이스터(회랑)의 아랍풍 아치가 일품.', '매일 09:00~19:00 (11월~2월', '무료', 'Piazza del Duomo, 84011 Amalfi SA', '대성당 앞 광장(피아자 델 두오모)이 아말피의 중심. 계단 62개 — 60대 무릎 주의. 내부 예배 시간(11:00, 18:00)에는 관광 제한.', 1),
  (15, '라벨로 빌라 루폴로', '비용', '13세기 루폴로 가문의 별장 정원. 리하르트 바그너가 1880년 방문 후 ''파르지팔'' 클링조르의 정원에 영감을 받았다. 테라스에서 내려다보는 티레노 해 전망이 압도적. 매년 7~8월 라벨로 음악 페스티벌의 야외 라벨로 주차: Piazza Duomo 인근 공영 주차장 2~3/시간.', '매일 09:00~20:00 (계절별 상이)', '무료', 'Piazza del Duomo, 84010 Ravello SA', '빌라 침브로네(Villa Cimbrone)의 ''무한의 테라스(Terrazza dell''Infinito)''도 필수. 두 빌라 도보 15분 거리. 라벨로 주차: Piazza Duomo 인근 공영 주차장 2~3/시간.', 2),
  (16, '나폴리 국립 고고학 박물관', '비용', '세계에서 가장 중요한 그레코-로마 유물 박물관. 폼페이·에르콜라노·스타비아에서 발굴된 모자이크·조각·프레스코·일상 도구의 원본이 소장되어 있다. 하이라이트: 알렉산드로스 대왕의 이소스 전투 모자이크(폼페이 파우누스의 집 출토), 파르네세 헤라클레스(2.3m 대리석 조각), 비밀의 방(에로틱 고대', '수~월 09:00~19:30 (화요일 휴무),', '무료', 'Piazza Museo Nazionale 19, 80135', '목요일 정상 영업 확인. 비밀의 방(Gabinetto Segreto)은 18세 이상만 입장, 사전 입장 신청 필요할 수 있음. 박물관 내 카페테리아 있음. 1층 조각→2층 모자이크→3층 프레스코 순 관람 권장.', 0),
  (16, '스파카나폴리', '비용', '고대 그리스 시대부터 내려온 나폴리의 대동맥. 직선으로 뻗은 좁은 골목이 나폴리 구도심을 동서로 가르는 모습이 위성사진에서 뚜렷하다. 제수 누오보(Gesu Nuovo) 성당의 다이아몬드 파사드, 산타 키아라(Santa Chiara) 수도원의 마욜리카 타일 회랑, 산 그레고리오 아르메노(San Gregorio Armeno)의 수공예', '상시 개방', '무료', 'Via Benedetto Croce / Via San Biagio', '나폴리 구도심 소매치기 주의 — 백팩은 앞으로 메고, 지갑·휴대폰 안쪽 주머니 보관. 산 그레고리오 아르메노 골목은 성수기에도 공방 영업 중. 스팡야롤로(나폴리 크림 도넛) 1.50 — 현지인 간식.', 1),
  (16, '카스텔 누오보', '비용', '1279년 샤를 1세 앙주 왕이 나폴리 항구 옆에 세운 중세 성곽. 5개의 원형 탑과 화려한 개선문(Arco Trionfale)이 인상적. 항구 전경과 베수비오 화산을 배경으로 촬영하는 포토스팟으로 인기. 내부는 나폴리 걸으면 나폴리 해안 산책로(Lungomare).', '월~토 09:00~18:00, 일요일 휴무', '무료', 'Piazza del Municipio, 80133 Napoli NA', '내부보다 외관 자체가 하이라이트. 성 앞 Piazza del Municipio에서 전체 성벽 사진 촬영. 항구 방향으로 5분 걸으면 나폴리 해안 산책로(Lungomare).', 2),
  (17, '카프리 섬', '비용', '티레노 해의 보석. 로마 황제 아우구스투스와 티베리우스가 별장을 둔 섬. 파라글리오니(3개의 바위 기둥), 푸른 동굴(Grotta Azzurra), 빌라 조비스(황제 별장 유적), 아나카프리의 몬테 솔라로 전망대가 대표 명소. 세계 최고급 리조트와 명품 부티크가 가득하지만 자연 경관이 압도적.', '섬 상시 개방 / 페리 06:00~22:00', '무료', '80073 Capri NA', '푸른 동굴(Grotta Azzurra)은 수위 높은 날 입장 불가 — 조건부 방문. 성수기 페리 혼잡 — 왕복 티켓 미리 예매. 섬 내 버스/택시 이용 (렌터카 반입 금지). 카프리 타운 명품 쇼핑 거리 Via Camerelle.', 0),
  (17, '몬테 솔라로 체어리프트', '비용', '아나카프리에서 카프리 최고봉 몬테 솔라로(589m)까지 11분간 오픈형 1인승 체어리프트. 정상에서 카프리 섬 전체, 나폴리 만, 아말피 해안, 맑은 날에는 시칠리아까지 보이는 360도 파노라마. 60대 부부가 도보 없이 즐길 수 있는 카프리 최고 뷰포인트.', '매일 09:30~17:00 (계절별 상이)', '무료', 'Piazza Vittoria, 80071 Anacapri NA', '체어리프트 1인 탑승 (2인 나란히 불가) — 고소공포증 있으면 주의. 정상 기온 카프리 타운보다 5~7도 낮음 — 가벼운 겉옷 지참. 내려오는 길 체어리프트 대신 도보 하산 가능 (35분, 비추 — 60대).', 1),
  (17, '파라글리오니 전망대', '비용', '카프리 마을에서 비아 트라가라(Via Tragara)를 따라 도보 20분 거리의 전망 포인트. 카프리의 상징인 파라글리오니 3개의 거대 바위 기둥과 에메랄드 지중해를 한눈에 담을 수 있다. 일몰 시간대에 더욱 환상적이나 당일치기 일정 상 오전 방문.', '상시 개방', '무료', 'Via Tragara, 80073 Capri NA', '비아 트라가라는 포장도로로 60대 도보 가능 (평탄한 편). 전망대 옆 카페 리도 델 파로 (Lido del Faro) 테라스에서 커피 한 잔 + 조망 추천.', 2),
  (19, '산타 마리아 델 이솔라 성당', '비용', '트로페아의 상징. 바다 쪽으로 돌출된 돌섬 위 절벽에 세워진 하얀 성당. 원래 섬이었지만 퇴적물로 육지와 연결됨. 7세기 창건, 현재 건물은 17세기 재건. 성당 앞 테라스에서 에메랄드 해변과 절벽이 어우러지는 풍경은 이탈리아 해안 사진 중 가장 많이 찍히는 장면 중 하나.', '매일 07:30~12:30 / 15:30~20:00', '무료', 'Via Portosalvo, 89861 Tropea VV', '성당 내부 예배 시간(일요일 10:00, 18:00) 관광 제한. 계단 약 50개 — 편한 신발. 성당 입구 옆 테라스 카페에서 커피 + 조망.', 0),
  (19, '카포 바티칼로 전망대', '비용', '트로페아에서 남서쪽으로 15km 지점의 칼라브리아 최서단 곶(串). 맑은 날에는 스트롬볼리·불카노·리파리 등 에올리에 화산섬들을 육안으로 볼 수 있다. 지중해 최고 투명도의 바다와 적벽 절벽이 조화를 이루는 곳. 영업시간     매일 12:30~15:00 / 19:30~22:30            휴무', '상시 개방', '무료', '89865 Ricadi VV', 'Faro di Capo Vaticano(등대) 주변 전망 포인트. 주차장 있음(무료). 차로 직접 진입 가능.', 1),
  (20, '니코테라 + 니코테라 마리나 해변', '비용', '트로페아 남쪽 25km의 조용한 칼라브리아 해안 마을. 언덕 위 중세 성곽 마을(Nicotera Alta)과 아래 해안 마을(Nicotera Marina)로 구성. 마리나 해변은 트로페아보다 덜 알려져 인파 없이 조용하게 즐길 수 있는 최고의 대안 해변. 모래 질감과 물 투명도 모두 최상급.', '상시 개방', '무료', '89844 Nicotera VV', '니코테라 마리나 → 니코테라 Alta 언덕 마을까지 차로 10분. 언덕 위에서 카라브리아 해안 파노라마. 성수기 7~8월이 아니면 해변 한산.', 0),
  (22, '카펠라 팔라티나', '비용', '09:00~13:00 (예배 후 관광) 루제로 2세가 1132~1143년에 건립한 궁전 예배당. 이슬람 목조 천장 + 비잔틴 황금 모자이크 + 노르만 건축이 혼합된 세계 유일의 건축 걸작. 6,000㎡의 황금 모자이크가 그리스도의 일생부터 노르만 왕실을', '월~토 09:00~17:00 / 일', '무료', 'Piazza del Parlamento 1, 90129', '수요일 정상 영업. 예약 없이도 입장 가능하나 성수기 대기 30분+. 사진 촬영 허용(플래시 금지). 입장 전 복장 규정: 어깨·무릎 노출 금지.', 0),
  (22, '팔레르모 대성당', '비용', '08:00~13:00, 16:00~19:00 9세기 아랍 모스크를 개조한 후 12~18세기에 걸쳐 증개축된 팔레르모의 성당. 외관은 아랍-노르만 양식의 굴곡미, 내부는 18세기 신고전주의로 개조. 루제로 2세·콘스탄체·프리드리히 2세 황제의 반암 석관이 왕릉', '월~토 07:00~19:00 / 일', '무료', 'Corso Vittorio Emanuele, 90134', '왕릉(Tesoro e Cripta) 별도 입장권 3. 지붕 테라스 계단 약 130개 — 60대 엘리베이터 없음 주의. 성당 광장 측면에서 아랍 문양 외벽 상세 촬영 가능.', 1),
  (22, '콰트로 칸티 + 라 마르토라나', '비용', '콰트로 칸티는 팔레르모 구시가 두 대로의 교차점에 세워진 바로크 건축 4면체(1608~1620). 팔레르모 4구역을 상징하는 조각이 3단으로 쌓인 독특한 도시 설계. 바로 옆 라 마르토라나(1143년)의 황금 비잔틴 모자이크는 카펠라 팔라티나에 필적하는 아름다움.', '라 마르토라나: 월~토 08:30~13:00', '무료', 'Piazza Vigliena, 90133 Palermo PA', '라 마르토라나 ''마르타판'' — 마르타판(marzapane)이 이 교회에서 비롯됐다는 설. 교회 앞 가게에서 시칠리아 마르지판 과자 구입 가능.', 2),
  (23, '몬레알레 대성당', '비용', '14:30~17:00 / 일 14:30~17:00 노르만 왕 굴리엘모 2세가 1172~1189년에 건립. 내부 전체를 덮는 6,000㎡ 황금 모자이크가 구약·신약 성경을 장면별로 묘사. 앱스의 거대한 그리스도 판토크라토르는 체팔루와 함께 비잔틴 모자이크 예술의 양대', '월~토 08:30~12:30 /', '무료', 'Piazza Guglielmo II 1, 90046', '목요일 정상 영업 확인. 오전 10시 이전 방문 시 단체 관광객 없어 조용히 감상 가능. 클로이스터(Chiostro)는 성당과 별도 입장권. 옥상 테라스 엘리베이터 없음 — 계단 200개 (60대 선택적으로). 버스 389번: 팔레르모 Piazza dell''Indipendenza 출발 30~40분 간격.', 0),
  (23, '부쿠치아 시장', '비용', '팔레르모 가장 오래된 시장. 14세기부터 운영. 르나토 구투조의 유명 회화 ''부쿠치아''(1974)의 배경. 오전에는 생선·해산물·향신료·채소 시장, 오후부터 청년들의 야외 바 문화 발생. 시칠리아 길거리 음식 영업시간      화~일 12:30~15:00 /                     휴무', '매일 07:00~14:00 (야간 바 문화는', '무료', 'Piazza Caracciolo, 90133 Palermo PA', '소매치기 주의 — 시장 내부 귀중품 관리. 즉석 해산물 튀김(Fritto di Mare) 4~6 도전. 수박(Anguria) 조각 2 — 시칠리아 여름 대표 간식.', 1),
  (24, '카푸친 수도원 카타콤베', '비용', '팔레르모 카푸친 프란치스코 수도회가 1599년부터 1880년대까지 운영한 지하 납골당. 8,000여 구의 방부 처리·미라화된 시신이 성직자·귀족·의사·군인·어린이 구역별로 복도 벽면에 세워져 있다. 특히 1920년 사망한 2세 여아 로살리아 롬바르도(Rosalia Lombardo)의 미라는 ''세계에서 가장 아름다운 미라''로 불리며', '매일 09:00~13:00 / 15:00~18:00', '무료', 'Piazza Cappuccini 1, 90129 Palermo', '충격적인 분위기지만 역사·인류학적 가치가 높은 필수 방문지. 사진 촬영 가능. 실내 기온 낮으니 가벼운 겉옷 권장. 어두운 분위기 — 심장이 약한 분 주의.', 0),
  (24, '테아트로 마시모', '비용', '1875~1897년 건립, 유럽에서 파리 오페라·빈 오페라 다음으로 세 번째로 큰 오페라 하우스. 신고전주의 외관과 붉은 금장식 내부가 장엄. 영화 ''대부 III''의 클라이맥스 장면 촬영지. 1,350석 대극장. 5~6월 시즌 티켓 구입 가능 — 비용 30~80. 외관은 무료로 광장에서 감상.', '가이드 투어: 화~일 09:30~17:30', '무료', 'Piazza Verdi, 90138 Palermo PA', '가이드 투어(한국어 없음 — 영어)로 내부 무대·분장실·VIP룸 견학. 공연 시즌(10~5월) 중이면 야간 오페라 티켓 구입 가능 — 비용 30~80. 외관은 무료로 광장에서 감상.', 1),
  (25, '몬델로 해변', '비용', '팔레르모 북서쪽 15km에 위치한 팔레르모 시민의 해수욕장. 백사장 길이 2km, 에메랄드빛 투명한 바닷물. 100년 넘은 바 카페 (Lo Stabilimento Mondelloo)와 아르누보 건물들이 해변 뒤에 늘어서 있다. 성수기(7~8월)는 극도로 혼잡하지만 5월 말은 아직 조용.', '상시 개방 (성수기 바 서비스', '무료', '90151 Mondello, Palermo PA', '오전 9~11시 이전 도착 시 자리 넉넉. 토요일이라 팔레르모 시민 많음 — 오전 일찍 도착 강력 권장. 해변 식사 — 즉석 아란치나 2, 그라니타(슬러시) 3.', 0),
  (25, '에리체', '비용', '해발 750m 바위 산 정상의 중세 마을. 페니키아·그리스·로마·아랍·노르만인이 차례로 거쳐 간 시칠리아 최고 역사 도시 중 하나. 안개가 자주 끼는 신비로운 분위기. 마리아 그람마티코(Maria Grammatico) 제과점의 전통 시칠리아 마르치판·쿠루쿠탕구·크로스타타가 유명.', '마을 상시 개방 / 케이블카', '무료', '91016 Erice TP', '케이블카는 바람이 강한 날 운행 중단 가능 — 출발 전 funivia-erice.it 확인. 마을 내 미리암 제과점(Pasticceria Maria Grammatico): Via Vittorio Emanuele 14. 시칠리아 전통 과자 선물 쇼핑 최적지.', 1),
  (26, '신전의 계곡', '비용', '기원전 6~5세기 그리스 식민 도시 아크라가스의 신전 군. 콘코르디아 신전은 세계에서 가장 잘 보존된 그리스 신전 중 하나로, 34개 원기둥이 거의 원형에 가깝게 서 있다. 붉은 황토색 사암 신전이 지중해를 내려다보는 능선에 줄지어 늘어선 광경이 압도적. UNESCO 세계문화유산.', '매일 08:30~20:00 (마지막 입장', '무료', 'Via Sacra, 92100 Agrigento AG', '일요일 오전 단체 관광 없이 비교적 한산 (현지 가족 단위 많음). 콘코르디아 신전 → 헤라 신전 → 헤라클레스 신전 → 올림피코 신전 순서 추천. 7~8월은 오전 7시 개방이지만 5월 말은 8:30 개방. 해 뜨는 방향이 아름다움 — 오전 방문 이유.', 0),
  (27, '갈레리아 레지오날레 — 팔라초 아바텔리스', '비용', '팔라초 아바텔리스(15세기 카탈루냐-고딕 궁전)에 위치한 시칠리아 지역 미술관. 주요 작품: 안토넬로 다 메시나의 ''수태고지''(1474, 시칠리아 르네상스 최고 걸작), 작자 미상의 ''죽음의 승리''(15세기 거대 프레스코, 흑사병 시대의 죽음의 기사가 사람들을 베는 장면), 부스토 디 에레오나(엘레오노라 다 아라고나', '화~토 09:00~18:30 / 일', '무료', 'Via Alloro 4, 90133 Palermo PA', '월요일 휴무 — 화요일 방문이었다면 놓쳤을 것. 에어컨 잘 작동하는 실내 — 더운 오후 완벽한 피난처. ''죽음의 승리'' 프레스코는 1층 대형 홀에 별도 전시, 충격적이고 강렬.', 0),
  (27, '카포 시장', '비용', '팔레르모 북쪽 Via Beati Paoli 일대의 재래시장. 발라로보다 더 현지인 비율 높은 시장. 식재료뿐 아니라 의류·잡화·기념품 판매. 시칠리아 향신료, 케이퍼(카페레), 오레가노, 특선 소시지(사르시치아) 구입 최적. 추천. 아몬드 피스타치오 페스토는 귀국 후 파스타에 활용 가능.', '월~토 07:00~13:30', '무료', 'Via Beati Paoli, 90134 Palermo PA', '월요일 정상 영업 확인. 기념품으로 시칠리아 케이퍼(염장/식초) 진공팩 3~5, 피스타치오 페스토 6~8 추천. 아몬드 피스타치오 페스토는 귀국 후 파스타에 활용 가능.', 1),
  (30, '리스카 차량 인수 — 푸조 오픈 유럽', '차량인수', 'Malpensa, Ferno VA 21010 69일 여행의 발인 푸조 3008 가솔린 하이브리드를 인수하는 가장 중요한 첫 번째 미션. 예약번호 11543743, 계약자 Mr. MOON JANGHWAN으로 등록. 차량 인수 시 외관 전체 촬영이 귀국 시 분쟁', '말펜사 공항 내 터미널 1 도착 로비', '무료', 'Terminal 1, Aeroporto di Milano', '①플래시로 사방 찍기 ②흠집·긁힘 발견 시 직원 서명+사진 동시 ③형광 안전조끼·삼각대·구급상자 트렁크 확인 ④국제면허+한국면허+여권 3종 제시', 0),
  (30, '밀라노 두오모', '성당·전망', '09:00~21:00 (마지막 입장 20:00) 1386년 착공, 1965년 완공. 세계에서 세 번째로 큰 고딕 성당. 옥상 테라스에서 알프스까지 보이는 밀라노 전경을 조망. 첨탑 135개가 숲처럼 펼쳐진 광경은 이탈리아 북부 여행의 하이라이트.', '성당 09:00~19:00 / 옥상', 'EUR26 (W45,500)', 'Piazza del Duomo, 20122 Milano MI,', 'Duomo Pass Lift(엘리베이터 포함) 사전 예약 필수. 옥상 통로 너비 30~50cm — 고소공포증 주의. 계단권(14)은 체력 소모 큼, 반드시 엘리베이터권 선택.', 1),
  (30, '갈레리아 비토리오 에마누엘레 II', '쇼핑·건축', '1867년 착공, 1877년 완공. 유럽에서 가장 오래된 쇼핑 아케이드. 철제 유리 돔이 인상적인 신르네상스 양식 건축물. Prada·Louis Vuitton·Versace 1호점과 역사적인 카페 Biffi·Camparino이 입점. 두오모 광장과 Zucca(1867년)에서 에스프레소 2~3 추천.', '24시간 개방 (매장은 10:00~20:00)', '무료', 'Piazza del Duomo, 20123 Milano MI,', '중앙 팔각형 공간 타일의 황소 그림 위에 발뒤꿈치 올리고 세 번 돌면 행운 — 현지 전통. 역사적 카페 Zucca(1867년)에서 에스프레소 2~3 추천.', 2),
  (30, '라 스칼라 극장', '문화·공연', '1778년 개관한 세계 3대 오페라 극장. 카루소·카라스·파바로티 등 전설적 음악가들이 무대에 올랐던 역사적 공간. 신고전주의 외관은 밀라노 문화의 상징. 내부 스칼라 박물관에는 공연 역사 유물·의상·악기 등 소장.', '박물관 10:00~17:30 (화~일, 월', '무료', 'Piazza della Scala, 20121 Milano MI,', '외관 무료. 박물관 9. 광장(Piazza della Scala) 벤치에서 외관 감상 + 레오나르도 다빈치 동상 앞 사진 추천. 갈레리아에서 도보 2분.', 3),
  (30, '브레라 지구', '예술가 골목', '밀라노 최고의 보헤미안 지구. Via Brera·Via Fiori Chiari·Via Madonnina 골목에 갤러리·앤티크숍·편집샵·카페가 즐비. 핀코테카 디 브레라 미술관(라파엘로·카라바조 소장)이 중심. 두오모 북쪽 도보 15분 거리. 오후 햇살에 골목 걸을 때 가장 아름다운 밀라노의 면모.', '미술관: 화~일 08:30~19:15 (월', '무료', 'Via Brera, 20121 Milano MI, 이탈리아', '돌바닥이므로 운동화 필수. 핀코테카 미술관 15(체력 여유 시). 골목 카페에서 카푸치노 한 잔 마시며 현지인처럼 쉬는 것도 좋은 선택.', 4),
  (30, '나빌리오 운하 & 아페리티보', '운하·문화체험', '12세기에 조성된 밀라노 운하 시스템. Naviglio Grande를 따라 색색의 건물·노천 바·갤러리가 이어지는 낭만적인 지구. 17:30~19:30 아페리티보 타임에 Spritz 한 잔 주문하면 뷔페식 안주(스낵·올리브·핑거푸드)가 무료 제공. 석양빛 운하 반영을 바라보며 즐기는 이탈리아 저녁 문화 체험.', '바 17:00~24:00 / 아페리티보', 'EUR20 (W35,000)', 'Alzaia Naviglio Grande, 20144 Milano', '2인 기준 Spritz 2잔 14~20. 안주 뷔페 무료(선착순). Mag Cafe(45.4535, 9.1728) 추천. 소매치기 많은 지역 — 크로스백 앞으로, 핸드폰 테이블 방치 금지.', 5),
  (30, '최후의 만찬', '비용', '레오나르도 다빈치가 1495~1498년에 그린 세계 최고의 걸작 벽화. 산타 마리아 델레 그라치에 수도원 식당 북쪽 벽에 위치. 15분 단위로 30명씩만 입장 가능하므로 사전 예약 필수. 습기에 약한 템페라 기법으로 그려져 항온항습 유지를 위해 2중 에어록을 통과해야 한다.', '화~일 08:15~19:00 (월요일 휴관),', '무료', 'Piazza di Santa Maria delle Grazie 2,', '예약 없이는 입장 절대 불가. 방문 3~6개월 전 예약 권장. 관람 시간은 15분. 사진 촬영 허용(플래시 금지). 영어 오디오 가이드 추가 3.', 6),
  (30, '스포르체스코 성', '비용', '15세기 밀라노 공국의 스포르차 가문이 건설한 거대 요새 성. 내부에 미켈란젤로의 마지막 조각 ''론다니니의 피에타''를 포함한 여러 박물관이 있다. 붉은 벽돌로 지어진 웅장한 외관과 해자 터가 인상적이며, 60대 부부에게는 광장 내 산책만으로도 충분히 즐길 수 있다.', '성내 광장 07:00~19:30 (무료),', '무료', 'Piazza Castello, 20121 Milano', '매월 첫째 화요일 오후 2시 이후 박물관 무료 개방. 성내 광장 벤치에서 잠시 쉬어가기 좋음. 스포르체스코 성에서 셈피오네 공원까지 도보 2분.', 7),
  (30, '셈피오네 공원', '비용', '스포르체스코 성 뒤편에 펼쳐진 약 38만㎡의 광대한 도심 공원. 영국식 정원 양식으로 조성되어 구불구불한 산책로와 연못, 잔디밭이 자연스럽게 어우러진다. 공원 중심부의 평화의 아치(Arco della Pace)까지', '06:30~21:00 (계절별 상이)', '무료', 'Piazza Sempione, 20154 Milano', '공원 내 Bar Bianco 카페에서 휴식 가능. 자갈길이 많으니 편한 신발 필수. 소매치기 주의 — 소지품 관리 철저.', 8),
  (30, '보스코 버티칼레', '비용', '2014년 완공된 세계적으로 유명한 수직 정원 아파트. 높이 110m·76m 두 동에 걸쳐 약 900그루의 나무, 5,000그루의 관목, 11,000여 본의 지피식물이 심어져 있다. 스테파노 보에리 아키텍티 설계. CNN이 선정한 세계에서 가장 아름다운 건물 중 하나.', '외관 상시 관람 가능', '무료', 'Via Gaetano De Castillia 11, 20124', 'Piazza Gae Aulenti에서 서쪽으로 도보 5분. Porta Nuova 방향에서 보는 뷰가 가장 아름다움. 내부 입장 불가 — 외관 촬영 포인트 선점이 관건.', 9),
  (30, '피아자 가에 아울렌티', '비용', '밀라노 Porta Nuova 재개발 지구의 중심 광장. 원형 분수와 현대적 건축물들이 어우러진 밀라노 신도심의 상징. UniCredit Tower를 비롯한 고층 빌딩들이 둘러싼 광장에서 밀라노의 현재와 미래를 한눈에 볼 수 있다. 영업시간     월~금 12:30~14:30,                     휴무', '상시', '무료', 'Piazza Gae Aulenti, 20124 Milano', '광장 주변 카페와 레스토랑 가격이 합리적. Eataly 밀라노 Smeraldo 지점이 근처에 있어 이탈리아 식품 쇼핑 가능.', 10),
  (30, '푸니콜라레 치타', '비용', '08:30~23:30 (5~10분 간격 운행) 베르가모 하부 도시(치타 바사)와 중세 상부 도시(치타 알타)를 연결하는 100년 역사의 케이블카. 편도 약 3분으로 가파른 언덕을 올라가며 도중에 도시 전경이 펼쳐진다. 60대 부부에게 최적의 이동수단 —', '월~토 07:00~00:30 / 일', '무료', 'Viale Vittorio Emanuele II, 24121', 'ATB 앱(Chat&Go;)이나 현장 발매기에서 티켓 구매. 성수기 주말 오전에는 줄이 생기므로 10분 일찍 도착 권장.', 11),
  (30, '피아자 베키아', '비용', '치타 알타의 심장부이자 베르가모 최고의 광장. 12세기 팔라초 델라 라조네(재판소)와 18세기 팔라초 누오보(도서관)가 마주 보고, 중앙에 콘타리니 분수(1780년)가 자리한다. 르 코르뷔지에가 ''세계에서 가장 아름다운 광장''이라 극찬한 곳. 노천카페에서 커피 한 잔 하며 중세 분위기를 만끽하기에 최고.', '상시', '무료', 'Piazza Vecchia, 24129 Bergamo BG', '광장 주변 카페 가격은 시내 대비 다소 높음(에스프레소 2~3). 아침 10시 이전 방문 시 한산함.', 12),
  (30, '산타 마리아 마조레 대성당', '비용', '14:30~18:00 / 일 09:00~13:00, 1137년 착공한 베르가모의 로마네스크 성당. 내부에 플랑드르 태피스트리(16~17세기)와 도니제티 작곡가의 묘소가 있다. 외관의 화려한 대리석 장식과 내부의 금박 장식이 인상적. 옆의 콜레오니 예배당과', '월~토 09:00~12:30,', '무료', 'Piazza Duomo, 24129 Bergamo BG', '내부 사진 촬영 가능. 미사 시간에는 관광 입장 제한될 수 있음.', 13),
  (30, '콜레오니 예배당', '비용', '14:00~18:30 (월요일 휴관, 3~10월 용병대장 바르톨로메오 콜레오니(1400~1475)가 자신의 묘소로 건립한 르네상스 최고 걸작 중 하나. 조반니 안토니오 아마데오가 설계하여 1476년 완공. 흰색·빨간색·검은색 대리석이 기하학 무늬를 이루는', '화~일 09:00~12:30,', '무료', 'Piazza Duomo 1, 24129 Bergamo BG', '산타 마리아 마조레 성당 바로 옆에 위치해 함께 관람 가능. 내부에 콜레오니 기사 조각상과 금도금 장식 천장이 있음.', 14),
  (30, '베네치아 성벽', '비용', '16세기 베네치아 공화국이 오스만 제국 위협에 대비해 축조한 방어 성벽. 전체 길이 약 6km, 두께 최대 40m. 2017년 유네스코 세계문화유산 등재. 성벽 위 산책로에서 베르가모 하부 도시와 롬바르디아 평원의 부부에게는 일부 구간(전망 좋은 포르타 산 자코모~포르타 산탄드레아)만 걷는 것 추천.', '상시 (성벽 위 산책로)', '무료', 'Via Rocca, 24129 Bergamo BG', '치타 알타에서 Porta San Giacomo 방향으로 나가면 성벽 산책 시작. 전체 일주는 약 1~2시간. 60대 부부에게는 일부 구간(전망 좋은 포르타 산 자코모~포르타 산탄드레아)만 걷는 것 추천.', 15),
  (30, '토레 델 캄파노네', '비용', '피아자 베키아에 솟은 54m 높이의 시계탑. 350년 넘게 매일 밤 10시 정각에 100번의 종을 울리는 것으로 유명. 엘리베이터를 타고 전망대에 오르면 베르가모 치타 알타 전체와 롬바르디아 평원, 날씨 좋은 날에는 영업시간    화~일 12:00~14:30,                  휴무', '화~금 09:30~18:00 / 토·일', '무료', 'Piazza Vecchia, 24129 Bergamo BG', '계단(230개) 또는 엘리베이터 선택 가능. 60대 부부에게는 엘리베이터 강력 추천. 전망대 폭이 좁아 혼잡 시 대기 발생.', 16),
  (30, '몬탈레그로 케이블카', '비용', '1934년 개통, 라팔로 해변에서 해발 612m 몬탈레그로 성지까지 2,350m를 7분 만에 오르는 케이블카. 티굴리오 만 전체와 라팔로, 산타 마르게리타, 멀리 포르토피노 반도까지 펼쳐지는 파노라마가 압권. 정상에 1557년 성모 발현을 기념해 세운 몬탈레그로 성지가 있어 순례지로도 유명.', '09:00~12:30, 14:00~18:00', '무료', 'Piazza Solari 2, 16035 Rapallo GE', '오전 9시 개장과 동시에 이용하면 대기 없이 탑승 가능. 바람이 강한 날은 운행 중단될 수 있으니 날씨 확인. 정상 기온이 해변보다 5~8도 낮으므로 가벼운 겉옷 지참.', 17),
  (30, '노스트라 시뇨라 디 몬탈레그로 성지', '비용', '1557년 한 농부에게 성모 마리아가 발현했다는 전설이 깃든 성지. 케이블카 상부역 바로 옆에 위치해 걷지 않고도 방문 가능. 17세기 건설된 바로크 양식 성당 내부에 비잔틴 성화상이 보존되어 있다. 정상 테라스에서의 리구리아 해안 조망은 이탈리아 최고 중 하나.', '07:00~19:00', '무료', 'Via Santuario di Montallegro, 16035', '성지 내부 복장 규정 있음 — 민소매·반바지 금지. 정상 카페(Bar Montallegro)에서 라팔로 만을 바라보며 커피 한 잔.', 18),
  (30, '포르토피노', '비용', '세계적으로 유명한 이탈리아 리비에라의 보석. 이탈리아 어부 마을 특유의 파스텔 톤 건물들이 작은 항구를 에워싼 그림 같은 풍경. 헤밍웨이, 버튼, 테일러 등 세기의 명사들이 사랑한 곳. 차가 없는 마을이라 오직 페리나 도보(산타 마르게리타에서 3km 해안 트레킹)로만 접근 가능. 항구 주변 카페와 부티크 산책이', '상시 (페리 운항 시간 내)', '무료', 'Piazzetta di Portofino, 16034', '포르토피노 내 식사·커피 가격은 라팔로의 2~3배. 음료 한 잔 정도만 즐기고 식사는 라팔로에서 할 것. 카스텔로 브라운(성) 입장은 계단 많아 60대 부부에게 비추. 피아체타 광장 벤치에서 항구 감상이 베스트.', 19),
  (30, '산 조르조 교회', '비용', '항구 언덕 위에 자리한 포르토피노의 수호성인 교회. 1133년 십자군 전사들이 성 게오르기우스의 유해를 모셔와 세운 것이 기원. 교회 앞 테라스에서 항구 전경을 내려다보는 시점이 포르토피노 최고의 포토 스팟. 계단으로 5분이면 도달하므로 60대 부부도 무리 없음.', '09:00~18:00', '무료', 'Via alla Chiesa di San Giorgio, 16034', '교회 앞 잔디밭에서 항구와 바다를 배경으로 사진 촬영 명소. 오후 햇살에 항구 건물들이 황금빛으로 빛나는 시간대가 최고.', 20),
  (30, '몬테로소 알 마레', '비용', '친퀘 테레 5개 마을 중 가장 크고 평탄한 마을. 모래 해변(페지나)과 조약돌 해변이 공존하며 식당·카페가 가장 많아 60대 부부에게 최적. 구도심(Centro)과 신도시(Fegina)를 연결하는 바위 터널을 걸어서 통과하는 것이 포인트. 유럽연합 PDO 인증을 받은 몬테로소 앤초비(Acciughe di Monterosso)의 본고장.', '상시', '무료', 'Via Fegina, 19016 Monterosso al', '역에서 페지나 해변까지 평지. 구도심 진입은 터널 통과 — 계단 없음. 5월은 성수기 시작 전이라 여유로움. 앤초비 기념품 구입 추천.', 21),
  (30, '베르나차', '비용', '친퀘 테레 5개 마을 중 경관이 가장 아름답다고 꼽히는 마을. 기차역에서 내리면 바로 작은 골목길을 따라 5분 걸으면 항구 광장에 도달. 바다로 돌출된 자연 항구를 형형색색 중세 건물들이 에워싼 그림 같은 풍경. 절벽 위 두오리아 성탑(Torre Doria)에서 내려다보는 전경도 장관이나 60대에게는 계단이 많아 선택사항.', '상시', '무료', 'Piazza Marconi, 19018 Vernazza SP', '기차역→항구 광장: 골목길 도보 5분 (계단 거의 없음). 항구 수영 가능(5월은 다소 쌀쌀). 성탑 오르기는 계단 많아 체력 고려.', 22),
  (30, '시에나 대성당', '비용', '13세기 착공한 이탈리아 고딕 건축의 최고 걸작. 흑백 줄무늬 대리석으로 만든 파사드와 56명 교황 흉상이 줄지어 선 내부, 56장의 대리석 상감 바닥화(Pavimento)가 압도적. 니콜라 피사노의 팔각형 설교단(1268년)은 유럽 조각 역사의 분기점으로 평가받는다. OPA SI PASS 구매 시 인접', '10:30~19:00 (계절별 상이, 목요일', '무료', 'Piazza del Duomo 8, 53100 Siena SI', 'OPA SI PASS가 압도적으로 경제적 (단품 합산 35 이상). 대리석 바닥화는 여름(8~9월)에만 전체 공개 — 5월은 부분 공개. 성당 내부 서늘하므로 가벼운 겉옷 지참.', 23),
  (30, '두오모 오페라 박물관', '비용', '두오모 오른쪽 미완성 증축 벽 내부에 자리한 박물관. 두치오 디 부오닌세냐의 ''마에스타(Maest, 1311년)'' 양면 제단화 원작이 핵심 소장품. 시에나 화파 회화의 정수를 감상할 수 있다.', '10:30~19:00', '무료', 'Piazza del Duomo 8, 53100 Siena SI', '마에스타 제단화는 2층 전시실에 위치. 조명이 어두우므로 눈이 익숙해질 시간 필요.', 24),
  (30, '파치아토네 전망대', '비용', '14세기 대성당 증축 계획(더 큰 성당 건설)이 흑사병으로 중단되어 남겨진 미완성 거대 벽 위에 만든 전망대. 토레 델 만자보다 계단이 적으면서 시에나 구시가지 전경을 360도로 감상 가능. 캄포 광장과 시청 탑이 한눈에 보이는 시에나 최고의 전망 포인트 중 하나.', '10:30~18:00', '무료', 'Piazza del Duomo, 53100 Siena SI', '계단 약 130개 — 토레 델 만자(400개) 대비 훨씬 적음. 60대 부부에게 전망 즐기기 최적. 난간 없는 구간 있으므로 주의.', 25),
  (30, '캄포 광장', '비용', 'UNESCO 세계유산. 유럽에서 가장 아름다운 중세 광장으로 꼽히는 부채꼴 형태의 광장. 1293년 이후 시에나 공화국의 중심지로 기능했으며 중앙의 가이아 분수(Fonte Gaia, 1419년 복제품)와 고딕 양식의 팔라초 푸블리코(시청, 1342년)가 광장을 에워싸고 있다.', '24시간', '무료', 'Piazza del Campo, 53100 Siena SI', '광장은 경사져 있어 한쪽에서 반대쪽을 내려다보는 구도 사진 추천. 주변 카페 테라스 이용 시 1인당 5~8 서비스 차지 각오.', 26),
  (30, '산타 마리아 델라 스칼라', '비용', '두오모 광장 맞은편 13세기 창립 중세 병원 건물을 개조한 대형 박물관. 지하 ''필그림 홀(Pellegrinaio)''의 15세기 프레스코 벽화가 핵심. 시에나의 도시 역사와 의료·사회 복지 역사를 입체적으로 전시. 지하 구조물', '10:30~19:30', '무료', 'Piazza del Duomo 2, 53100 Siena SI', '두오모 관람 후 바로 옆이므로 연계 방문 효율적. 지하 구역은 시원하고 조명이 독특해 분위기 있음.', 27),
  (30, '산 도메니코 성당', '비용', '시에나의 수호성인 성녀 카테리나(1347~1380)와 깊이 연결된 고딕 성당. 성녀의 두개골 성유물이 보관된 채플과 15세기 안토니오 소도마의 프레스코화가 있다. 언덕 위에 위치해 두오모와 시에나 서쪽 전경을 영업시간     12:30~14:30, 19:30~22:00              휴무', '07:00~18:30', '무료', 'Piazza San Domenico, 53100 Siena SI', 'Santa Caterina 주차장 에스컬레이터 바로 위에 위치 — 주차 후 첫 방문지로 동선 최적. 내부 성유물 채플은 경건하게 관람.', 28),
  (30, '카펠라 디 비탈레타', '비용', '밀밭과 구릉 한가운데 홀로 선 작은 예배당. 양쪽으로 사이프러스 나무가 줄지어 서 있는 구도가 발도르차 대표 사진으로 전 세계에 알려진 곳. 1480년경 건립. SP146에서 비포장 진입로(약 200m)로 들어가면 도달. 이른 아침 안개가 걷힐 무렵 황금빛 빛살이 드는 시간대가 최고.', '상시 (외관)', '무료', 'SP146, 53026 San Quirico d''Orcia SI', '비포장 진입로 진입 시 저속 운전. 리스카(3008)로 충분히 접근 가능. 해 뜨고 1~2시간 후 역광 없이 촬영 최적.', 29),
  (30, '산 키리코 도르차', '비용', '중세 성벽이 온전히 남아 있는 발도르차의 관문 소도시. 12세기 콜레지아타 성당의 세 개 정문(포르탈레)이 로마네스크·고딕 양식 조각의 걸작으로 꼽힌다. 성벽 안 호르티 레오니니(Horti Leonini) 16세기 이탈리아식 정원은 탁 트인 발도르차 풍경과 함께 산책하기 좋다.', '상시', '무료', 'Piazza della Libert, 53027 San', '성벽 안 주차 불가 — 외곽 무료 주차장 이용. 콜레지아타 성당은 외관 장식이 핵심. 호르티 레오니니는 경사 없는 테라스 정원으로 60대 부부 산책 최적.', 30),
  (30, '바뇨 비뇨니', '비용', '세계에서 유일하게 광장 중앙에 온천 욕조가 있는 마을. 로렌초 데 메디치, 교황 피우스 2세, 성녀 카테리나가 치료 목적으로 방문한 기록이 있는 중세 온천 마을. 현재 광장의 온천수(52°C)는 수영 금지이나, 마을 아래 인공 탕(파르코 데이 물리니)에서 흘러내리는 온천수 체험 가능. 안드레이', '상시', '무료', 'Piazza delle Sorgenti, 53027 Bagno', '광장 온천 수영 절대 불가 (벌금 부과). 주변 온천 스파 호텔에서 유료 이용 가능. 마을 자체가 소규모라 30분이면 충분. 인접 계곡 테라체(Terrace) 뷰 포인트 추천.', 31),
  (30, 'SP146 사이프러스 가로수길', '비용', '산 키리코 도르차에서 피엔차 사이 약 12km 구간의 SP146 지방도. 구불구불한 언덕길을 따라 수백 년 된 사이프러스(Cupressus sempervirens) 나무들이 늘어서며 토스카나의 상징적 풍경을 만들어낸다. 유네스코 세계유산 발도르차의 핵심 경관. 봄철(4~6월) 녹색 밀밭과 사이프러스의 조합이 가장 아름답다.', '상시', '무료', 'SP146, 산 키리코~피엔차 구간', '차창을 열고 천천히 드라이브하며 촬영. 갓길 넓은 곳에서 주차 후 사진 가능. 맞은편 차량 주의 — 폭 좁은 구간 있음.', 32),
  (30, '피엔차', '비용', '교황 피우스 2세(1405~1464)가 르네상스 이상 도시로 설계한 유네스코 세계유산 소도시. 피콜로미니 광장을 중심으로 두오모·팔라초 피콜로미니·팔라초 코뮤날레가 완벽한 르네상스 구성을 이룬다. ''피엔차 페코리노 치즈(DOP)''의 본고장으로 거리 곳곳에 치즈 가게가 늘어서 있다.', '상시', '무료', 'Piazza Pio II, 53026 Pienza SI', '성벽 남쪽 벨베데레에서 발도르차 파노라마가 펼쳐짐 — 필수 방문. 페코리노 치즈 시식 무료 제공 가게 多. 피콜로미니 궁전 내부 투어 7.', 33),
  (30, '피아차 델라 치스테르나', '비용', '13세기 우물(치스테르나)이 중앙에 자리한 산 지미냐노의 심장 광장. 삼각형 모양 광장 주변으로 중세 탑들이 촘촘히 솟아 있어 어느 각도에서 봐도 그림 같은 풍경. 한때 72개에 달했던 탑은 현재 14개가 남아', '상시', '무료', 'Piazza della Cisterna, 53037 San', '광장 모퉁이 카페 테라스에서 탑 배경 사진 촬영. 토요일 오전 장시가 열려 현지 농산물 구경 가능.', 34),
  (30, '두오모', '비용', '12세기 로마네스크 성당. 내부 전체를 덮는 구약성서(왼쪽 벽)·신약성서(오른쪽 벽) 프레스코 연작과 최후의 심판(Barna da Siena, 1380년)이 압도적. 성당 자체보다 내부 그림이 더 유명한 ''그림 박물관'' 같은', '10:00~19:30 (토 10:00~17:30)', '무료', 'Piazza del Duomo, 53037 San', '토요일 오후 단체 관광객 혼잡 — 오전 개장 직후 방문 권장. 내부 사진 허용(플래시 금지).', 35),
  (30, '토레 그로사 전망대', '비용', '산 지미냐노에서 유일하게 일반 공개되는 탑(54m). 계단 218개. 정상에서 나머지 13개 탑과 토스카나 구릉, 날씨 좋은 날 시에나까지 조망 가능.', '10:00~19:30', '무료', 'Piazza del Duomo 2, 53037 San', '계단 218개 — 60대 부부 무리하지 말 것. 중간 층에서 조망만 해도 충분. 파치아토네(시에나)보다 계단 많음.', 36),
  (30, '젤라테리아 돈돌리', '비용', '세르지오 돈돌리가 2006·2010·2015년 세계 젤라토 챔피언십을 제패한 전설적인 젤라테리아. 산 지미냐노 방문객이라면 줄 서서라도 먹어야 하는 필수 코스. 대표 맛: 자프란 크로칸테(Crema di Santa Fina), 리볼라 영업시간    매일 12:00~15:00, 19:00~22:00   휴무', '09:00~22:00', '무료', 'Piazza della Cisterna 4, 53037 San', '토요일 성수기 대기 10~20분 각오. 2스쿱(콘/컵) 추천. 현금만 가능할 수 있음.', 37),
  (30, '몬탈치노 로카 에노테카', '비용', '1361년 시에나 공화국이 건립한 요새 내부에 자리한 공식 에노테카. 브루넬로 디 몬탈치노 DOCG, 로소 디 몬탈치노 DOC를 포함해 수십 종의 몬탈치노 와인을 글라스 단위로 시음 가능. 요새 테라스에서 발도르차 파노라마를 감상하며 마시는 와인이 압권.', '매일 09:00~20:00', '무료', 'Piazzale Fortezza, 53024 Montalcino', '일요일도 정상 운영. 시음 세트(3잔) 약 15. 마음에 드는 와인은 현장 구입 가능. 브루넬로 정규 와인(40~100/병)과 로소(15~25/병) 가격 차이 큼.', 38),
  (30, '산탄티모 수도원', '비용', '15:00~18:30 / 일 15:15~18:30 Castelnuovo dell''Abate SI 카를로 대제가 812년 창건했다는 전설을 품은 토스카나 최고의 로마네스크 수도원. 빛에 따라 색이 변하는', '월~토 10:00~13:00,', '무료', 'Loc. Sant''Antimo, 53024', '일요일 15:15 이후 입장 (오전 미사 후 개방). 수도원 성가 시간표 확인 후 방문 조율 — 그레고리오 성가 생음악 체험 권장. 주변 비포장 주차장 무료.', 39),
  (30, '에르콜라노 고고학 공원', '비용', '09:00~17:00), 마감 90분 전 입장 서기 79년 베수비오 화산 폭발 당시 화쇄류(pyroclastic flow)에 순식간에 매몰되어 폼페이보다 훨씬 완벽하게 보존된 고대 로마 도시. 2층 건물의 목조 구조물, 색채 선명한 프레스코화, 탄화된 가구·음식 등이', '매일 09:00~19:30 (11월~3월', '무료', 'Corso Resina 187, 80056 Ercolano', '폼페이보다 관람객 적고 동선 짧음 — 오전 방문 시 30분 내 입장 가능. 목욕탕(Terme Suburbane) 내부 에로틱 모자이크 유일 보존. 매점·화장실 입구 부근 집중.', 40),
  (30, '폼페이 고고학 공원', '비용', '09:00~17:00), 마감 90분 전 입장 서기 79년 베수비오 화산 폭발로 화산재에 매몰된 인구 2만 명의 로마 도시. 포룸, 원형극장, 목욕탕, 창관(루파나레), 빌라 데이 미스테리의 디오니소스 의식 대형 프레스코 등 고대 일상이 그대로 남아있다.', '매일 09:00~19:30 (동절기', '무료', 'Via Villa dei Misteri 2, 80045 Pompei', '오디오 가이드 앱 ''Pompei Sites'' 무료 다운로드 권장. 마리나 문(입구)→ 포룸 → 아폴로 신전 → 목욕탕 → 루파나레 코스가 핵심 1.5시간 동선. 석조 보도블록 울퉁불퉁 — 편한 운동화 필수. 모자·물·선크림 필수 (그늘 거의 없음).', 41),
  (30, '포지타노', '비용', '아말피 해안 서쪽 끝의 절벽 마을. 분홍·노랑·주황색 파스텔 건물들이 가파른 절벽에 계단식으로 붙어 있는 이탈리아 해안 최고의 포토스팟. 스폰다 해변에서 수영·일광욕 가능. 레몬 향초·그릇·수공예품 쇼핑 거리로도 계단 많으니 내려갈 때만 도보, 올라올 때는 버스 이용.', '마을 상시 개방 / 해변 무료', '무료', '84017 Positano SA', '포지타노 마을 진입로 협소 — 위쪽 주차장(Via G. Marconi)에 주차 후 마을 버스 또는 도보 하강 권장. 60대는 계단 많으니 내려갈 때만 도보, 올라올 때는 버스 이용.', 42),
  (30, '아말피 성 안드레아 대성당', '비용', '9세기 창건, 아랍-노르만 양식의 독특한 이중 계단 외관이 인상적인 아말피의 상징. 예수의 12제자 중 첫 번째 제자 성 안드레아의 유해가 안치되어 있으며, 해상 공화국 시절 지중해를 호령하던 아말피의 영화를 상징한다. 경내 클로이스터(회랑)의 아랍풍 아치가 일품.', '매일 09:00~19:00 (11월~2월', '무료', 'Piazza del Duomo, 84011 Amalfi SA', '대성당 앞 광장(피아자 델 두오모)이 아말피의 중심. 계단 62개 — 60대 무릎 주의. 내부 예배 시간(11:00, 18:00)에는 관광 제한.', 43),
  (30, '라벨로 빌라 루폴로', '비용', '13세기 루폴로 가문의 별장 정원. 리하르트 바그너가 1880년 방문 후 ''파르지팔'' 클링조르의 정원에 영감을 받았다. 테라스에서 내려다보는 티레노 해 전망이 압도적. 매년 7~8월 라벨로 음악 페스티벌의 야외 라벨로 주차: Piazza Duomo 인근 공영 주차장 2~3/시간.', '매일 09:00~20:00 (계절별 상이)', '무료', 'Piazza del Duomo, 84010 Ravello SA', '빌라 침브로네(Villa Cimbrone)의 ''무한의 테라스(Terrazza dell''Infinito)''도 필수. 두 빌라 도보 15분 거리. 라벨로 주차: Piazza Duomo 인근 공영 주차장 2~3/시간.', 44),
  (30, '나폴리 국립 고고학 박물관', '비용', '세계에서 가장 중요한 그레코-로마 유물 박물관. 폼페이·에르콜라노·스타비아에서 발굴된 모자이크·조각·프레스코·일상 도구의 원본이 소장되어 있다. 하이라이트: 알렉산드로스 대왕의 이소스 전투 모자이크(폼페이 파우누스의 집 출토), 파르네세 헤라클레스(2.3m 대리석 조각), 비밀의 방(에로틱 고대', '수~월 09:00~19:30 (화요일 휴무),', '무료', 'Piazza Museo Nazionale 19, 80135', '목요일 정상 영업 확인. 비밀의 방(Gabinetto Segreto)은 18세 이상만 입장, 사전 입장 신청 필요할 수 있음. 박물관 내 카페테리아 있음. 1층 조각→2층 모자이크→3층 프레스코 순 관람 권장.', 45),
  (30, '스파카나폴리', '비용', '고대 그리스 시대부터 내려온 나폴리의 대동맥. 직선으로 뻗은 좁은 골목이 나폴리 구도심을 동서로 가르는 모습이 위성사진에서 뚜렷하다. 제수 누오보(Gesu Nuovo) 성당의 다이아몬드 파사드, 산타 키아라(Santa Chiara) 수도원의 마욜리카 타일 회랑, 산 그레고리오 아르메노(San Gregorio Armeno)의 수공예', '상시 개방', '무료', 'Via Benedetto Croce / Via San Biagio', '나폴리 구도심 소매치기 주의 — 백팩은 앞으로 메고, 지갑·휴대폰 안쪽 주머니 보관. 산 그레고리오 아르메노 골목은 성수기에도 공방 영업 중. 스팡야롤로(나폴리 크림 도넛) 1.50 — 현지인 간식.', 46),
  (30, '카스텔 누오보', '비용', '1279년 샤를 1세 앙주 왕이 나폴리 항구 옆에 세운 중세 성곽. 5개의 원형 탑과 화려한 개선문(Arco Trionfale)이 인상적. 항구 전경과 베수비오 화산을 배경으로 촬영하는 포토스팟으로 인기. 내부는 나폴리 걸으면 나폴리 해안 산책로(Lungomare).', '월~토 09:00~18:00, 일요일 휴무', '무료', 'Piazza del Municipio, 80133 Napoli NA', '내부보다 외관 자체가 하이라이트. 성 앞 Piazza del Municipio에서 전체 성벽 사진 촬영. 항구 방향으로 5분 걸으면 나폴리 해안 산책로(Lungomare).', 47),
  (30, '카프리 섬', '비용', '티레노 해의 보석. 로마 황제 아우구스투스와 티베리우스가 별장을 둔 섬. 파라글리오니(3개의 바위 기둥), 푸른 동굴(Grotta Azzurra), 빌라 조비스(황제 별장 유적), 아나카프리의 몬테 솔라로 전망대가 대표 명소. 세계 최고급 리조트와 명품 부티크가 가득하지만 자연 경관이 압도적.', '섬 상시 개방 / 페리 06:00~22:00', '무료', '80073 Capri NA', '푸른 동굴(Grotta Azzurra)은 수위 높은 날 입장 불가 — 조건부 방문. 성수기 페리 혼잡 — 왕복 티켓 미리 예매. 섬 내 버스/택시 이용 (렌터카 반입 금지). 카프리 타운 명품 쇼핑 거리 Via Camerelle.', 48),
  (30, '몬테 솔라로 체어리프트', '비용', '아나카프리에서 카프리 최고봉 몬테 솔라로(589m)까지 11분간 오픈형 1인승 체어리프트. 정상에서 카프리 섬 전체, 나폴리 만, 아말피 해안, 맑은 날에는 시칠리아까지 보이는 360도 파노라마. 60대 부부가 도보 없이 즐길 수 있는 카프리 최고 뷰포인트.', '매일 09:30~17:00 (계절별 상이)', '무료', 'Piazza Vittoria, 80071 Anacapri NA', '체어리프트 1인 탑승 (2인 나란히 불가) — 고소공포증 있으면 주의. 정상 기온 카프리 타운보다 5~7도 낮음 — 가벼운 겉옷 지참. 내려오는 길 체어리프트 대신 도보 하산 가능 (35분, 비추 — 60대).', 49),
  (30, '파라글리오니 전망대', '비용', '카프리 마을에서 비아 트라가라(Via Tragara)를 따라 도보 20분 거리의 전망 포인트. 카프리의 상징인 파라글리오니 3개의 거대 바위 기둥과 에메랄드 지중해를 한눈에 담을 수 있다. 일몰 시간대에 더욱 환상적이나 당일치기 일정 상 오전 방문.', '상시 개방', '무료', 'Via Tragara, 80073 Capri NA', '비아 트라가라는 포장도로로 60대 도보 가능 (평탄한 편). 전망대 옆 카페 리도 델 파로 (Lido del Faro) 테라스에서 커피 한 잔 + 조망 추천.', 50),
  (30, '산타 마리아 델 이솔라 성당', '비용', '트로페아의 상징. 바다 쪽으로 돌출된 돌섬 위 절벽에 세워진 하얀 성당. 원래 섬이었지만 퇴적물로 육지와 연결됨. 7세기 창건, 현재 건물은 17세기 재건. 성당 앞 테라스에서 에메랄드 해변과 절벽이 어우러지는 풍경은 이탈리아 해안 사진 중 가장 많이 찍히는 장면 중 하나.', '매일 07:30~12:30 / 15:30~20:00', '무료', 'Via Portosalvo, 89861 Tropea VV', '성당 내부 예배 시간(일요일 10:00, 18:00) 관광 제한. 계단 약 50개 — 편한 신발. 성당 입구 옆 테라스 카페에서 커피 + 조망.', 51),
  (30, '카포 바티칼로 전망대', '비용', '트로페아에서 남서쪽으로 15km 지점의 칼라브리아 최서단 곶(串). 맑은 날에는 스트롬볼리·불카노·리파리 등 에올리에 화산섬들을 육안으로 볼 수 있다. 지중해 최고 투명도의 바다와 적벽 절벽이 조화를 이루는 곳. 영업시간     매일 12:30~15:00 / 19:30~22:30            휴무', '상시 개방', '무료', '89865 Ricadi VV', 'Faro di Capo Vaticano(등대) 주변 전망 포인트. 주차장 있음(무료). 차로 직접 진입 가능.', 52),
  (30, '니코테라 + 니코테라 마리나 해변', '비용', '트로페아 남쪽 25km의 조용한 칼라브리아 해안 마을. 언덕 위 중세 성곽 마을(Nicotera Alta)과 아래 해안 마을(Nicotera Marina)로 구성. 마리나 해변은 트로페아보다 덜 알려져 인파 없이 조용하게 즐길 수 있는 최고의 대안 해변. 모래 질감과 물 투명도 모두 최상급.', '상시 개방', '무료', '89844 Nicotera VV', '니코테라 마리나 → 니코테라 Alta 언덕 마을까지 차로 10분. 언덕 위에서 카라브리아 해안 파노라마. 성수기 7~8월이 아니면 해변 한산.', 53),
  (30, '카펠라 팔라티나', '비용', '09:00~13:00 (예배 후 관광) 루제로 2세가 1132~1143년에 건립한 궁전 예배당. 이슬람 목조 천장 + 비잔틴 황금 모자이크 + 노르만 건축이 혼합된 세계 유일의 건축 걸작. 6,000㎡의 황금 모자이크가 그리스도의 일생부터 노르만 왕실을', '월~토 09:00~17:00 / 일', '무료', 'Piazza del Parlamento 1, 90129', '수요일 정상 영업. 예약 없이도 입장 가능하나 성수기 대기 30분+. 사진 촬영 허용(플래시 금지). 입장 전 복장 규정: 어깨·무릎 노출 금지.', 54),
  (30, '팔레르모 대성당', '비용', '08:00~13:00, 16:00~19:00 9세기 아랍 모스크를 개조한 후 12~18세기에 걸쳐 증개축된 팔레르모의 성당. 외관은 아랍-노르만 양식의 굴곡미, 내부는 18세기 신고전주의로 개조. 루제로 2세·콘스탄체·프리드리히 2세 황제의 반암 석관이 왕릉', '월~토 07:00~19:00 / 일', '무료', 'Corso Vittorio Emanuele, 90134', '왕릉(Tesoro e Cripta) 별도 입장권 3. 지붕 테라스 계단 약 130개 — 60대 엘리베이터 없음 주의. 성당 광장 측면에서 아랍 문양 외벽 상세 촬영 가능.', 55),
  (30, '콰트로 칸티 + 라 마르토라나', '비용', '콰트로 칸티는 팔레르모 구시가 두 대로의 교차점에 세워진 바로크 건축 4면체(1608~1620). 팔레르모 4구역을 상징하는 조각이 3단으로 쌓인 독특한 도시 설계. 바로 옆 라 마르토라나(1143년)의 황금 비잔틴 모자이크는 카펠라 팔라티나에 필적하는 아름다움.', '라 마르토라나: 월~토 08:30~13:00', '무료', 'Piazza Vigliena, 90133 Palermo PA', '라 마르토라나 ''마르타판'' — 마르타판(marzapane)이 이 교회에서 비롯됐다는 설. 교회 앞 가게에서 시칠리아 마르지판 과자 구입 가능.', 56),
  (30, '몬레알레 대성당', '비용', '14:30~17:00 / 일 14:30~17:00 노르만 왕 굴리엘모 2세가 1172~1189년에 건립. 내부 전체를 덮는 6,000㎡ 황금 모자이크가 구약·신약 성경을 장면별로 묘사. 앱스의 거대한 그리스도 판토크라토르는 체팔루와 함께 비잔틴 모자이크 예술의 양대', '월~토 08:30~12:30 /', '무료', 'Piazza Guglielmo II 1, 90046', '목요일 정상 영업 확인. 오전 10시 이전 방문 시 단체 관광객 없어 조용히 감상 가능. 클로이스터(Chiostro)는 성당과 별도 입장권. 옥상 테라스 엘리베이터 없음 — 계단 200개 (60대 선택적으로). 버스 389번: 팔레르모 Piazza dell''Indipendenza 출발 30~40분 간격.', 57),
  (30, '부쿠치아 시장', '비용', '팔레르모 가장 오래된 시장. 14세기부터 운영. 르나토 구투조의 유명 회화 ''부쿠치아''(1974)의 배경. 오전에는 생선·해산물·향신료·채소 시장, 오후부터 청년들의 야외 바 문화 발생. 시칠리아 길거리 음식 영업시간      화~일 12:30~15:00 /                     휴무', '매일 07:00~14:00 (야간 바 문화는', '무료', 'Piazza Caracciolo, 90133 Palermo PA', '소매치기 주의 — 시장 내부 귀중품 관리. 즉석 해산물 튀김(Fritto di Mare) 4~6 도전. 수박(Anguria) 조각 2 — 시칠리아 여름 대표 간식.', 58),
  (30, '카푸친 수도원 카타콤베', '비용', '팔레르모 카푸친 프란치스코 수도회가 1599년부터 1880년대까지 운영한 지하 납골당. 8,000여 구의 방부 처리·미라화된 시신이 성직자·귀족·의사·군인·어린이 구역별로 복도 벽면에 세워져 있다. 특히 1920년 사망한 2세 여아 로살리아 롬바르도(Rosalia Lombardo)의 미라는 ''세계에서 가장 아름다운 미라''로 불리며', '매일 09:00~13:00 / 15:00~18:00', '무료', 'Piazza Cappuccini 1, 90129 Palermo', '충격적인 분위기지만 역사·인류학적 가치가 높은 필수 방문지. 사진 촬영 가능. 실내 기온 낮으니 가벼운 겉옷 권장. 어두운 분위기 — 심장이 약한 분 주의.', 59),
  (30, '테아트로 마시모', '비용', '1875~1897년 건립, 유럽에서 파리 오페라·빈 오페라 다음으로 세 번째로 큰 오페라 하우스. 신고전주의 외관과 붉은 금장식 내부가 장엄. 영화 ''대부 III''의 클라이맥스 장면 촬영지. 1,350석 대극장. 5~6월 시즌 티켓 구입 가능 — 비용 30~80. 외관은 무료로 광장에서 감상.', '가이드 투어: 화~일 09:30~17:30', '무료', 'Piazza Verdi, 90138 Palermo PA', '가이드 투어(한국어 없음 — 영어)로 내부 무대·분장실·VIP룸 견학. 공연 시즌(10~5월) 중이면 야간 오페라 티켓 구입 가능 — 비용 30~80. 외관은 무료로 광장에서 감상.', 60),
  (30, '몬델로 해변', '비용', '팔레르모 북서쪽 15km에 위치한 팔레르모 시민의 해수욕장. 백사장 길이 2km, 에메랄드빛 투명한 바닷물. 100년 넘은 바 카페 (Lo Stabilimento Mondelloo)와 아르누보 건물들이 해변 뒤에 늘어서 있다. 성수기(7~8월)는 극도로 혼잡하지만 5월 말은 아직 조용.', '상시 개방 (성수기 바 서비스', '무료', '90151 Mondello, Palermo PA', '오전 9~11시 이전 도착 시 자리 넉넉. 토요일이라 팔레르모 시민 많음 — 오전 일찍 도착 강력 권장. 해변 식사 — 즉석 아란치나 2, 그라니타(슬러시) 3.', 61),
  (30, '에리체', '비용', '해발 750m 바위 산 정상의 중세 마을. 페니키아·그리스·로마·아랍·노르만인이 차례로 거쳐 간 시칠리아 최고 역사 도시 중 하나. 안개가 자주 끼는 신비로운 분위기. 마리아 그람마티코(Maria Grammatico) 제과점의 전통 시칠리아 마르치판·쿠루쿠탕구·크로스타타가 유명.', '마을 상시 개방 / 케이블카', '무료', '91016 Erice TP', '케이블카는 바람이 강한 날 운행 중단 가능 — 출발 전 funivia-erice.it 확인. 마을 내 미리암 제과점(Pasticceria Maria Grammatico): Via Vittorio Emanuele 14. 시칠리아 전통 과자 선물 쇼핑 최적지.', 62),
  (30, '신전의 계곡', '비용', '기원전 6~5세기 그리스 식민 도시 아크라가스의 신전 군. 콘코르디아 신전은 세계에서 가장 잘 보존된 그리스 신전 중 하나로, 34개 원기둥이 거의 원형에 가깝게 서 있다. 붉은 황토색 사암 신전이 지중해를 내려다보는 능선에 줄지어 늘어선 광경이 압도적. UNESCO 세계문화유산.', '매일 08:30~20:00 (마지막 입장', '무료', 'Via Sacra, 92100 Agrigento AG', '일요일 오전 단체 관광 없이 비교적 한산 (현지 가족 단위 많음). 콘코르디아 신전 → 헤라 신전 → 헤라클레스 신전 → 올림피코 신전 순서 추천. 7~8월은 오전 7시 개방이지만 5월 말은 8:30 개방. 해 뜨는 방향이 아름다움 — 오전 방문 이유.', 63),
  (30, '갈레리아 레지오날레 — 팔라초 아바텔리스', '비용', '팔라초 아바텔리스(15세기 카탈루냐-고딕 궁전)에 위치한 시칠리아 지역 미술관. 주요 작품: 안토넬로 다 메시나의 ''수태고지''(1474, 시칠리아 르네상스 최고 걸작), 작자 미상의 ''죽음의 승리''(15세기 거대 프레스코, 흑사병 시대의 죽음의 기사가 사람들을 베는 장면), 부스토 디 에레오나(엘레오노라 다 아라고나', '화~토 09:00~18:30 / 일', '무료', 'Via Alloro 4, 90133 Palermo PA', '월요일 휴무 — 화요일 방문이었다면 놓쳤을 것. 에어컨 잘 작동하는 실내 — 더운 오후 완벽한 피난처. ''죽음의 승리'' 프레스코는 1층 대형 홀에 별도 전시, 충격적이고 강렬.', 64),
  (30, '카포 시장', '비용', '팔레르모 북쪽 Via Beati Paoli 일대의 재래시장. 발라로보다 더 현지인 비율 높은 시장. 식재료뿐 아니라 의류·잡화·기념품 판매. 시칠리아 향신료, 케이퍼(카페레), 오레가노, 특선 소시지(사르시치아) 구입 최적. 추천. 아몬드 피스타치오 페스토는 귀국 후 파스타에 활용 가능.', '월~토 07:00~13:30', '무료', 'Via Beati Paoli, 90134 Palermo PA', '월요일 정상 영업 확인. 기념품으로 시칠리아 케이퍼(염장/식초) 진공팩 3~5, 피스타치오 페스토 6~8 추천. 아몬드 피스타치오 페스토는 귀국 후 파스타에 활용 가능.', 65),
  (30, '오르티자 섬 두오모 광장 + 대성당', '비용', '기원전 480년 히에론 1세가 카르타고 격파 기념으로 세운 아테나 신전(도리아식 38개 원기둥) 위에 7세기 비잔틴 교회, 이후 아랍 모스크, 노르만 성당을 거쳐 18세기 안드레아 팔마의 바로크 파사드로 완성된 시라쿠사의 상징. 성당 벽면 속에 2,500년 된 그리스 원기둥이 살아있는 것을 내부에서 직접 확인할 수', '성당 08:00~19:00 / 광장 상시 개방', '무료', 'Piazza del Duomo 1, 96100 Siracusa', '오전 9~10시 햇살이 파사드 황금색으로 물드는 시간이 최고 사진 타이밍. 광장 카페 테라스(Bar del Duomo)에서 커피 한 잔 + 성당 조망 추천. 내부 촬영 무료.', 66),
  (30, '아폴로 신전', '비용', '기원전 565년경 건립, 그리스 도리아식 신전으로 시칠리아에서 가장 오래된 그리스 신전. 오르티자 섬 육지 연결 다리 바로 앞 광장에 일부 원기둥과 기단이 보존. 아테나 신전(대성당)과 더불어 시라쿠사 고대 영업시간    화~일 19:00~23:00, 월요일 휴무               휴무', '상시 개방 (유적 외부에서 관람)', '무료', 'Piazza Pancali, 96100 Siracusa SR', '오르티자 섬 진입하자마자 보임. 야간 조명 받는 모습도 아름다움. 주변 카페들이 신전 뷰 테라스 운영.', 67),
  (30, '그리스 극장 — 고고학 공원 네아폴리스', '비용', '기원전 5세기 히에론 1세 시절 건립. 시칠리아에서 가장 크고 가장 잘 보존된 그리스 극장. 67줄 관객석이 천연 암반을 깎아 만들어졌으며, 1만 5천 명 수용. 아이스킬로스, 소포클레스, 에우리피데스의 비극이 초연된 역사적 무대. 현재도 5~6월 ''시라쿠사 고대 연극 축제''(INDA) 기간 공연 개최. 배경의 이오니아 해', '매일 09:00~18:30 (마지막 입장', '무료', 'Via del Teatro Greco, 96100 Siracusa', '6월 초 INDA 고대 연극 축제 공연 기간 — 야간 공연 관람 가능하면 특별 경험. 공연 티켓 fondazioneindasr.com에서 사전 예매. 오전 방문이 그늘 적으므로 모자·선크림 필수.', 68),
  (30, '시라쿠사 파올로 오르시 고고학 박물관', '비용', '시칠리아 최대 고고학 박물관. 선사~로마 시대 시라쿠사 및 시칠리아 동부 발굴품 11만 점 소장. 주요 작품: 베누스 란돌리나(Venere Landolina — 1세기 로마 아프로디테 조각, 상반신 없음에도 완전한 아름다움), 메가라 흙 인형 컬렉션, 청동 기마상. 냉방 잘 되어 있어 더운 오후 최적.', '화~토 09:00~18:00 / 일', '무료', 'Viale Teocrito 66, 96100 Siracusa SR', '목요일 정상 영업. 베누스 란돌리나는 2관 중앙. 그리스 극장 관람 후 박물관 방향이 자연스러운 동선(차량 10분).', 69),
  (31, '노토— 바로크 도시', '비용', '08:00~12:30 / 15:00~19:30 1693년 1월 대지진으로 완전 파괴된 뒤 완전히 새로 설계·건축된 바로크 계획 도시. 시칠리아 특산 황금빛 칼카레니테(석회암)으로 건축된 건물들이 직선 코르소 대로 양쪽에 완벽한 바로크 양식으로 늘어서 있다. 발', '마을 상시 개방 / 대성당', '무료', '96017 Noto SR', '카페 시칠리아(Caffe Sicilia)는 노토 방문 절대 필수. 코르소 대로에서 노토 대성당 계단까지 직선 시야 — 계단 위에서 대로 사진 촬영 최적. 여름 관광 시즌 노토 초만원 — 오전 9시 이전 도착 추천.', 0),
  (31, '모디카+ 초콜릿 문화', '비용', '아랍·스페인 식민지 시절 아즈텍 방식으로 전래된 냉 가공 초콜릿(Cioccolato di Modica IGP)의 고향. 설탕을 가열하지 않아 초콜릿 안에 설탕 결정이 그대로 살아있는 독특한 식감. 비탈진 두 계곡에 걸쳐 있는 도시 구조가 독특하며, 산 조르조 대성당의 황금빛 파사드가 도시를 압도.', '마을 상시 개방 / 돌체리아', '무료', '97015 Modica RG', '안티카 돌체리아 보나주토(Via Grimaldi 84): 1880년 창업, 모디카 초콜릿 원조. 시나몬·칠리·바닐라·캐럽 맛 초콜릿 시음. 모디카 초콜릿 포장 선물 최적 (귀국 수하물 가능). 산 조르조 대성당 242계단 — 60대 하부에서 조망 권장.', 1),
  (32, '폰타네 비안케 해변', '비용', '시라쿠사 남쪽 20km, SS115 해안도로 접근. 시라쿠사 지역에서 가장 아름다운 해변 중 하나. 하얀 모래(Fontane Bianche=하얀 샘의 뜻)와 얕고 맑은 이오니아 해가 특징. 수심이 얕아 노인·가족에게 최적. 여름 성수기도 폼페이·아말피보다 한산.', '상시 개방 (바 서비스 09:00~20:00)', '무료', '96010 Fontane Bianche SR', '시라쿠사 도심에서 차로 25분. SS115 해안도로 드라이브도 아름다움. 해변 선베드 오전 10시 이전 확보 권장. 주차장 무료.', 0),
  (33, '카스텔로 마니아체', '비용', '13세기 프리드리히 2세 황제가 오르티자 섬 최남단 바다 위 돌출 지점에 건립한 노르만-슈바벤 성곽. 3면이 이오니아 해로 둘러싸여 있어 바다 한가운데 있는 듯한 느낌. 성 위에서 시라쿠사 항구 + 오르티자 전경 +', '월~토 08:30~18:30 / 일요일 특정', '무료', 'Via del Castello Maniace 1, 96100', '일요일 개방 여부 사전 확인 필수(불규칙 운영). 성 앞 바다 방파제에서 낚시꾼들과 함께 이오니아 해 조망. 이른 아침 방문 시 조용하고 바람 서늘.', 0),
  (33, '파피루스 박물관', '비용', '아이집트 이외 세계 유일의 파피루스 자생지인 시라쿠사의 파피루스 문화를 전시. 고대 이집트부터 현재까지 파피루스 제작 과정, 문자 기록 역사, 아레투사 샘의 파피루스 자생 생태 설명. 공예품 판매 코너에서 직접 영업시간    화~일 19:00~23:00, 월요일 휴무             휴무', '월~토 09:00~14:00, 일요일 휴무', '무료', 'Via Nizza 14, 96100 Siracusa SR', '일요일 휴무 — 토요일 또는 월~금 방문 권장. 관람 시간 약 45분. 기념품으로 파피루스 카드 3~5 추천.', 1),
  (35, '에트나 화산— 케이블카+4WD 투어', '비용', '해발 3,357m, 유럽 최대 활화산. 남쪽 사면 리푸지오 사피엔자(1,923m)까지 차량 접근, 케이블카로 2,500m, 4WD+가이드로 2,900~3,000m 분화구 인근까지 접근. 화산재·용암 지형·연기 분출 현장. 시칠리아 여행 최고 스릴 체험. 60대 부부: 케이블카+4WD 투어로 도보 없이 접근 가능.', '케이블카: 09:00~16:00 (기상', '무료', 'Rifugio Sapienza, Via Etna, 95030', '에트나 기상 변화 극심 — 출발 당일 운행 여부 확인 필수(www.funiviaetna.com). 정상 기온 10~15도 이하 — 두꺼운 겉옷·장갑 필수. 화산 가스(이산화황) 민감한 분 마스크 지참. 4WD 투어 사전 예약 권장.', 0),
  (35, '타오르미나 그리스 극장', '비용', '기원전 3세기 그리스인이 건립하고 2세기 로마인이 확장한 원형 극장. 무대 뒤로 에트나 화산과 이오니아 해가 동시에 보이는 세계에서 가장 아름다운 극장 배경. 현재도 Taormina Arte 페스티벌(6~9월) 등 공연 개최. 지름 109m, 수용 5,000명.', '매일 09:00~일몰 1시간 전', '무료', 'Via del Teatro Greco 1, 98039', '오전 10시 이전 방문 시 관람객 적음. 오후 3~5시 햇살이 석회암 기둥을 황금빛으로 물들이는 시간 — 사진 최적. 무대 중앙에서 에트나 화산이 무대 배경으로 들어오는 앵글이 포토존.', 1),
  (36, '이솔라 벨라', '비용', '타오르미나 절벽 바로 아래 작은 자연보호구역 섬. 육지와 얕은 모래톱(tombolo)으로 연결되어 있어 썰물 때는 걸어서 건널 수 있다. 주변 해수 투명도가 지중해에서도 최상급. 이오니아 해의 보석 같은 스팟. 케이블카 하부(마짜로 해변)에서 도보 10분.', '해변 상시 개방 / 섬 내 자연보호구역', '무료', 'Via Isola Bella, 98039 Taormina ME', '오전 9~11시가 가장 조용. 성수기 7~8월은 자리 전쟁이지만 6월 초는 한산. 해변에서 에메랄드 물색과 타오르미나 절벽이 함께 찍히는 앵글이 절경.', 0),
  (36, '카스텔몰라', '비용', '타오르미나 위 5km, 해발 529m 절벽 꼭대기의 중세 요새 마을. 인구 1,000명의 조용한 마을이지만 조망은 시칠리아 최고. 아랍 시대 성곽에서 타오르미나 전체 + 이오니아 해 + 에트나 화산을 한 눈에. 아몬드 와인의 에로틱한 내부 장식은 시칠리아 역사적 민속문화의 일부 — 특이 경험.', '마을 상시 개방 / Bar Turisi', '무료', '98030 Castelmola ME', '카스텔몰라 진입 산길: 급커브+협소 — 속도 20km/h 이하. 마을 주차장(무료) 이용 후 도보. Bar Turisi의 에로틱한 내부 장식은 시칠리아 역사적 민속문화의 일부 — 특이 경험.', 1),
  (37, '낙소스 그리스 유적지', '비용', '기원전 734년 칼키스인이 건설한 시칠리아 최초의 그리스 식민도시 유적. 현재는 도시 성벽 일부와 수많은 고대 도자기·동전이 출토된 지점이 보존되어 있다. 인근 박물관(Museo Archeologico di Naxos)에 발굴품 전시. 잔르디니 낙소스 해변과 바로 인접.', '매일 09:00~18:00', '무료', 'Via Stazione, 98035 Giardini Naxos', '해변 산책 후 자연스럽게 연결. 입구 박물관 내 에어컨 — 더운 오후 휴식 겸 관람 가능. 목요일 정상 영업 확인.', 0),
  (37, '타오르미나 공중 정원', '비용', '19세기 영국 여성 플로렌스 트레벨얀이 조성한 열대 정원. 타오르미나 구시가 동쪽 절벽 가장자리에 위치. 선인장·야자수·알로에 등 지중해 식물과 조각들이 정원을 채운다. 정원 테라스에서 이오니아 해와 에트나 영업시간    화~일 12:30~15:00 /                    휴무', '매일 08:00~20:00', '무료', 'Via Bagnoli Croci, 98039 Taormina', '코르소 움베르토에서 도보 5분. 에트나 배경 사진 최적 포인트. 벤치에서 휴식하며 경관 감상 — 60대 부부 완벽 휴식지.', 1),
  (38, '사보카— 대부 촬영지', '비용', '타오르미나 북쪽 20km 메시나 산악 지대의 중세 마을. 프란시스 포드 코폴라 감독의 영화 ''대부''(1972) 시칠리아 장면(마이클과 아폴로니아의 결혼식, 마이클이 피난 와서 아폴로니아를 만나는 바 장면)이 촬영된 곳. 영화 속 그대로 보존된 바 비텔리와 산 니콜로 교회, 중세 성채 폐허가 남아있다.', '마을 상시 개방 / Bar Vitelli', '무료', '98038 Savoca ME', '사보카 진입 산길: 좁고 구불구불 — 천천히. Bar Vitelli 내부: 영화 포스터·사진·코를레오네 가족 기념품 가득. 커피 한 잔 시키면 내부 사진 자유. 이른 오전 방문 시 단체 관광객 없이 조용히 감상 가능.', 0),
  (40, '알베로벨로 트룰리', '비용', '유네스코 세계유산. 석회암 판석(치안코)으로 접착제 없이 쌓은 원뿔형 돌 지붕 집. 풀리아 무르게 고원 특유의 건축 양식. 현재 1,500여 채가 리오네 몬티·아야 피콜라 두 구역에 남아있으며, 일부는 여전히 주거지로 사용. 지붕 꼭대기 석회 도형(점성술·종교 상징)이 각 집마다 다름.', '상시 개방 (리오네 몬티 지구)', '무료', '70011 Alberobello BA', '일요일 오전 9~11시가 가장 조용. 오후 단체 관광 버스 밀림. 아야 피콜라(Aia Piccola) 구역이 리오네 몬티보다 덜 상업화되어 로컬 분위기. 트룰리 숙박 체험도 가능 (이번 여행 숙소는 인근 아쿠아비바).', 0),
  (40, '마르티나 프란카', '비용', '17~18세기 풀리아 바로크 건축의 정수. 하얀 석회 칠한 집들이 미로처럼 얽힌 구시가(Citt Vecchia). 피아자 플레비시토의 두칼레 궁전(Palazzo Ducale)은 바로크 파사드의 걸작. 7~8월 바로크 음악 페스티벌(Festival della Valle d''Itria)로 세계적으로 유명.', '마을 상시 개방', '무료', '74015 Martina Franca TA', '알베로벨로에서 차로 20분. 무료 주차 가능(구시가 외곽). 하얀 골목 탐방 + 풀리아 부레이타 치즈 구입 최적. 바로크 음악 페스티벌 7월 이후 — 이번 방문은 6월로 관광객 적음.', 1),
  (41, '산타 크로체 성당', '비용', '1549년 착공, 1695년 완공. 레체 바로크의 최고 걸작이자 이탈리아 바로크 성당 중 가장 화려한 파사드를 가진 건물. 레체 특산 황금빛 석회암(피에트라 레체제)을 수십 명의 조각가가 200년에 걸쳐 조각. 로즈 창문 주변과 두 층 파사드 전체가 꽃·천사·그리핀·인물 조각으로 빼곡. ''바로크의 과잉''이라 불린다.', '매일 09:00~13:00 / 16:00~20:00', '무료', 'Via Umberto I 1, 73100 Lecce LE', '오전 햇살이 황금빛 석회암 파사드를 가장 아름답게 비추는 시간(10~11시). 성당 바로 뒤 주지사 궁(Palazzo del Governo)의 파사드도 같은 바로크 양식. 레체 구시가 전체가 조각 박물관 수준.', 0),
  (41, '오트란토 성채 + 두오모', '비용', '07:00~12:00, 15:00~19:00 오트란토 성채는 1480년 오스만 투르크 침략으로 800명 주민이 순교한 역사적 현장(성벽 내 순교자 유골 전시). 두오모 내 11~12세기 모자이크 바닥(Mosaico di Pantaleone)은 800㎡ 면적에 인류', '성채 09:00~18:30 / 두오모', '무료', 'Piazza del Castello, 73028 Otranto LE', '오트란토 모자이크 바닥: 당대 최고 장인 판탈레오네가 제작. 중세 세계관 전체를 담은 압도적 규모. 아침 햇살이 들어올 때 색채 최고.', 1),
  (42, '카스텔 델 몬테', '비용', '1240년 신성로마제국 황제 프리드리히 2세가 건립. 8각형 성채 본체 + 8개의 8각형 탑. 완벽한 수학적 대칭과 춘분·추분 햇빛이 특정 방으로 들어오는 천문학적 설계. ''왜 지었는가''가 아직도 논쟁 중(사냥 별장설, 천문 관측소설, 순례 상징물설). 이탈리아 1유로센트 동전 도안 모델. UNESCO 세계유산.', '매일 10:15~19:45 (3~10월) /', '무료', '76123 Andria BT (Castel del Monte)', '화요일 정상 영업 확인. 내부는 비어있어 건축 자체가 전시물. 외부에서 8각형 전체 들어오는 사진: 성채 남동쪽 50m 지점. 주차장 완비(무료). 여름 성수기 사전 예약 권장.', 0),
  (42, '알타무라 빵', '비용', '이탈리아 최초로 DOP(원산지 인증)를 받은 빵. 알타무라 지역 재배 듀럼 밀(세몰라 리마치나타)만 사용. 황금빛 껍질, 부드러운 속결, 특유의 고소한 향. 냉동 보관 시 수일 가능. 기념품으로 소형 포장 구입 추천. 현지 최고 빵집: Panificio Piccoli Forno — Via Matera', '빵집: 06:00~13:00 /', '무료', '70022 Altamura BA (구시가 빵집', '알타무라 구시가 입구 Via Matera 방향에 전통 빵집 집중. 갓 구운 것 바로 먹는 것이 최고. 풀리아 올리브오일+방울토마토와 함께 현지식 식사.', 1),
  (44, '그라비나 인 풀리아', '비용', '석회암 협곡(그라바, Grava) 위에 자리잡은 중세 마을. 협곡 건너편에서 바라보는 마을 전경이 압도적. 2008년 영화 007 ''퀀텀 오브 솔러스''에서 중간 보스 사무실 장면이 촬영된 곳. 16세기 아케두또(수로교)가 협곡을 가로질러 현재도 원형 보존. 남부 이탈리아 비밀의 숨겨진 보석.', '마을 상시 개방', '무료', '70024 Gravina in Puglia BA', '협곡 조망 최적 포인트: Via Appia 방향 전망대. 수로교(폰테 아케두또) 사진: 협곡 반대편 Via Vito Melodia에서 전체 구도 가능. 마을 진입 후 구시가 주차장 이용.', 0),
  (44, '그라비나 수로교', '비용', '1754년 완공된 바로크 시대 수로교. 협곡 깊이 30m를 가로지르는 5개의 아치. 그라비나 구시가와 맞은편 절벽 동굴 주거지(사시)를 연결. 이탈리아 남부 공학의 걸작이자 포토 포인트. 영업시간     화~일 12:30~15:00 /                       휴무', '상시 개방 (외부 관람)', '무료', 'Via Appia, 70024 Gravina in Puglia BA', '수로교 정면 사진: 협곡 아래 Via Matteotti에서 올려다보는 구도. 아침 10~11시 햇빛 방향 최적.', 1),
  (45, '산 비탈레 성당', '비용', '526~547년 건립. 이탈리아에서 가장 중요한 비잔틴 건축물. 팔각형 평면 구조로 서로마의 바실리카와 동로마의 집중식 성당을 결합. 내부 금빛 모자이크가 전체를 뒤덮음. 특히 유스티니아누스 황제와 테오도라 황후 모자이크 패널은 세계 비잔틴 미술의 최고봉. 단테의 신곡에서 천국 묘사의 영감이 된 공간.', '매일 09:00~19:00 (3~10월) /', '무료', 'Via San Vitale 17, 48121 Ravenna', '오전 9시 30분 전후 방문 시 관광객 적음. 갈라 플라키디아 영묘와 동일 부지 — 함께 방문. 천장 황금 모자이크 감상 위해 목 받침대(폰 목 방지) 또는 거울 이용.', 0),
  (45, '갈라 플라키디아 영묘', '비용', '425~430년 건립. 서로마 황후 갈라 플라키디아(테오도시우스 대제의 딸)의 영묘로 추정. 외부는 단순한 십자형 벽돌 건물이지만, 내부는 코발트 블루 바탕에 황금 별과 그리스도·성인 모자이크로 완전히 덮여 있음. 입장 인원 제한(15~20명) — 반드시 사전 예약 필요. 라벤나에서 가장 신비로운 공간.', '매일 09:00~19:00 (3~10월) /', '무료', 'Via Galla Placidia, 48121 Ravenna RA', '예약 필수: ravennafestival.org 또는 현장 예약 (전날 확인 권장). 입장 대기 5분. 내부 20분 체류. 코발트 블루 천장 별 모자이크: 맑은 날 외부 빛이 들어올 때 색채 최고.', 1),
  (45, '단테 알리기에리 무덤', '비용', '1321년 망명 중 라벤나에서 사망한 단테의 영묘. 피렌체 시가 수차례 유해 반환을 요구했지만 라벤나가 거부. 신고전주의 소형 건물 내부에 대리석 석관. 입구에 영원의 불꽃 점등. 단테 박물관(Museo 영업시간     화~일 12:00~14:30 /                휴무', '매일 10:00~19:00', '무료', 'Via Dante Alighieri 9, 48121 Ravenna', '무료 입장. 관람 5~10분. 신곡 관련 관심 있으면 옆 단테 박물관(Museo Dantesco) 추가 방문.', 2),
  (46, '산 아폴리나레 인 클라세', '비용', '547년 완공. 초기 비잔틴 바실리카의 완벽한 보존 형태. 클라세(고대 항구 도시) 수호 성인 아폴리나레를 위한 성당. 외부: 원통형 종탑(캄파닐레)이 라벤나 평원에 우뚝. 내부 앱스: 황금빛 배경에 성인 아폴리나레가 12마리 양(사도)을 이끄는 대형 모자이크. 초기 기독교 미술의 최고봉 중 하나.', '월~토 08:30~19:30 / 일', '무료', 'Via Romea Sud 224, 48124 Ravenna', '라벤나 시내에서 차로 10분. 주차 완비(무료). 관광객이 산 비탈레보다 훨씬 적음 — 여유롭게 감상 가능. 내부 모자이크 조도 좋은 오전 10~11시 방문 추천.', 0),
  (46, '네오니아노 세례당', '비용', '5세기 초 건립. 라벤나 팔각형 세례당. 돔 천장 모자이크: 세례 요한이 예수를 세례하는 장면을 중심으로 사도 행진이 원형으로 배치. 비잔틴 이전 서로마 시대 모자이크 양식의 정수. 도심 내 위치로 접근 편리. 영업시간     목~화 12:00~14:30 /                   휴무', '매일 09:00~19:00', '무료', 'Piazza Arcivescovado 1, 48121', '구시가 중심에 위치. 도보 접근 가능. 관람 15~20분. 아리우스파 세례당(Battistero degli Ariani)과 같은 날 방문 추천 (도보 10분 거리).', 1),
  (47, '테오도리쿠스 영묘', '비용', '526년경 건립. 동고트 왕국의 왕 테오도리쿠스 대왕의 영묘. 지름 14m의 이스트리아 석회암 단일 블록으로 제작한 10각형 돔 — 고대 로마 이후 최대 규모의 단일 석재 지붕. 모르타르 없이 정밀하게 맞춘 석재 기술이 경이로움. 비잔틴 모자이크가 없음에도 건축 자체가 주는 강렬한 인상. 유네스코 세계유산.', '화~일 08:30~19:30, 월요일 휴무', '무료', 'Via delle Industrie 14, 48122 Ravenna', '일요일 오전 개관. 라벤나 시내에서 도보 또는 리스카로 10분. 주차 편리. 내부 2층 전실에 테오도리쿠스의 반암 석관 원형 보존.', 0),
  (47, '코마키오 트레폰티', '비용', '1638년 건립된 5개 아치를 가진 바로크 다리. 코마키오 구도심을 3방향으로 연결. 이탈리아에서 가장 아름다운 다리 중 하나로 선정. 운하 위 반영과 함께 촬영하면 압도적 풍경. 코마키오는 아드리아 해 석호(라구나)에 형성된 운하 도시 — ''작은 베네치아''로 불림.', '상시 개방', '무료', 'Piazzale Buonafede, 44022', '트레폰티 최적 사진 포인트: Via Agatopisto 방향 운하변. 오전 또는 석양 시 반영 최고. 코마키오 뱀장어 마리네이드(아길라 마리나타)는 현지 특산 — 진공 포장 기념 구입 가능.', 1),
  (49, '팔로리아 곤돌라', '비용', '코르티나 구시가에서 도보 5분. 팔로리아 산(2,123m)으로 연결하는 최신 곤돌라. 8분 만에 해발 2,000m 이상으로 상승. 정상에서 크리스탈로(3,221m)·토파나 디 로체스(3,244m)·마르몰라다 등 돌로미티 주요 봉우리 파노라마. 60대에 최적 — 케이블카로 고산 전망 접근.', '08:30~17:00 (여름 성수기)', '무료', 'Via del Castello 48, 32043 Cortina', '성수기 줄 있음 — 09:00 이전 탑승 권장. 정상 테라스 20분 전망 후 하산. 겉옷 필수 (정상 15~17도). 카페테리아 운영.', 0),
  (49, '친쿠에 토리 리프트 + 야외 박물관', '비용', '팔자레고 파소(2,192m) 인근. 의자식 2인 리프트로 5개의 수직 돌로미티 암봉(친쿠에 토리)에 접근. 1차 세계대전 당시 오스트리아-이탈리아 격전지. 당시 참호·포진지·군사 장비가 야외 박물관으로 보존. 암봉 사이 평탄한 트레일로 산책 — 60대에 적합한 수준.', '09:00~17:00', '무료', 'Passo Falzarego, 32043 Cortina', '팔자레고 파소 주차장(무료)에서 리프트 탑승. 코르티나에서 차로 15분. 리프트 탑승 전 방수 겉옷 착용 권장. 리푸지오 스코이아톨리에서 점심 추천.', 1),
  (50, '라가주오이 케이블카 + 정상', '비용', '팔자레고 파소(2,105m)에서 라가주오이 정상(2,778m)까지 5분. 코르티나 주변 최고 전망 포인트. 360도 파노라마: 마르몰라다 빙하·크리스탈로·토파나·친쿠에 토리·팔레 디 산 마르티노. 정상 리푸지오에서 전망 커피 가능. 케이블카 탑승소 팔자레고 파소에 무료 대형 주차장 완비. 1차 세계대전 당시', '08:30~17:00 (여름)', '무료', 'Passo Falzarego, 32043 Cortina', '오전 9~11시 구름 없어 시야 최적. 정상 기온 약 12~15도 — 두꺼운 겉옷 필수. 케이블카 대기 오전 15~20분. 팔자레고 주차 무료(넓음).', 0),
  (51, '미수리나 호수', '비용', '해발 1,756m. 이탈리아 돌로미티에서 가장 아름다운 호수 중 하나. 소라피스 산군(3,205m)이 수면에 반영되는 아침 조망 최고. 호수 둘레 약 2.8km의 완만한 산책로 — 60대에 최적. 트레 치메 진입로', '상시 개방', '무료', '32041 Auronzo di Cadore BL', '오전 8~10시 바람 없을 때 수면 반영 최고. 호수 남쪽 주차장 무료. 카페/레스토랑 호수변 위치. 트레 치메 유료도로 진입구가 호수에서 2km.', 0),
  (51, '트레 치메 디 라바레도', '비용', '세계적으로 유명한 돌로미티 3개의 수직 암봉 — 피콜라(2,857m)·그란데(2,999m)·오베스트(2,973m). 1935년 세계 최초 북벽 등반 이후 암벽 등반의 성지. 아우론조 산장(2,333m)까지 차량 진입 가능. 산장에서 북벽 정면 조망 포인트까지 평탄 트레일 약 30분 — 60대 가능. 돌로미티 최고 절경.', '유료도로 06:00~20:00 (여름)', '무료', 'Rifugio Auronzo, 32041 Auronzo di', '유료도로 입구: 미수리나 호수에서 2km. 차량 30 지불 후 진입. 아우론조 산장 주차 후 도보. 북벽 조망 포인트: 산장에서 반시계 방향 30분. 왕복 60분이면 충분.', 1),
  (52, '크리스탈로 케이블카', '비용', '코르티나 북쪽 크리스탈로 산군 접근 케이블카. Son Forca(1,843m)에서 Forcella Staunies(2,932m)까지 2단계. 정상에서 코르티나 담페초 분지 전체, 마르몰라다 빙하, 트레 치메 등 돌로미티 전방위 조망. 고도가 높아 시원하고 맑은 날 시야 최고. 코르티나 4일 중 마지막 하이라이트.', '08:30~17:00 (여름)', '무료', 'Via Cantore, 32043 Cortina', '코르티나 구시가에서 차로 5분. 주차 있음. 성수기 오전 일찍 방문 권장. 정상 기온 10~13도 — 겉옷 필수.', 0),
  (54, '세체다 케이블카 + 능선', '비용', '오르티세이에서 세체다 능선(2,519m)까지 2단계 케이블카. 이탈리아 돌로미티에서 가장 인상적인 능선 조망 중 하나. 사스 리가이스(3,025m) 등 가르데나 협곡 북쪽 암봉군이 파노라마로 펼쳐짐. 능선 상부는 완만한 고원으로 평탄 트레일 산책 가능 — 60대에 최적. 돌로미티 SNS 대표 사진 배경지.', '08:30~17:30 (여름 성수기)', '무료', 'Via Furines 38, 39046 Ortisei BZ', '일요일 성수기 — 오전 08:30~09:00 탑승 권장. 능선 기온 12~15도 — 겉옷 필수. 리푸지오 세체다까지 도보 15분 평탄. 점심 예약 불필요 (현장 착석).', 0),
  (54, '오르티세이 목조각 공방 거리', '비용', '오르티세이(St. Ulrich)는 알프스 목조각 공예의 세계적 중심지. Via Rezia를 중심으로 전통 목조각 공방·갤러리 집중. 성인상·동물·가구부터 현대 추상 작품까지 다양. 라딘어로 조각을 뜻하는 ''스쿨투라''가 마을 정체성. 고급 원목 조각품 기념품으로 최적.', '월~토 09:00~12:30 /', '무료', 'Via Rezia, 39046 Ortisei BZ', '일요일 일부 공방 휴무 가능 — 오전보다 오후 운영 많음. 소형 성인상 15~50, 대형 조각 100 이상. 오르티세이 마을 박물관(Museo della Val Gardena)에서 라딘 문화 전시 무료 관람 가능.', 1),
  (55, '알페 디 시우시 고원', '비용', '해발 1,800~2,350m, 면적 56km². 알프스에서 유럽 최대 규모의 고원 초원. 6월 말~7월 초 야생화 최성기 — 황금빛 미나리아재비 + 보라 아네모네 + 흰 데이지 가득. 남쪽으로 샤슬라(Schlern/Sciliar, 2,563m) 수직 암봉이 극적으로 대비. 소떼·목동·전통 산장(말가)이 그대로 운영. 차량 진입 금지(여름) — 곤돌라', '곤돌라 08:00~18:30 (여름)', '무료', 'Compatsch, 39040 Castelrotto BZ', '6월 29일 야생화 절정 시기. 콤파치 주변 평탄 트레일 — 60대 적합. 고원 내 전기 미니 트랙터 택시 운행(유료). 겉옷 필수 (고원 기온 12~16도).', 0),
  (56, '카스텔로또', '비용', '알토 아디제 대표 전통 남티롤 마을. 15세기 종탑이 있는 광장(Piazza Kraus)을 중심으로 알프스 목조 건물들이 늘어선 그림 같은 마을. 이탈리아이지만 완전한 독일어·오스트리아 문화권. 알페 디 시우시 접근 기지 마을로도 유명. 6월 말 마을 꽃장식(제라늄) 최성기.', '마을 상시 개방', '무료', '39040 Castelrotto BZ', '카스텔로또 종탑: 매시 정각 종소리 울림. 오전 방문 시 인파 적음. 제과점(베케라이)에서 구겔후프·아펠슈트루델 구입 추천.', 0),
  (56, '발 가르데나 SR242 드라이브', '비용', '오르티세이(St. Ulrich) → 산타 크리스티나(St. Christina) → 셀바(Wolkenstein) 약 15km의 돌로미티 협곡 드라이브. 협곡 양쪽으로 세체다 암봉·사스 리가이스 수직 암벽이 연속. 이탈리아 최고의 경관 드라이브 루트 중 하나. 셀바에서 가르데나 파소(2,121m)로 계속 연결.', '상시', '무료', 'SR242, Ortisei → Selva di Val Gardena', 'SR242 왕복 약 30km, 30분. 셀바 마을 광장에서 U턴. 도중 전망 포인트마다 주차 공간 있음.', 1),
  (58, '벨라조', '비용', '코모 호수 3개 지류의 분기점에 위치한 인구 2,000명의 마을. ''이탈리아 호수 지방의 진주''. 꽃이 가득한 계단 골목(살리타 세르포니), 호수변 카페, 빌라 멜치·세르벨로니 등 귀족 빌라 정원. 벨라조 페리 정착지에서 바라보는 호수 분기 조망이 압도적. 전통 코모 실크 제품 기념품.', '마을 상시 개방 / 빌라 세르벨로니 정원', '무료', '22021 Bellagio CO', '페리: 코모 → 벨라조 1시간. 빌라 세르벨로니 정원 투어: 10:00·11:00·15:00·16:00 출발 (영어·이탈리아어). 계단 골목 사진: 아침 일찍 또는 오후 늦게 관광객 적음.', 0),
  (58, '코모 두오모', '비용', '14세기~18세기에 걸쳐 완공. 고딕·르네상스·바로크 양식이 혼합된 독특한 파사드. 내부 르네상스 시대 태피스트리 14장 보존. 파사드 좌우에 로마 시대 작가 대플리니우스(코모 출신)와 소플리니우스 조각상. 영업시간     목~화 12:00~14:30 /                      휴무', '매일 09:00~17:30', '무료', 'Piazza del Duomo, 22100 Como CO', '코모 선착장에서 도보 3분. 이른 오전 방문 시 내부 조용. 태피스트리 감상 후 두오모 광장 카페에서 에스프레소.', 1),
  (59, '빌라 카를로타', '비용', '18세기 귀족 빌라. 1843년 프로이센 공주 카를로타에게 결혼 선물로 증여되어 ''빌라 카를로타''로 명명. 테라스식 4ha 정원: 진달래 500품종·장미·열대 식물원. 7월 장미 최성기. 내부: 안토니오 카노바의 ''사랑과 프시케'' 복제 조각 원본급 보존. 코모 호수 전망 계단식 테라스가 극적.', '매일 09:00~19:30 (3~10월)', '무료', 'Via Regina 2, 22016 Tremezzo CO', '7월 초 장미+진달래 동시 개화 (부분). 입장 후 정원 먼저 탐방 권장. 내부 조각 갤러리 30분. 빌라 카를로타 페리 정착지에서 하선.', 0),
  (59, '바레나', '비용', '코모 호수 동쪽 지류의 인구 800명 소마을. 분홍·노랑·오렌지색 건물들이 절벽에 매달린 모습이 코모 호수의 가장 아름다운 포토 포인트. 바레나 선착장에서 바라보는 맞은편 트레메조·카데나비아 전경도 압도적. 빌라 몬아스테로 정원(8)과 빌라 시르몬도 정원(6)도 인근.', '마을 상시 개방', '무료', '23829 Varenna LC', '바레나: 페리 하선 후 구시가 자유 탐방. 계단 골목은 좁고 계단 많음 — 짧게 30분 이내 추천. 선착장 바로 옆 호수변 카페에서 젤라토+에스프레소.', 1),
  (61, '그란 파라디소 국립공원', '비용', '1922년 설립. 이탈리아 최초 국립공원. 알프스 아이벡스(야생 염소) 최대 서식지 — 코냐 마을 주변에서 흔히 목격 가능. 그란 파라디소 산(4,061m)이 공원 중심. 코냐 마을 → 그란 프라도 완만 초원 산책로 — 60대에 적합. 7월 야생화 절정 시기.', '상시 개방', '무료', 'Frazione Valnontey, 11012 Cogne', '코냐 마을 주차 후 도보 탐방. 그란 프라도 초원(Prato di Sant''Orso) 방향 완만 트레일 30분. 알파인 동물원(Giardino Botanico Alpino Paradisia) 무료 방문 가능. 아이벡스 목격 확률: 이른 아침 높음.', 0),
  (61, '아오스타 로마 극장', '비용', '기원전 1세기 건립. 3,000석 규모 로마 야외 극장. 무대 벽면 3층 구조 일부 보존. 그란 파라디소 방향 알프스 배경과 어우러진 로마 유적 — 독특한 조합. 인근 성벽·아우구스투스 개선문과 묶어 탐방 가능. 영업시간      화~일 12:00~14:30 /                   휴무', '매일 09:00~19:00 (여름)', '무료', 'Via Arco d''Augusto 6, 11100 Aosta', '아오스타 구시가 동쪽 끝. 무료 주차 가능. 로마 극장 → 아우구스투스 개선문 도보 5분. 이른 오전 입장 시 빛 방향 최적.', 1),
  (62, '체르비니아 플라토 로사 케이블카', '비용', '체르비니아에서 2단계 케이블카로 3,488m 플라토 로사 빙하 고원 도달. 이탈리아와 스위스 국경 능선 위. 마터호른(4,478m) 이탈리아 면 정면 조망. 여름에도 스키 가능 빙하 지대. 스위스 체르마트 방향 레만 호수까지 조망 가능. 기온 0~5도 — 방풍·보온 의류 필수.', '08:30~16:30 (여름)', '무료', 'Via Guido Rey, 11021 Breuil-Cervinia', '케이블카 탑승소: 체르비니아 마을 중심. 2단계 연결: 쉬엘트론(2,500m) → 플라토 로사(3,488m). 합산 약 20분. 정상 리푸지오에서 따뜻한 음료 필수. 고산병 주의 — 두통 시 즉시 하산.', 0),
  (62, '라고 블루', '비용', '체르비니아 마을 바로 위 청록색 빙하 호수. 마터호른(체르비노) 수면 반영. 호수 한 바퀴 완만 산책로 약 20~30분 — 60대에 최적. 오전 바람 없을 때 반영 최고. 체르비니아 케이블카 하산 후 방문 추천. 영업시간    매일 12:00~14:30 / 19:00~21:30           휴무', '상시', '무료', '11021 Breuil-Cervinia AO', '체르비니아 마을에서 도보 15분 상행 (완만). 마터호른 반영 최적 포인트: 호수 북동쪽 끝. 오전 10~12시 바람 없는 맑은 날 반영 최고.', 1),
  (63, '스카이웨이 몽블랑 케이블카', '비용', '2015년 개통. 세계 최첨단 360도 회전 케이블카. 쿠르마이외르(1,224m) → 파비용(1,370m) → 피오나이(2,173m) → 폰테 달레 로니스(3,466m) 3단계. 각 곤돌라가 주행 중 360도 회전하며 전방위 파노라마 제공. 정상에서 몽블랑(4,808m) 빙하 벽 정면 조망. ''스카이웨이''라는 이름처럼 하늘 위에서', '08:00~16:30 (여름 / 요일별 차이)', '무료', 'Strada Statale 26 della Valle d''Aosta,', '사전 예약 강력 권장: monterosasky.it. 여름 성수기 매진 빈번. 정상 기온 -2~5도 — 패딩 재킷 필수. 고산병 주의 (3,466m). 맑은 날 마터호른·그랑드 조라스·쿠르마이외르 계곡 전체 조망 가능.', 0),
  (63, '쿠르마이외르 구시가', '비용', '이탈리아 최고급 알파인 리조트. Via Roma를 중심으로 명품 아웃도어 브랜드(몽클레르·아크테릭스·노스페이스 등)와 로컬 공방이 공존. 전통 석조 알파인 건물들이 잘 보존된 구시가. 중세 교회(Sant''Orso) + 알파인 박물관. 7월 여름 성수기 활기.', '마을 상시 개방', '무료', 'Via Roma, 11013 Courmayeur AO', '', 1),
  (65, '앙시 구시가 + 팔레 드 릴', '비용', '14세기 사부아 공국 수도. 티우 강 운하가 구시가를 가로질러 흐르며 운하 위 다리와 꽃으로 장식된 골목이 ''알프스의 베네치아'' 분위기. 팔레 드 릴은 운하 섬 위 12세기 건물로 감옥·법원·조폐국으로 사용됨 — 앙시 가장 유명한 포토 포인트. 목요일 아침 꽃·채소 시장 운영.', '구시가 상시 / 팔레 드 릴', '무료', 'Quai de l''le, 74000 Annecy, France', '팔레 드 릴 최고 사진 포인트: Pont Perrire 다리에서 바라보는 구도. 오전 9~10시 관광객 적음. 목요일 꽃 시장은 7시~12시 (Rue Sainte-Claire 일대).', 0),
  (65, '앙시 호수 유람선', '비용', '앙시 선착장에서 출발하는 1시간 또는 2시간 30분 호수 유람선. 에메랄드빛 알파인 호수 위에서 알프스 봉우리 파노라마 조망. 뒬리에(Duingt) 성채 + 탈루아르(Talloires) 마을 경유. 유럽에서 가장 깨끗한 호수 영업시간      화~일 12:00~14:00 /                     휴무', '10:00~18:00 (여름 1시간 간격', '무료', '2 Place aux Bois, 74000 Annecy,', '선착장: Place aux Bois (구시가 동쪽). 1시간 유람 충분. 선상 우측 자리가 알프스 조망 유리. 성수기 출발 15분 전 탑승 권장.', 1),
  (67, '리스카 차량 인수 — 푸조 오픈 유럽', '차량인수', 'Malpensa, Ferno VA 21010 69일 여행의 발인 푸조 3008 가솔린 하이브리드를 인수하는 가장 중요한 첫 번째 미션. 예약번호 11543743, 계약자 Mr. MOON JANGHWAN으로 등록. 차량 인수 시 외관 전체 촬영이 귀국 시 분쟁', '말펜사 공항 내 터미널 1 도착 로비', '무료', 'Terminal 1, Aeroporto di Milano', '①플래시로 사방 찍기 ②흠집·긁힘 발견 시 직원 서명+사진 동시 ③형광 안전조끼·삼각대·구급상자 트렁크 확인 ④국제면허+한국면허+여권 3종 제시', 0),
  (67, '밀라노 두오모', '성당·전망', '09:00~21:00 (마지막 입장 20:00) 1386년 착공, 1965년 완공. 세계에서 세 번째로 큰 고딕 성당. 옥상 테라스에서 알프스까지 보이는 밀라노 전경을 조망. 첨탑 135개가 숲처럼 펼쳐진 광경은 이탈리아 북부 여행의 하이라이트.', '성당 09:00~19:00 / 옥상', 'EUR26 (W45,500)', 'Piazza del Duomo, 20122 Milano MI,', 'Duomo Pass Lift(엘리베이터 포함) 사전 예약 필수. 옥상 통로 너비 30~50cm — 고소공포증 주의. 계단권(14)은 체력 소모 큼, 반드시 엘리베이터권 선택.', 1),
  (67, '갈레리아 비토리오 에마누엘레 II', '쇼핑·건축', '1867년 착공, 1877년 완공. 유럽에서 가장 오래된 쇼핑 아케이드. 철제 유리 돔이 인상적인 신르네상스 양식 건축물. Prada·Louis Vuitton·Versace 1호점과 역사적인 카페 Biffi·Camparino이 입점. 두오모 광장과 Zucca(1867년)에서 에스프레소 2~3 추천.', '24시간 개방 (매장은 10:00~20:00)', '무료', 'Piazza del Duomo, 20123 Milano MI,', '중앙 팔각형 공간 타일의 황소 그림 위에 발뒤꿈치 올리고 세 번 돌면 행운 — 현지 전통. 역사적 카페 Zucca(1867년)에서 에스프레소 2~3 추천.', 2),
  (67, '라 스칼라 극장', '문화·공연', '1778년 개관한 세계 3대 오페라 극장. 카루소·카라스·파바로티 등 전설적 음악가들이 무대에 올랐던 역사적 공간. 신고전주의 외관은 밀라노 문화의 상징. 내부 스칼라 박물관에는 공연 역사 유물·의상·악기 등 소장.', '박물관 10:00~17:30 (화~일, 월', '무료', 'Piazza della Scala, 20121 Milano MI,', '외관 무료. 박물관 9. 광장(Piazza della Scala) 벤치에서 외관 감상 + 레오나르도 다빈치 동상 앞 사진 추천. 갈레리아에서 도보 2분.', 3),
  (67, '브레라 지구', '예술가 골목', '밀라노 최고의 보헤미안 지구. Via Brera·Via Fiori Chiari·Via Madonnina 골목에 갤러리·앤티크숍·편집샵·카페가 즐비. 핀코테카 디 브레라 미술관(라파엘로·카라바조 소장)이 중심. 두오모 북쪽 도보 15분 거리. 오후 햇살에 골목 걸을 때 가장 아름다운 밀라노의 면모.', '미술관: 화~일 08:30~19:15 (월', '무료', 'Via Brera, 20121 Milano MI, 이탈리아', '돌바닥이므로 운동화 필수. 핀코테카 미술관 15(체력 여유 시). 골목 카페에서 카푸치노 한 잔 마시며 현지인처럼 쉬는 것도 좋은 선택.', 4),
  (67, '나빌리오 운하 & 아페리티보', '운하·문화체험', '12세기에 조성된 밀라노 운하 시스템. Naviglio Grande를 따라 색색의 건물·노천 바·갤러리가 이어지는 낭만적인 지구. 17:30~19:30 아페리티보 타임에 Spritz 한 잔 주문하면 뷔페식 안주(스낵·올리브·핑거푸드)가 무료 제공. 석양빛 운하 반영을 바라보며 즐기는 이탈리아 저녁 문화 체험.', '바 17:00~24:00 / 아페리티보', 'EUR20 (W35,000)', 'Alzaia Naviglio Grande, 20144 Milano', '2인 기준 Spritz 2잔 14~20. 안주 뷔페 무료(선착순). Mag Cafe(45.4535, 9.1728) 추천. 소매치기 많은 지역 — 크로스백 앞으로, 핸드폰 테이블 방치 금지.', 5),
  (67, '최후의 만찬', '비용', '레오나르도 다빈치가 1495~1498년에 그린 세계 최고의 걸작 벽화. 산타 마리아 델레 그라치에 수도원 식당 북쪽 벽에 위치. 15분 단위로 30명씩만 입장 가능하므로 사전 예약 필수. 습기에 약한 템페라 기법으로 그려져 항온항습 유지를 위해 2중 에어록을 통과해야 한다.', '화~일 08:15~19:00 (월요일 휴관),', '무료', 'Piazza di Santa Maria delle Grazie 2,', '예약 없이는 입장 절대 불가. 방문 3~6개월 전 예약 권장. 관람 시간은 15분. 사진 촬영 허용(플래시 금지). 영어 오디오 가이드 추가 3.', 6),
  (67, '스포르체스코 성', '비용', '15세기 밀라노 공국의 스포르차 가문이 건설한 거대 요새 성. 내부에 미켈란젤로의 마지막 조각 ''론다니니의 피에타''를 포함한 여러 박물관이 있다. 붉은 벽돌로 지어진 웅장한 외관과 해자 터가 인상적이며, 60대 부부에게는 광장 내 산책만으로도 충분히 즐길 수 있다.', '성내 광장 07:00~19:30 (무료),', '무료', 'Piazza Castello, 20121 Milano', '매월 첫째 화요일 오후 2시 이후 박물관 무료 개방. 성내 광장 벤치에서 잠시 쉬어가기 좋음. 스포르체스코 성에서 셈피오네 공원까지 도보 2분.', 7),
  (67, '셈피오네 공원', '비용', '스포르체스코 성 뒤편에 펼쳐진 약 38만㎡의 광대한 도심 공원. 영국식 정원 양식으로 조성되어 구불구불한 산책로와 연못, 잔디밭이 자연스럽게 어우러진다. 공원 중심부의 평화의 아치(Arco della Pace)까지', '06:30~21:00 (계절별 상이)', '무료', 'Piazza Sempione, 20154 Milano', '공원 내 Bar Bianco 카페에서 휴식 가능. 자갈길이 많으니 편한 신발 필수. 소매치기 주의 — 소지품 관리 철저.', 8),
  (67, '보스코 버티칼레', '비용', '2014년 완공된 세계적으로 유명한 수직 정원 아파트. 높이 110m·76m 두 동에 걸쳐 약 900그루의 나무, 5,000그루의 관목, 11,000여 본의 지피식물이 심어져 있다. 스테파노 보에리 아키텍티 설계. CNN이 선정한 세계에서 가장 아름다운 건물 중 하나.', '외관 상시 관람 가능', '무료', 'Via Gaetano De Castillia 11, 20124', 'Piazza Gae Aulenti에서 서쪽으로 도보 5분. Porta Nuova 방향에서 보는 뷰가 가장 아름다움. 내부 입장 불가 — 외관 촬영 포인트 선점이 관건.', 9),
  (67, '피아자 가에 아울렌티', '비용', '밀라노 Porta Nuova 재개발 지구의 중심 광장. 원형 분수와 현대적 건축물들이 어우러진 밀라노 신도심의 상징. UniCredit Tower를 비롯한 고층 빌딩들이 둘러싼 광장에서 밀라노의 현재와 미래를 한눈에 볼 수 있다. 영업시간     월~금 12:30~14:30,                     휴무', '상시', '무료', 'Piazza Gae Aulenti, 20124 Milano', '광장 주변 카페와 레스토랑 가격이 합리적. Eataly 밀라노 Smeraldo 지점이 근처에 있어 이탈리아 식품 쇼핑 가능.', 10),
  (67, '푸니콜라레 치타', '비용', '08:30~23:30 (5~10분 간격 운행) 베르가모 하부 도시(치타 바사)와 중세 상부 도시(치타 알타)를 연결하는 100년 역사의 케이블카. 편도 약 3분으로 가파른 언덕을 올라가며 도중에 도시 전경이 펼쳐진다. 60대 부부에게 최적의 이동수단 —', '월~토 07:00~00:30 / 일', '무료', 'Viale Vittorio Emanuele II, 24121', 'ATB 앱(Chat&Go;)이나 현장 발매기에서 티켓 구매. 성수기 주말 오전에는 줄이 생기므로 10분 일찍 도착 권장.', 11),
  (67, '피아자 베키아', '비용', '치타 알타의 심장부이자 베르가모 최고의 광장. 12세기 팔라초 델라 라조네(재판소)와 18세기 팔라초 누오보(도서관)가 마주 보고, 중앙에 콘타리니 분수(1780년)가 자리한다. 르 코르뷔지에가 ''세계에서 가장 아름다운 광장''이라 극찬한 곳. 노천카페에서 커피 한 잔 하며 중세 분위기를 만끽하기에 최고.', '상시', '무료', 'Piazza Vecchia, 24129 Bergamo BG', '광장 주변 카페 가격은 시내 대비 다소 높음(에스프레소 2~3). 아침 10시 이전 방문 시 한산함.', 12),
  (67, '산타 마리아 마조레 대성당', '비용', '14:30~18:00 / 일 09:00~13:00, 1137년 착공한 베르가모의 로마네스크 성당. 내부에 플랑드르 태피스트리(16~17세기)와 도니제티 작곡가의 묘소가 있다. 외관의 화려한 대리석 장식과 내부의 금박 장식이 인상적. 옆의 콜레오니 예배당과', '월~토 09:00~12:30,', '무료', 'Piazza Duomo, 24129 Bergamo BG', '내부 사진 촬영 가능. 미사 시간에는 관광 입장 제한될 수 있음.', 13),
  (67, '콜레오니 예배당', '비용', '14:00~18:30 (월요일 휴관, 3~10월 용병대장 바르톨로메오 콜레오니(1400~1475)가 자신의 묘소로 건립한 르네상스 최고 걸작 중 하나. 조반니 안토니오 아마데오가 설계하여 1476년 완공. 흰색·빨간색·검은색 대리석이 기하학 무늬를 이루는', '화~일 09:00~12:30,', '무료', 'Piazza Duomo 1, 24129 Bergamo BG', '산타 마리아 마조레 성당 바로 옆에 위치해 함께 관람 가능. 내부에 콜레오니 기사 조각상과 금도금 장식 천장이 있음.', 14),
  (67, '베네치아 성벽', '비용', '16세기 베네치아 공화국이 오스만 제국 위협에 대비해 축조한 방어 성벽. 전체 길이 약 6km, 두께 최대 40m. 2017년 유네스코 세계문화유산 등재. 성벽 위 산책로에서 베르가모 하부 도시와 롬바르디아 평원의 부부에게는 일부 구간(전망 좋은 포르타 산 자코모~포르타 산탄드레아)만 걷는 것 추천.', '상시 (성벽 위 산책로)', '무료', 'Via Rocca, 24129 Bergamo BG', '치타 알타에서 Porta San Giacomo 방향으로 나가면 성벽 산책 시작. 전체 일주는 약 1~2시간. 60대 부부에게는 일부 구간(전망 좋은 포르타 산 자코모~포르타 산탄드레아)만 걷는 것 추천.', 15),
  (67, '토레 델 캄파노네', '비용', '피아자 베키아에 솟은 54m 높이의 시계탑. 350년 넘게 매일 밤 10시 정각에 100번의 종을 울리는 것으로 유명. 엘리베이터를 타고 전망대에 오르면 베르가모 치타 알타 전체와 롬바르디아 평원, 날씨 좋은 날에는 영업시간    화~일 12:00~14:30,                  휴무', '화~금 09:30~18:00 / 토·일', '무료', 'Piazza Vecchia, 24129 Bergamo BG', '계단(230개) 또는 엘리베이터 선택 가능. 60대 부부에게는 엘리베이터 강력 추천. 전망대 폭이 좁아 혼잡 시 대기 발생.', 16),
  (67, '몬탈레그로 케이블카', '비용', '1934년 개통, 라팔로 해변에서 해발 612m 몬탈레그로 성지까지 2,350m를 7분 만에 오르는 케이블카. 티굴리오 만 전체와 라팔로, 산타 마르게리타, 멀리 포르토피노 반도까지 펼쳐지는 파노라마가 압권. 정상에 1557년 성모 발현을 기념해 세운 몬탈레그로 성지가 있어 순례지로도 유명.', '09:00~12:30, 14:00~18:00', '무료', 'Piazza Solari 2, 16035 Rapallo GE', '오전 9시 개장과 동시에 이용하면 대기 없이 탑승 가능. 바람이 강한 날은 운행 중단될 수 있으니 날씨 확인. 정상 기온이 해변보다 5~8도 낮으므로 가벼운 겉옷 지참.', 17),
  (67, '노스트라 시뇨라 디 몬탈레그로 성지', '비용', '1557년 한 농부에게 성모 마리아가 발현했다는 전설이 깃든 성지. 케이블카 상부역 바로 옆에 위치해 걷지 않고도 방문 가능. 17세기 건설된 바로크 양식 성당 내부에 비잔틴 성화상이 보존되어 있다. 정상 테라스에서의 리구리아 해안 조망은 이탈리아 최고 중 하나.', '07:00~19:00', '무료', 'Via Santuario di Montallegro, 16035', '성지 내부 복장 규정 있음 — 민소매·반바지 금지. 정상 카페(Bar Montallegro)에서 라팔로 만을 바라보며 커피 한 잔.', 18),
  (67, '포르토피노', '비용', '세계적으로 유명한 이탈리아 리비에라의 보석. 이탈리아 어부 마을 특유의 파스텔 톤 건물들이 작은 항구를 에워싼 그림 같은 풍경. 헤밍웨이, 버튼, 테일러 등 세기의 명사들이 사랑한 곳. 차가 없는 마을이라 오직 페리나 도보(산타 마르게리타에서 3km 해안 트레킹)로만 접근 가능. 항구 주변 카페와 부티크 산책이', '상시 (페리 운항 시간 내)', '무료', 'Piazzetta di Portofino, 16034', '포르토피노 내 식사·커피 가격은 라팔로의 2~3배. 음료 한 잔 정도만 즐기고 식사는 라팔로에서 할 것. 카스텔로 브라운(성) 입장은 계단 많아 60대 부부에게 비추. 피아체타 광장 벤치에서 항구 감상이 베스트.', 19),
  (67, '산 조르조 교회', '비용', '항구 언덕 위에 자리한 포르토피노의 수호성인 교회. 1133년 십자군 전사들이 성 게오르기우스의 유해를 모셔와 세운 것이 기원. 교회 앞 테라스에서 항구 전경을 내려다보는 시점이 포르토피노 최고의 포토 스팟. 계단으로 5분이면 도달하므로 60대 부부도 무리 없음.', '09:00~18:00', '무료', 'Via alla Chiesa di San Giorgio, 16034', '교회 앞 잔디밭에서 항구와 바다를 배경으로 사진 촬영 명소. 오후 햇살에 항구 건물들이 황금빛으로 빛나는 시간대가 최고.', 20),
  (67, '몬테로소 알 마레', '비용', '친퀘 테레 5개 마을 중 가장 크고 평탄한 마을. 모래 해변(페지나)과 조약돌 해변이 공존하며 식당·카페가 가장 많아 60대 부부에게 최적. 구도심(Centro)과 신도시(Fegina)를 연결하는 바위 터널을 걸어서 통과하는 것이 포인트. 유럽연합 PDO 인증을 받은 몬테로소 앤초비(Acciughe di Monterosso)의 본고장.', '상시', '무료', 'Via Fegina, 19016 Monterosso al', '역에서 페지나 해변까지 평지. 구도심 진입은 터널 통과 — 계단 없음. 5월은 성수기 시작 전이라 여유로움. 앤초비 기념품 구입 추천.', 21),
  (67, '베르나차', '비용', '친퀘 테레 5개 마을 중 경관이 가장 아름답다고 꼽히는 마을. 기차역에서 내리면 바로 작은 골목길을 따라 5분 걸으면 항구 광장에 도달. 바다로 돌출된 자연 항구를 형형색색 중세 건물들이 에워싼 그림 같은 풍경. 절벽 위 두오리아 성탑(Torre Doria)에서 내려다보는 전경도 장관이나 60대에게는 계단이 많아 선택사항.', '상시', '무료', 'Piazza Marconi, 19018 Vernazza SP', '기차역→항구 광장: 골목길 도보 5분 (계단 거의 없음). 항구 수영 가능(5월은 다소 쌀쌀). 성탑 오르기는 계단 많아 체력 고려.', 22),
  (67, '시에나 대성당', '비용', '13세기 착공한 이탈리아 고딕 건축의 최고 걸작. 흑백 줄무늬 대리석으로 만든 파사드와 56명 교황 흉상이 줄지어 선 내부, 56장의 대리석 상감 바닥화(Pavimento)가 압도적. 니콜라 피사노의 팔각형 설교단(1268년)은 유럽 조각 역사의 분기점으로 평가받는다. OPA SI PASS 구매 시 인접', '10:30~19:00 (계절별 상이, 목요일', '무료', 'Piazza del Duomo 8, 53100 Siena SI', 'OPA SI PASS가 압도적으로 경제적 (단품 합산 35 이상). 대리석 바닥화는 여름(8~9월)에만 전체 공개 — 5월은 부분 공개. 성당 내부 서늘하므로 가벼운 겉옷 지참.', 23),
  (67, '두오모 오페라 박물관', '비용', '두오모 오른쪽 미완성 증축 벽 내부에 자리한 박물관. 두치오 디 부오닌세냐의 ''마에스타(Maest, 1311년)'' 양면 제단화 원작이 핵심 소장품. 시에나 화파 회화의 정수를 감상할 수 있다.', '10:30~19:00', '무료', 'Piazza del Duomo 8, 53100 Siena SI', '마에스타 제단화는 2층 전시실에 위치. 조명이 어두우므로 눈이 익숙해질 시간 필요.', 24),
  (67, '파치아토네 전망대', '비용', '14세기 대성당 증축 계획(더 큰 성당 건설)이 흑사병으로 중단되어 남겨진 미완성 거대 벽 위에 만든 전망대. 토레 델 만자보다 계단이 적으면서 시에나 구시가지 전경을 360도로 감상 가능. 캄포 광장과 시청 탑이 한눈에 보이는 시에나 최고의 전망 포인트 중 하나.', '10:30~18:00', '무료', 'Piazza del Duomo, 53100 Siena SI', '계단 약 130개 — 토레 델 만자(400개) 대비 훨씬 적음. 60대 부부에게 전망 즐기기 최적. 난간 없는 구간 있으므로 주의.', 25),
  (67, '캄포 광장', '비용', 'UNESCO 세계유산. 유럽에서 가장 아름다운 중세 광장으로 꼽히는 부채꼴 형태의 광장. 1293년 이후 시에나 공화국의 중심지로 기능했으며 중앙의 가이아 분수(Fonte Gaia, 1419년 복제품)와 고딕 양식의 팔라초 푸블리코(시청, 1342년)가 광장을 에워싸고 있다.', '24시간', '무료', 'Piazza del Campo, 53100 Siena SI', '광장은 경사져 있어 한쪽에서 반대쪽을 내려다보는 구도 사진 추천. 주변 카페 테라스 이용 시 1인당 5~8 서비스 차지 각오.', 26),
  (67, '산타 마리아 델라 스칼라', '비용', '두오모 광장 맞은편 13세기 창립 중세 병원 건물을 개조한 대형 박물관. 지하 ''필그림 홀(Pellegrinaio)''의 15세기 프레스코 벽화가 핵심. 시에나의 도시 역사와 의료·사회 복지 역사를 입체적으로 전시. 지하 구조물', '10:30~19:30', '무료', 'Piazza del Duomo 2, 53100 Siena SI', '두오모 관람 후 바로 옆이므로 연계 방문 효율적. 지하 구역은 시원하고 조명이 독특해 분위기 있음.', 27),
  (67, '산 도메니코 성당', '비용', '시에나의 수호성인 성녀 카테리나(1347~1380)와 깊이 연결된 고딕 성당. 성녀의 두개골 성유물이 보관된 채플과 15세기 안토니오 소도마의 프레스코화가 있다. 언덕 위에 위치해 두오모와 시에나 서쪽 전경을 영업시간     12:30~14:30, 19:30~22:00              휴무', '07:00~18:30', '무료', 'Piazza San Domenico, 53100 Siena SI', 'Santa Caterina 주차장 에스컬레이터 바로 위에 위치 — 주차 후 첫 방문지로 동선 최적. 내부 성유물 채플은 경건하게 관람.', 28),
  (67, '카펠라 디 비탈레타', '비용', '밀밭과 구릉 한가운데 홀로 선 작은 예배당. 양쪽으로 사이프러스 나무가 줄지어 서 있는 구도가 발도르차 대표 사진으로 전 세계에 알려진 곳. 1480년경 건립. SP146에서 비포장 진입로(약 200m)로 들어가면 도달. 이른 아침 안개가 걷힐 무렵 황금빛 빛살이 드는 시간대가 최고.', '상시 (외관)', '무료', 'SP146, 53026 San Quirico d''Orcia SI', '비포장 진입로 진입 시 저속 운전. 리스카(3008)로 충분히 접근 가능. 해 뜨고 1~2시간 후 역광 없이 촬영 최적.', 29),
  (67, '산 키리코 도르차', '비용', '중세 성벽이 온전히 남아 있는 발도르차의 관문 소도시. 12세기 콜레지아타 성당의 세 개 정문(포르탈레)이 로마네스크·고딕 양식 조각의 걸작으로 꼽힌다. 성벽 안 호르티 레오니니(Horti Leonini) 16세기 이탈리아식 정원은 탁 트인 발도르차 풍경과 함께 산책하기 좋다.', '상시', '무료', 'Piazza della Libert, 53027 San', '성벽 안 주차 불가 — 외곽 무료 주차장 이용. 콜레지아타 성당은 외관 장식이 핵심. 호르티 레오니니는 경사 없는 테라스 정원으로 60대 부부 산책 최적.', 30),
  (67, '바뇨 비뇨니', '비용', '세계에서 유일하게 광장 중앙에 온천 욕조가 있는 마을. 로렌초 데 메디치, 교황 피우스 2세, 성녀 카테리나가 치료 목적으로 방문한 기록이 있는 중세 온천 마을. 현재 광장의 온천수(52°C)는 수영 금지이나, 마을 아래 인공 탕(파르코 데이 물리니)에서 흘러내리는 온천수 체험 가능. 안드레이', '상시', '무료', 'Piazza delle Sorgenti, 53027 Bagno', '광장 온천 수영 절대 불가 (벌금 부과). 주변 온천 스파 호텔에서 유료 이용 가능. 마을 자체가 소규모라 30분이면 충분. 인접 계곡 테라체(Terrace) 뷰 포인트 추천.', 31),
  (67, 'SP146 사이프러스 가로수길', '비용', '산 키리코 도르차에서 피엔차 사이 약 12km 구간의 SP146 지방도. 구불구불한 언덕길을 따라 수백 년 된 사이프러스(Cupressus sempervirens) 나무들이 늘어서며 토스카나의 상징적 풍경을 만들어낸다. 유네스코 세계유산 발도르차의 핵심 경관. 봄철(4~6월) 녹색 밀밭과 사이프러스의 조합이 가장 아름답다.', '상시', '무료', 'SP146, 산 키리코~피엔차 구간', '차창을 열고 천천히 드라이브하며 촬영. 갓길 넓은 곳에서 주차 후 사진 가능. 맞은편 차량 주의 — 폭 좁은 구간 있음.', 32),
  (67, '피엔차', '비용', '교황 피우스 2세(1405~1464)가 르네상스 이상 도시로 설계한 유네스코 세계유산 소도시. 피콜로미니 광장을 중심으로 두오모·팔라초 피콜로미니·팔라초 코뮤날레가 완벽한 르네상스 구성을 이룬다. ''피엔차 페코리노 치즈(DOP)''의 본고장으로 거리 곳곳에 치즈 가게가 늘어서 있다.', '상시', '무료', 'Piazza Pio II, 53026 Pienza SI', '성벽 남쪽 벨베데레에서 발도르차 파노라마가 펼쳐짐 — 필수 방문. 페코리노 치즈 시식 무료 제공 가게 多. 피콜로미니 궁전 내부 투어 7.', 33),
  (67, '피아차 델라 치스테르나', '비용', '13세기 우물(치스테르나)이 중앙에 자리한 산 지미냐노의 심장 광장. 삼각형 모양 광장 주변으로 중세 탑들이 촘촘히 솟아 있어 어느 각도에서 봐도 그림 같은 풍경. 한때 72개에 달했던 탑은 현재 14개가 남아', '상시', '무료', 'Piazza della Cisterna, 53037 San', '광장 모퉁이 카페 테라스에서 탑 배경 사진 촬영. 토요일 오전 장시가 열려 현지 농산물 구경 가능.', 34),
  (67, '두오모', '비용', '12세기 로마네스크 성당. 내부 전체를 덮는 구약성서(왼쪽 벽)·신약성서(오른쪽 벽) 프레스코 연작과 최후의 심판(Barna da Siena, 1380년)이 압도적. 성당 자체보다 내부 그림이 더 유명한 ''그림 박물관'' 같은', '10:00~19:30 (토 10:00~17:30)', '무료', 'Piazza del Duomo, 53037 San', '토요일 오후 단체 관광객 혼잡 — 오전 개장 직후 방문 권장. 내부 사진 허용(플래시 금지).', 35),
  (67, '토레 그로사 전망대', '비용', '산 지미냐노에서 유일하게 일반 공개되는 탑(54m). 계단 218개. 정상에서 나머지 13개 탑과 토스카나 구릉, 날씨 좋은 날 시에나까지 조망 가능.', '10:00~19:30', '무료', 'Piazza del Duomo 2, 53037 San', '계단 218개 — 60대 부부 무리하지 말 것. 중간 층에서 조망만 해도 충분. 파치아토네(시에나)보다 계단 많음.', 36),
  (67, '젤라테리아 돈돌리', '비용', '세르지오 돈돌리가 2006·2010·2015년 세계 젤라토 챔피언십을 제패한 전설적인 젤라테리아. 산 지미냐노 방문객이라면 줄 서서라도 먹어야 하는 필수 코스. 대표 맛: 자프란 크로칸테(Crema di Santa Fina), 리볼라 영업시간    매일 12:00~15:00, 19:00~22:00   휴무', '09:00~22:00', '무료', 'Piazza della Cisterna 4, 53037 San', '토요일 성수기 대기 10~20분 각오. 2스쿱(콘/컵) 추천. 현금만 가능할 수 있음.', 37),
  (67, '몬탈치노 로카 에노테카', '비용', '1361년 시에나 공화국이 건립한 요새 내부에 자리한 공식 에노테카. 브루넬로 디 몬탈치노 DOCG, 로소 디 몬탈치노 DOC를 포함해 수십 종의 몬탈치노 와인을 글라스 단위로 시음 가능. 요새 테라스에서 발도르차 파노라마를 감상하며 마시는 와인이 압권.', '매일 09:00~20:00', '무료', 'Piazzale Fortezza, 53024 Montalcino', '일요일도 정상 운영. 시음 세트(3잔) 약 15. 마음에 드는 와인은 현장 구입 가능. 브루넬로 정규 와인(40~100/병)과 로소(15~25/병) 가격 차이 큼.', 38),
  (67, '산탄티모 수도원', '비용', '15:00~18:30 / 일 15:15~18:30 Castelnuovo dell''Abate SI 카를로 대제가 812년 창건했다는 전설을 품은 토스카나 최고의 로마네스크 수도원. 빛에 따라 색이 변하는', '월~토 10:00~13:00,', '무료', 'Loc. Sant''Antimo, 53024', '일요일 15:15 이후 입장 (오전 미사 후 개방). 수도원 성가 시간표 확인 후 방문 조율 — 그레고리오 성가 생음악 체험 권장. 주변 비포장 주차장 무료.', 39),
  (67, '에르콜라노 고고학 공원', '비용', '09:00~17:00), 마감 90분 전 입장 서기 79년 베수비오 화산 폭발 당시 화쇄류(pyroclastic flow)에 순식간에 매몰되어 폼페이보다 훨씬 완벽하게 보존된 고대 로마 도시. 2층 건물의 목조 구조물, 색채 선명한 프레스코화, 탄화된 가구·음식 등이', '매일 09:00~19:30 (11월~3월', '무료', 'Corso Resina 187, 80056 Ercolano', '폼페이보다 관람객 적고 동선 짧음 — 오전 방문 시 30분 내 입장 가능. 목욕탕(Terme Suburbane) 내부 에로틱 모자이크 유일 보존. 매점·화장실 입구 부근 집중.', 40),
  (67, '폼페이 고고학 공원', '비용', '09:00~17:00), 마감 90분 전 입장 서기 79년 베수비오 화산 폭발로 화산재에 매몰된 인구 2만 명의 로마 도시. 포룸, 원형극장, 목욕탕, 창관(루파나레), 빌라 데이 미스테리의 디오니소스 의식 대형 프레스코 등 고대 일상이 그대로 남아있다.', '매일 09:00~19:30 (동절기', '무료', 'Via Villa dei Misteri 2, 80045 Pompei', '오디오 가이드 앱 ''Pompei Sites'' 무료 다운로드 권장. 마리나 문(입구)→ 포룸 → 아폴로 신전 → 목욕탕 → 루파나레 코스가 핵심 1.5시간 동선. 석조 보도블록 울퉁불퉁 — 편한 운동화 필수. 모자·물·선크림 필수 (그늘 거의 없음).', 41),
  (67, '포지타노', '비용', '아말피 해안 서쪽 끝의 절벽 마을. 분홍·노랑·주황색 파스텔 건물들이 가파른 절벽에 계단식으로 붙어 있는 이탈리아 해안 최고의 포토스팟. 스폰다 해변에서 수영·일광욕 가능. 레몬 향초·그릇·수공예품 쇼핑 거리로도 계단 많으니 내려갈 때만 도보, 올라올 때는 버스 이용.', '마을 상시 개방 / 해변 무료', '무료', '84017 Positano SA', '포지타노 마을 진입로 협소 — 위쪽 주차장(Via G. Marconi)에 주차 후 마을 버스 또는 도보 하강 권장. 60대는 계단 많으니 내려갈 때만 도보, 올라올 때는 버스 이용.', 42),
  (67, '아말피 성 안드레아 대성당', '비용', '9세기 창건, 아랍-노르만 양식의 독특한 이중 계단 외관이 인상적인 아말피의 상징. 예수의 12제자 중 첫 번째 제자 성 안드레아의 유해가 안치되어 있으며, 해상 공화국 시절 지중해를 호령하던 아말피의 영화를 상징한다. 경내 클로이스터(회랑)의 아랍풍 아치가 일품.', '매일 09:00~19:00 (11월~2월', '무료', 'Piazza del Duomo, 84011 Amalfi SA', '대성당 앞 광장(피아자 델 두오모)이 아말피의 중심. 계단 62개 — 60대 무릎 주의. 내부 예배 시간(11:00, 18:00)에는 관광 제한.', 43),
  (67, '라벨로 빌라 루폴로', '비용', '13세기 루폴로 가문의 별장 정원. 리하르트 바그너가 1880년 방문 후 ''파르지팔'' 클링조르의 정원에 영감을 받았다. 테라스에서 내려다보는 티레노 해 전망이 압도적. 매년 7~8월 라벨로 음악 페스티벌의 야외 라벨로 주차: Piazza Duomo 인근 공영 주차장 2~3/시간.', '매일 09:00~20:00 (계절별 상이)', '무료', 'Piazza del Duomo, 84010 Ravello SA', '빌라 침브로네(Villa Cimbrone)의 ''무한의 테라스(Terrazza dell''Infinito)''도 필수. 두 빌라 도보 15분 거리. 라벨로 주차: Piazza Duomo 인근 공영 주차장 2~3/시간.', 44),
  (67, '나폴리 국립 고고학 박물관', '비용', '세계에서 가장 중요한 그레코-로마 유물 박물관. 폼페이·에르콜라노·스타비아에서 발굴된 모자이크·조각·프레스코·일상 도구의 원본이 소장되어 있다. 하이라이트: 알렉산드로스 대왕의 이소스 전투 모자이크(폼페이 파우누스의 집 출토), 파르네세 헤라클레스(2.3m 대리석 조각), 비밀의 방(에로틱 고대', '수~월 09:00~19:30 (화요일 휴무),', '무료', 'Piazza Museo Nazionale 19, 80135', '목요일 정상 영업 확인. 비밀의 방(Gabinetto Segreto)은 18세 이상만 입장, 사전 입장 신청 필요할 수 있음. 박물관 내 카페테리아 있음. 1층 조각→2층 모자이크→3층 프레스코 순 관람 권장.', 45),
  (67, '스파카나폴리', '비용', '고대 그리스 시대부터 내려온 나폴리의 대동맥. 직선으로 뻗은 좁은 골목이 나폴리 구도심을 동서로 가르는 모습이 위성사진에서 뚜렷하다. 제수 누오보(Gesu Nuovo) 성당의 다이아몬드 파사드, 산타 키아라(Santa Chiara) 수도원의 마욜리카 타일 회랑, 산 그레고리오 아르메노(San Gregorio Armeno)의 수공예', '상시 개방', '무료', 'Via Benedetto Croce / Via San Biagio', '나폴리 구도심 소매치기 주의 — 백팩은 앞으로 메고, 지갑·휴대폰 안쪽 주머니 보관. 산 그레고리오 아르메노 골목은 성수기에도 공방 영업 중. 스팡야롤로(나폴리 크림 도넛) 1.50 — 현지인 간식.', 46),
  (67, '카스텔 누오보', '비용', '1279년 샤를 1세 앙주 왕이 나폴리 항구 옆에 세운 중세 성곽. 5개의 원형 탑과 화려한 개선문(Arco Trionfale)이 인상적. 항구 전경과 베수비오 화산을 배경으로 촬영하는 포토스팟으로 인기. 내부는 나폴리 걸으면 나폴리 해안 산책로(Lungomare).', '월~토 09:00~18:00, 일요일 휴무', '무료', 'Piazza del Municipio, 80133 Napoli NA', '내부보다 외관 자체가 하이라이트. 성 앞 Piazza del Municipio에서 전체 성벽 사진 촬영. 항구 방향으로 5분 걸으면 나폴리 해안 산책로(Lungomare).', 47),
  (67, '카프리 섬', '비용', '티레노 해의 보석. 로마 황제 아우구스투스와 티베리우스가 별장을 둔 섬. 파라글리오니(3개의 바위 기둥), 푸른 동굴(Grotta Azzurra), 빌라 조비스(황제 별장 유적), 아나카프리의 몬테 솔라로 전망대가 대표 명소. 세계 최고급 리조트와 명품 부티크가 가득하지만 자연 경관이 압도적.', '섬 상시 개방 / 페리 06:00~22:00', '무료', '80073 Capri NA', '푸른 동굴(Grotta Azzurra)은 수위 높은 날 입장 불가 — 조건부 방문. 성수기 페리 혼잡 — 왕복 티켓 미리 예매. 섬 내 버스/택시 이용 (렌터카 반입 금지). 카프리 타운 명품 쇼핑 거리 Via Camerelle.', 48),
  (67, '몬테 솔라로 체어리프트', '비용', '아나카프리에서 카프리 최고봉 몬테 솔라로(589m)까지 11분간 오픈형 1인승 체어리프트. 정상에서 카프리 섬 전체, 나폴리 만, 아말피 해안, 맑은 날에는 시칠리아까지 보이는 360도 파노라마. 60대 부부가 도보 없이 즐길 수 있는 카프리 최고 뷰포인트.', '매일 09:30~17:00 (계절별 상이)', '무료', 'Piazza Vittoria, 80071 Anacapri NA', '체어리프트 1인 탑승 (2인 나란히 불가) — 고소공포증 있으면 주의. 정상 기온 카프리 타운보다 5~7도 낮음 — 가벼운 겉옷 지참. 내려오는 길 체어리프트 대신 도보 하산 가능 (35분, 비추 — 60대).', 49),
  (67, '파라글리오니 전망대', '비용', '카프리 마을에서 비아 트라가라(Via Tragara)를 따라 도보 20분 거리의 전망 포인트. 카프리의 상징인 파라글리오니 3개의 거대 바위 기둥과 에메랄드 지중해를 한눈에 담을 수 있다. 일몰 시간대에 더욱 환상적이나 당일치기 일정 상 오전 방문.', '상시 개방', '무료', 'Via Tragara, 80073 Capri NA', '비아 트라가라는 포장도로로 60대 도보 가능 (평탄한 편). 전망대 옆 카페 리도 델 파로 (Lido del Faro) 테라스에서 커피 한 잔 + 조망 추천.', 50),
  (67, '산타 마리아 델 이솔라 성당', '비용', '트로페아의 상징. 바다 쪽으로 돌출된 돌섬 위 절벽에 세워진 하얀 성당. 원래 섬이었지만 퇴적물로 육지와 연결됨. 7세기 창건, 현재 건물은 17세기 재건. 성당 앞 테라스에서 에메랄드 해변과 절벽이 어우러지는 풍경은 이탈리아 해안 사진 중 가장 많이 찍히는 장면 중 하나.', '매일 07:30~12:30 / 15:30~20:00', '무료', 'Via Portosalvo, 89861 Tropea VV', '성당 내부 예배 시간(일요일 10:00, 18:00) 관광 제한. 계단 약 50개 — 편한 신발. 성당 입구 옆 테라스 카페에서 커피 + 조망.', 51),
  (67, '카포 바티칼로 전망대', '비용', '트로페아에서 남서쪽으로 15km 지점의 칼라브리아 최서단 곶(串). 맑은 날에는 스트롬볼리·불카노·리파리 등 에올리에 화산섬들을 육안으로 볼 수 있다. 지중해 최고 투명도의 바다와 적벽 절벽이 조화를 이루는 곳. 영업시간     매일 12:30~15:00 / 19:30~22:30            휴무', '상시 개방', '무료', '89865 Ricadi VV', 'Faro di Capo Vaticano(등대) 주변 전망 포인트. 주차장 있음(무료). 차로 직접 진입 가능.', 52),
  (67, '니코테라 + 니코테라 마리나 해변', '비용', '트로페아 남쪽 25km의 조용한 칼라브리아 해안 마을. 언덕 위 중세 성곽 마을(Nicotera Alta)과 아래 해안 마을(Nicotera Marina)로 구성. 마리나 해변은 트로페아보다 덜 알려져 인파 없이 조용하게 즐길 수 있는 최고의 대안 해변. 모래 질감과 물 투명도 모두 최상급.', '상시 개방', '무료', '89844 Nicotera VV', '니코테라 마리나 → 니코테라 Alta 언덕 마을까지 차로 10분. 언덕 위에서 카라브리아 해안 파노라마. 성수기 7~8월이 아니면 해변 한산.', 53),
  (67, '카펠라 팔라티나', '비용', '09:00~13:00 (예배 후 관광) 루제로 2세가 1132~1143년에 건립한 궁전 예배당. 이슬람 목조 천장 + 비잔틴 황금 모자이크 + 노르만 건축이 혼합된 세계 유일의 건축 걸작. 6,000㎡의 황금 모자이크가 그리스도의 일생부터 노르만 왕실을', '월~토 09:00~17:00 / 일', '무료', 'Piazza del Parlamento 1, 90129', '수요일 정상 영업. 예약 없이도 입장 가능하나 성수기 대기 30분+. 사진 촬영 허용(플래시 금지). 입장 전 복장 규정: 어깨·무릎 노출 금지.', 54),
  (67, '팔레르모 대성당', '비용', '08:00~13:00, 16:00~19:00 9세기 아랍 모스크를 개조한 후 12~18세기에 걸쳐 증개축된 팔레르모의 성당. 외관은 아랍-노르만 양식의 굴곡미, 내부는 18세기 신고전주의로 개조. 루제로 2세·콘스탄체·프리드리히 2세 황제의 반암 석관이 왕릉', '월~토 07:00~19:00 / 일', '무료', 'Corso Vittorio Emanuele, 90134', '왕릉(Tesoro e Cripta) 별도 입장권 3. 지붕 테라스 계단 약 130개 — 60대 엘리베이터 없음 주의. 성당 광장 측면에서 아랍 문양 외벽 상세 촬영 가능.', 55),
  (67, '콰트로 칸티 + 라 마르토라나', '비용', '콰트로 칸티는 팔레르모 구시가 두 대로의 교차점에 세워진 바로크 건축 4면체(1608~1620). 팔레르모 4구역을 상징하는 조각이 3단으로 쌓인 독특한 도시 설계. 바로 옆 라 마르토라나(1143년)의 황금 비잔틴 모자이크는 카펠라 팔라티나에 필적하는 아름다움.', '라 마르토라나: 월~토 08:30~13:00', '무료', 'Piazza Vigliena, 90133 Palermo PA', '라 마르토라나 ''마르타판'' — 마르타판(marzapane)이 이 교회에서 비롯됐다는 설. 교회 앞 가게에서 시칠리아 마르지판 과자 구입 가능.', 56),
  (67, '몬레알레 대성당', '비용', '14:30~17:00 / 일 14:30~17:00 노르만 왕 굴리엘모 2세가 1172~1189년에 건립. 내부 전체를 덮는 6,000㎡ 황금 모자이크가 구약·신약 성경을 장면별로 묘사. 앱스의 거대한 그리스도 판토크라토르는 체팔루와 함께 비잔틴 모자이크 예술의 양대', '월~토 08:30~12:30 /', '무료', 'Piazza Guglielmo II 1, 90046', '목요일 정상 영업 확인. 오전 10시 이전 방문 시 단체 관광객 없어 조용히 감상 가능. 클로이스터(Chiostro)는 성당과 별도 입장권. 옥상 테라스 엘리베이터 없음 — 계단 200개 (60대 선택적으로). 버스 389번: 팔레르모 Piazza dell''Indipendenza 출발 30~40분 간격.', 57),
  (67, '부쿠치아 시장', '비용', '팔레르모 가장 오래된 시장. 14세기부터 운영. 르나토 구투조의 유명 회화 ''부쿠치아''(1974)의 배경. 오전에는 생선·해산물·향신료·채소 시장, 오후부터 청년들의 야외 바 문화 발생. 시칠리아 길거리 음식 영업시간      화~일 12:30~15:00 /                     휴무', '매일 07:00~14:00 (야간 바 문화는', '무료', 'Piazza Caracciolo, 90133 Palermo PA', '소매치기 주의 — 시장 내부 귀중품 관리. 즉석 해산물 튀김(Fritto di Mare) 4~6 도전. 수박(Anguria) 조각 2 — 시칠리아 여름 대표 간식.', 58),
  (67, '카푸친 수도원 카타콤베', '비용', '팔레르모 카푸친 프란치스코 수도회가 1599년부터 1880년대까지 운영한 지하 납골당. 8,000여 구의 방부 처리·미라화된 시신이 성직자·귀족·의사·군인·어린이 구역별로 복도 벽면에 세워져 있다. 특히 1920년 사망한 2세 여아 로살리아 롬바르도(Rosalia Lombardo)의 미라는 ''세계에서 가장 아름다운 미라''로 불리며', '매일 09:00~13:00 / 15:00~18:00', '무료', 'Piazza Cappuccini 1, 90129 Palermo', '충격적인 분위기지만 역사·인류학적 가치가 높은 필수 방문지. 사진 촬영 가능. 실내 기온 낮으니 가벼운 겉옷 권장. 어두운 분위기 — 심장이 약한 분 주의.', 59),
  (67, '테아트로 마시모', '비용', '1875~1897년 건립, 유럽에서 파리 오페라·빈 오페라 다음으로 세 번째로 큰 오페라 하우스. 신고전주의 외관과 붉은 금장식 내부가 장엄. 영화 ''대부 III''의 클라이맥스 장면 촬영지. 1,350석 대극장. 5~6월 시즌 티켓 구입 가능 — 비용 30~80. 외관은 무료로 광장에서 감상.', '가이드 투어: 화~일 09:30~17:30', '무료', 'Piazza Verdi, 90138 Palermo PA', '가이드 투어(한국어 없음 — 영어)로 내부 무대·분장실·VIP룸 견학. 공연 시즌(10~5월) 중이면 야간 오페라 티켓 구입 가능 — 비용 30~80. 외관은 무료로 광장에서 감상.', 60),
  (67, '몬델로 해변', '비용', '팔레르모 북서쪽 15km에 위치한 팔레르모 시민의 해수욕장. 백사장 길이 2km, 에메랄드빛 투명한 바닷물. 100년 넘은 바 카페 (Lo Stabilimento Mondelloo)와 아르누보 건물들이 해변 뒤에 늘어서 있다. 성수기(7~8월)는 극도로 혼잡하지만 5월 말은 아직 조용.', '상시 개방 (성수기 바 서비스', '무료', '90151 Mondello, Palermo PA', '오전 9~11시 이전 도착 시 자리 넉넉. 토요일이라 팔레르모 시민 많음 — 오전 일찍 도착 강력 권장. 해변 식사 — 즉석 아란치나 2, 그라니타(슬러시) 3.', 61),
  (67, '에리체', '비용', '해발 750m 바위 산 정상의 중세 마을. 페니키아·그리스·로마·아랍·노르만인이 차례로 거쳐 간 시칠리아 최고 역사 도시 중 하나. 안개가 자주 끼는 신비로운 분위기. 마리아 그람마티코(Maria Grammatico) 제과점의 전통 시칠리아 마르치판·쿠루쿠탕구·크로스타타가 유명.', '마을 상시 개방 / 케이블카', '무료', '91016 Erice TP', '케이블카는 바람이 강한 날 운행 중단 가능 — 출발 전 funivia-erice.it 확인. 마을 내 미리암 제과점(Pasticceria Maria Grammatico): Via Vittorio Emanuele 14. 시칠리아 전통 과자 선물 쇼핑 최적지.', 62),
  (67, '신전의 계곡', '비용', '기원전 6~5세기 그리스 식민 도시 아크라가스의 신전 군. 콘코르디아 신전은 세계에서 가장 잘 보존된 그리스 신전 중 하나로, 34개 원기둥이 거의 원형에 가깝게 서 있다. 붉은 황토색 사암 신전이 지중해를 내려다보는 능선에 줄지어 늘어선 광경이 압도적. UNESCO 세계문화유산.', '매일 08:30~20:00 (마지막 입장', '무료', 'Via Sacra, 92100 Agrigento AG', '일요일 오전 단체 관광 없이 비교적 한산 (현지 가족 단위 많음). 콘코르디아 신전 → 헤라 신전 → 헤라클레스 신전 → 올림피코 신전 순서 추천. 7~8월은 오전 7시 개방이지만 5월 말은 8:30 개방. 해 뜨는 방향이 아름다움 — 오전 방문 이유.', 63),
  (67, '갈레리아 레지오날레 — 팔라초 아바텔리스', '비용', '팔라초 아바텔리스(15세기 카탈루냐-고딕 궁전)에 위치한 시칠리아 지역 미술관. 주요 작품: 안토넬로 다 메시나의 ''수태고지''(1474, 시칠리아 르네상스 최고 걸작), 작자 미상의 ''죽음의 승리''(15세기 거대 프레스코, 흑사병 시대의 죽음의 기사가 사람들을 베는 장면), 부스토 디 에레오나(엘레오노라 다 아라고나', '화~토 09:00~18:30 / 일', '무료', 'Via Alloro 4, 90133 Palermo PA', '월요일 휴무 — 화요일 방문이었다면 놓쳤을 것. 에어컨 잘 작동하는 실내 — 더운 오후 완벽한 피난처. ''죽음의 승리'' 프레스코는 1층 대형 홀에 별도 전시, 충격적이고 강렬.', 64),
  (67, '카포 시장', '비용', '팔레르모 북쪽 Via Beati Paoli 일대의 재래시장. 발라로보다 더 현지인 비율 높은 시장. 식재료뿐 아니라 의류·잡화·기념품 판매. 시칠리아 향신료, 케이퍼(카페레), 오레가노, 특선 소시지(사르시치아) 구입 최적. 추천. 아몬드 피스타치오 페스토는 귀국 후 파스타에 활용 가능.', '월~토 07:00~13:30', '무료', 'Via Beati Paoli, 90134 Palermo PA', '월요일 정상 영업 확인. 기념품으로 시칠리아 케이퍼(염장/식초) 진공팩 3~5, 피스타치오 페스토 6~8 추천. 아몬드 피스타치오 페스토는 귀국 후 파스타에 활용 가능.', 65),
  (67, '오르티자 섬 두오모 광장 + 대성당', '비용', '기원전 480년 히에론 1세가 카르타고 격파 기념으로 세운 아테나 신전(도리아식 38개 원기둥) 위에 7세기 비잔틴 교회, 이후 아랍 모스크, 노르만 성당을 거쳐 18세기 안드레아 팔마의 바로크 파사드로 완성된 시라쿠사의 상징. 성당 벽면 속에 2,500년 된 그리스 원기둥이 살아있는 것을 내부에서 직접 확인할 수', '성당 08:00~19:00 / 광장 상시 개방', '무료', 'Piazza del Duomo 1, 96100 Siracusa', '오전 9~10시 햇살이 파사드 황금색으로 물드는 시간이 최고 사진 타이밍. 광장 카페 테라스(Bar del Duomo)에서 커피 한 잔 + 성당 조망 추천. 내부 촬영 무료.', 66),
  (67, '아폴로 신전', '비용', '기원전 565년경 건립, 그리스 도리아식 신전으로 시칠리아에서 가장 오래된 그리스 신전. 오르티자 섬 육지 연결 다리 바로 앞 광장에 일부 원기둥과 기단이 보존. 아테나 신전(대성당)과 더불어 시라쿠사 고대 영업시간    화~일 19:00~23:00, 월요일 휴무               휴무', '상시 개방 (유적 외부에서 관람)', '무료', 'Piazza Pancali, 96100 Siracusa SR', '오르티자 섬 진입하자마자 보임. 야간 조명 받는 모습도 아름다움. 주변 카페들이 신전 뷰 테라스 운영.', 67),
  (67, '그리스 극장 — 고고학 공원 네아폴리스', '비용', '기원전 5세기 히에론 1세 시절 건립. 시칠리아에서 가장 크고 가장 잘 보존된 그리스 극장. 67줄 관객석이 천연 암반을 깎아 만들어졌으며, 1만 5천 명 수용. 아이스킬로스, 소포클레스, 에우리피데스의 비극이 초연된 역사적 무대. 현재도 5~6월 ''시라쿠사 고대 연극 축제''(INDA) 기간 공연 개최. 배경의 이오니아 해', '매일 09:00~18:30 (마지막 입장', '무료', 'Via del Teatro Greco, 96100 Siracusa', '6월 초 INDA 고대 연극 축제 공연 기간 — 야간 공연 관람 가능하면 특별 경험. 공연 티켓 fondazioneindasr.com에서 사전 예매. 오전 방문이 그늘 적으므로 모자·선크림 필수.', 68),
  (67, '시라쿠사 파올로 오르시 고고학 박물관', '비용', '시칠리아 최대 고고학 박물관. 선사~로마 시대 시라쿠사 및 시칠리아 동부 발굴품 11만 점 소장. 주요 작품: 베누스 란돌리나(Venere Landolina — 1세기 로마 아프로디테 조각, 상반신 없음에도 완전한 아름다움), 메가라 흙 인형 컬렉션, 청동 기마상. 냉방 잘 되어 있어 더운 오후 최적.', '화~토 09:00~18:00 / 일', '무료', 'Viale Teocrito 66, 96100 Siracusa SR', '목요일 정상 영업. 베누스 란돌리나는 2관 중앙. 그리스 극장 관람 후 박물관 방향이 자연스러운 동선(차량 10분).', 69),
  (67, '노토— 바로크 도시', '비용', '08:00~12:30 / 15:00~19:30 1693년 1월 대지진으로 완전 파괴된 뒤 완전히 새로 설계·건축된 바로크 계획 도시. 시칠리아 특산 황금빛 칼카레니테(석회암)으로 건축된 건물들이 직선 코르소 대로 양쪽에 완벽한 바로크 양식으로 늘어서 있다. 발', '마을 상시 개방 / 대성당', '무료', '96017 Noto SR', '카페 시칠리아(Caffe Sicilia)는 노토 방문 절대 필수. 코르소 대로에서 노토 대성당 계단까지 직선 시야 — 계단 위에서 대로 사진 촬영 최적. 여름 관광 시즌 노토 초만원 — 오전 9시 이전 도착 추천.', 70),
  (67, '모디카+ 초콜릿 문화', '비용', '아랍·스페인 식민지 시절 아즈텍 방식으로 전래된 냉 가공 초콜릿(Cioccolato di Modica IGP)의 고향. 설탕을 가열하지 않아 초콜릿 안에 설탕 결정이 그대로 살아있는 독특한 식감. 비탈진 두 계곡에 걸쳐 있는 도시 구조가 독특하며, 산 조르조 대성당의 황금빛 파사드가 도시를 압도.', '마을 상시 개방 / 돌체리아', '무료', '97015 Modica RG', '안티카 돌체리아 보나주토(Via Grimaldi 84): 1880년 창업, 모디카 초콜릿 원조. 시나몬·칠리·바닐라·캐럽 맛 초콜릿 시음. 모디카 초콜릿 포장 선물 최적 (귀국 수하물 가능). 산 조르조 대성당 242계단 — 60대 하부에서 조망 권장.', 71),
  (67, '폰타네 비안케 해변', '비용', '시라쿠사 남쪽 20km, SS115 해안도로 접근. 시라쿠사 지역에서 가장 아름다운 해변 중 하나. 하얀 모래(Fontane Bianche=하얀 샘의 뜻)와 얕고 맑은 이오니아 해가 특징. 수심이 얕아 노인·가족에게 최적. 여름 성수기도 폼페이·아말피보다 한산.', '상시 개방 (바 서비스 09:00~20:00)', '무료', '96010 Fontane Bianche SR', '시라쿠사 도심에서 차로 25분. SS115 해안도로 드라이브도 아름다움. 해변 선베드 오전 10시 이전 확보 권장. 주차장 무료.', 72),
  (67, '카스텔로 마니아체', '비용', '13세기 프리드리히 2세 황제가 오르티자 섬 최남단 바다 위 돌출 지점에 건립한 노르만-슈바벤 성곽. 3면이 이오니아 해로 둘러싸여 있어 바다 한가운데 있는 듯한 느낌. 성 위에서 시라쿠사 항구 + 오르티자 전경 +', '월~토 08:30~18:30 / 일요일 특정', '무료', 'Via del Castello Maniace 1, 96100', '일요일 개방 여부 사전 확인 필수(불규칙 운영). 성 앞 바다 방파제에서 낚시꾼들과 함께 이오니아 해 조망. 이른 아침 방문 시 조용하고 바람 서늘.', 73),
  (67, '파피루스 박물관', '비용', '아이집트 이외 세계 유일의 파피루스 자생지인 시라쿠사의 파피루스 문화를 전시. 고대 이집트부터 현재까지 파피루스 제작 과정, 문자 기록 역사, 아레투사 샘의 파피루스 자생 생태 설명. 공예품 판매 코너에서 직접 영업시간    화~일 19:00~23:00, 월요일 휴무             휴무', '월~토 09:00~14:00, 일요일 휴무', '무료', 'Via Nizza 14, 96100 Siracusa SR', '일요일 휴무 — 토요일 또는 월~금 방문 권장. 관람 시간 약 45분. 기념품으로 파피루스 카드 3~5 추천.', 74),
  (67, '에트나 화산— 케이블카+4WD 투어', '비용', '해발 3,357m, 유럽 최대 활화산. 남쪽 사면 리푸지오 사피엔자(1,923m)까지 차량 접근, 케이블카로 2,500m, 4WD+가이드로 2,900~3,000m 분화구 인근까지 접근. 화산재·용암 지형·연기 분출 현장. 시칠리아 여행 최고 스릴 체험. 60대 부부: 케이블카+4WD 투어로 도보 없이 접근 가능.', '케이블카: 09:00~16:00 (기상', '무료', 'Rifugio Sapienza, Via Etna, 95030', '에트나 기상 변화 극심 — 출발 당일 운행 여부 확인 필수(www.funiviaetna.com). 정상 기온 10~15도 이하 — 두꺼운 겉옷·장갑 필수. 화산 가스(이산화황) 민감한 분 마스크 지참. 4WD 투어 사전 예약 권장.', 75),
  (67, '타오르미나 그리스 극장', '비용', '기원전 3세기 그리스인이 건립하고 2세기 로마인이 확장한 원형 극장. 무대 뒤로 에트나 화산과 이오니아 해가 동시에 보이는 세계에서 가장 아름다운 극장 배경. 현재도 Taormina Arte 페스티벌(6~9월) 등 공연 개최. 지름 109m, 수용 5,000명.', '매일 09:00~일몰 1시간 전', '무료', 'Via del Teatro Greco 1, 98039', '오전 10시 이전 방문 시 관람객 적음. 오후 3~5시 햇살이 석회암 기둥을 황금빛으로 물들이는 시간 — 사진 최적. 무대 중앙에서 에트나 화산이 무대 배경으로 들어오는 앵글이 포토존.', 76),
  (67, '이솔라 벨라', '비용', '타오르미나 절벽 바로 아래 작은 자연보호구역 섬. 육지와 얕은 모래톱(tombolo)으로 연결되어 있어 썰물 때는 걸어서 건널 수 있다. 주변 해수 투명도가 지중해에서도 최상급. 이오니아 해의 보석 같은 스팟. 케이블카 하부(마짜로 해변)에서 도보 10분.', '해변 상시 개방 / 섬 내 자연보호구역', '무료', 'Via Isola Bella, 98039 Taormina ME', '오전 9~11시가 가장 조용. 성수기 7~8월은 자리 전쟁이지만 6월 초는 한산. 해변에서 에메랄드 물색과 타오르미나 절벽이 함께 찍히는 앵글이 절경.', 77),
  (67, '카스텔몰라', '비용', '타오르미나 위 5km, 해발 529m 절벽 꼭대기의 중세 요새 마을. 인구 1,000명의 조용한 마을이지만 조망은 시칠리아 최고. 아랍 시대 성곽에서 타오르미나 전체 + 이오니아 해 + 에트나 화산을 한 눈에. 아몬드 와인의 에로틱한 내부 장식은 시칠리아 역사적 민속문화의 일부 — 특이 경험.', '마을 상시 개방 / Bar Turisi', '무료', '98030 Castelmola ME', '카스텔몰라 진입 산길: 급커브+협소 — 속도 20km/h 이하. 마을 주차장(무료) 이용 후 도보. Bar Turisi의 에로틱한 내부 장식은 시칠리아 역사적 민속문화의 일부 — 특이 경험.', 78),
  (67, '낙소스 그리스 유적지', '비용', '기원전 734년 칼키스인이 건설한 시칠리아 최초의 그리스 식민도시 유적. 현재는 도시 성벽 일부와 수많은 고대 도자기·동전이 출토된 지점이 보존되어 있다. 인근 박물관(Museo Archeologico di Naxos)에 발굴품 전시. 잔르디니 낙소스 해변과 바로 인접.', '매일 09:00~18:00', '무료', 'Via Stazione, 98035 Giardini Naxos', '해변 산책 후 자연스럽게 연결. 입구 박물관 내 에어컨 — 더운 오후 휴식 겸 관람 가능. 목요일 정상 영업 확인.', 79),
  (67, '타오르미나 공중 정원', '비용', '19세기 영국 여성 플로렌스 트레벨얀이 조성한 열대 정원. 타오르미나 구시가 동쪽 절벽 가장자리에 위치. 선인장·야자수·알로에 등 지중해 식물과 조각들이 정원을 채운다. 정원 테라스에서 이오니아 해와 에트나 영업시간    화~일 12:30~15:00 /                    휴무', '매일 08:00~20:00', '무료', 'Via Bagnoli Croci, 98039 Taormina', '코르소 움베르토에서 도보 5분. 에트나 배경 사진 최적 포인트. 벤치에서 휴식하며 경관 감상 — 60대 부부 완벽 휴식지.', 80),
  (67, '사보카— 대부 촬영지', '비용', '타오르미나 북쪽 20km 메시나 산악 지대의 중세 마을. 프란시스 포드 코폴라 감독의 영화 ''대부''(1972) 시칠리아 장면(마이클과 아폴로니아의 결혼식, 마이클이 피난 와서 아폴로니아를 만나는 바 장면)이 촬영된 곳. 영화 속 그대로 보존된 바 비텔리와 산 니콜로 교회, 중세 성채 폐허가 남아있다.', '마을 상시 개방 / Bar Vitelli', '무료', '98038 Savoca ME', '사보카 진입 산길: 좁고 구불구불 — 천천히. Bar Vitelli 내부: 영화 포스터·사진·코를레오네 가족 기념품 가득. 커피 한 잔 시키면 내부 사진 자유. 이른 오전 방문 시 단체 관광객 없이 조용히 감상 가능.', 81),
  (67, '알베로벨로 트룰리', '비용', '유네스코 세계유산. 석회암 판석(치안코)으로 접착제 없이 쌓은 원뿔형 돌 지붕 집. 풀리아 무르게 고원 특유의 건축 양식. 현재 1,500여 채가 리오네 몬티·아야 피콜라 두 구역에 남아있으며, 일부는 여전히 주거지로 사용. 지붕 꼭대기 석회 도형(점성술·종교 상징)이 각 집마다 다름.', '상시 개방 (리오네 몬티 지구)', '무료', '70011 Alberobello BA', '일요일 오전 9~11시가 가장 조용. 오후 단체 관광 버스 밀림. 아야 피콜라(Aia Piccola) 구역이 리오네 몬티보다 덜 상업화되어 로컬 분위기. 트룰리 숙박 체험도 가능 (이번 여행 숙소는 인근 아쿠아비바).', 82),
  (67, '마르티나 프란카', '비용', '17~18세기 풀리아 바로크 건축의 정수. 하얀 석회 칠한 집들이 미로처럼 얽힌 구시가(Citt Vecchia). 피아자 플레비시토의 두칼레 궁전(Palazzo Ducale)은 바로크 파사드의 걸작. 7~8월 바로크 음악 페스티벌(Festival della Valle d''Itria)로 세계적으로 유명.', '마을 상시 개방', '무료', '74015 Martina Franca TA', '알베로벨로에서 차로 20분. 무료 주차 가능(구시가 외곽). 하얀 골목 탐방 + 풀리아 부레이타 치즈 구입 최적. 바로크 음악 페스티벌 7월 이후 — 이번 방문은 6월로 관광객 적음.', 83),
  (67, '산타 크로체 성당', '비용', '1549년 착공, 1695년 완공. 레체 바로크의 최고 걸작이자 이탈리아 바로크 성당 중 가장 화려한 파사드를 가진 건물. 레체 특산 황금빛 석회암(피에트라 레체제)을 수십 명의 조각가가 200년에 걸쳐 조각. 로즈 창문 주변과 두 층 파사드 전체가 꽃·천사·그리핀·인물 조각으로 빼곡. ''바로크의 과잉''이라 불린다.', '매일 09:00~13:00 / 16:00~20:00', '무료', 'Via Umberto I 1, 73100 Lecce LE', '오전 햇살이 황금빛 석회암 파사드를 가장 아름답게 비추는 시간(10~11시). 성당 바로 뒤 주지사 궁(Palazzo del Governo)의 파사드도 같은 바로크 양식. 레체 구시가 전체가 조각 박물관 수준.', 84),
  (67, '오트란토 성채 + 두오모', '비용', '07:00~12:00, 15:00~19:00 오트란토 성채는 1480년 오스만 투르크 침략으로 800명 주민이 순교한 역사적 현장(성벽 내 순교자 유골 전시). 두오모 내 11~12세기 모자이크 바닥(Mosaico di Pantaleone)은 800㎡ 면적에 인류', '성채 09:00~18:30 / 두오모', '무료', 'Piazza del Castello, 73028 Otranto LE', '오트란토 모자이크 바닥: 당대 최고 장인 판탈레오네가 제작. 중세 세계관 전체를 담은 압도적 규모. 아침 햇살이 들어올 때 색채 최고.', 85),
  (67, '카스텔 델 몬테', '비용', '1240년 신성로마제국 황제 프리드리히 2세가 건립. 8각형 성채 본체 + 8개의 8각형 탑. 완벽한 수학적 대칭과 춘분·추분 햇빛이 특정 방으로 들어오는 천문학적 설계. ''왜 지었는가''가 아직도 논쟁 중(사냥 별장설, 천문 관측소설, 순례 상징물설). 이탈리아 1유로센트 동전 도안 모델. UNESCO 세계유산.', '매일 10:15~19:45 (3~10월) /', '무료', '76123 Andria BT (Castel del Monte)', '화요일 정상 영업 확인. 내부는 비어있어 건축 자체가 전시물. 외부에서 8각형 전체 들어오는 사진: 성채 남동쪽 50m 지점. 주차장 완비(무료). 여름 성수기 사전 예약 권장.', 86),
  (67, '알타무라 빵', '비용', '이탈리아 최초로 DOP(원산지 인증)를 받은 빵. 알타무라 지역 재배 듀럼 밀(세몰라 리마치나타)만 사용. 황금빛 껍질, 부드러운 속결, 특유의 고소한 향. 냉동 보관 시 수일 가능. 기념품으로 소형 포장 구입 추천. 현지 최고 빵집: Panificio Piccoli Forno — Via Matera', '빵집: 06:00~13:00 /', '무료', '70022 Altamura BA (구시가 빵집', '알타무라 구시가 입구 Via Matera 방향에 전통 빵집 집중. 갓 구운 것 바로 먹는 것이 최고. 풀리아 올리브오일+방울토마토와 함께 현지식 식사.', 87),
  (67, '그라비나 인 풀리아', '비용', '석회암 협곡(그라바, Grava) 위에 자리잡은 중세 마을. 협곡 건너편에서 바라보는 마을 전경이 압도적. 2008년 영화 007 ''퀀텀 오브 솔러스''에서 중간 보스 사무실 장면이 촬영된 곳. 16세기 아케두또(수로교)가 협곡을 가로질러 현재도 원형 보존. 남부 이탈리아 비밀의 숨겨진 보석.', '마을 상시 개방', '무료', '70024 Gravina in Puglia BA', '협곡 조망 최적 포인트: Via Appia 방향 전망대. 수로교(폰테 아케두또) 사진: 협곡 반대편 Via Vito Melodia에서 전체 구도 가능. 마을 진입 후 구시가 주차장 이용.', 88),
  (67, '그라비나 수로교', '비용', '1754년 완공된 바로크 시대 수로교. 협곡 깊이 30m를 가로지르는 5개의 아치. 그라비나 구시가와 맞은편 절벽 동굴 주거지(사시)를 연결. 이탈리아 남부 공학의 걸작이자 포토 포인트. 영업시간     화~일 12:30~15:00 /                       휴무', '상시 개방 (외부 관람)', '무료', 'Via Appia, 70024 Gravina in Puglia BA', '수로교 정면 사진: 협곡 아래 Via Matteotti에서 올려다보는 구도. 아침 10~11시 햇빛 방향 최적.', 89),
  (67, '산 비탈레 성당', '비용', '526~547년 건립. 이탈리아에서 가장 중요한 비잔틴 건축물. 팔각형 평면 구조로 서로마의 바실리카와 동로마의 집중식 성당을 결합. 내부 금빛 모자이크가 전체를 뒤덮음. 특히 유스티니아누스 황제와 테오도라 황후 모자이크 패널은 세계 비잔틴 미술의 최고봉. 단테의 신곡에서 천국 묘사의 영감이 된 공간.', '매일 09:00~19:00 (3~10월) /', '무료', 'Via San Vitale 17, 48121 Ravenna', '오전 9시 30분 전후 방문 시 관광객 적음. 갈라 플라키디아 영묘와 동일 부지 — 함께 방문. 천장 황금 모자이크 감상 위해 목 받침대(폰 목 방지) 또는 거울 이용.', 90),
  (67, '갈라 플라키디아 영묘', '비용', '425~430년 건립. 서로마 황후 갈라 플라키디아(테오도시우스 대제의 딸)의 영묘로 추정. 외부는 단순한 십자형 벽돌 건물이지만, 내부는 코발트 블루 바탕에 황금 별과 그리스도·성인 모자이크로 완전히 덮여 있음. 입장 인원 제한(15~20명) — 반드시 사전 예약 필요. 라벤나에서 가장 신비로운 공간.', '매일 09:00~19:00 (3~10월) /', '무료', 'Via Galla Placidia, 48121 Ravenna RA', '예약 필수: ravennafestival.org 또는 현장 예약 (전날 확인 권장). 입장 대기 5분. 내부 20분 체류. 코발트 블루 천장 별 모자이크: 맑은 날 외부 빛이 들어올 때 색채 최고.', 91),
  (67, '단테 알리기에리 무덤', '비용', '1321년 망명 중 라벤나에서 사망한 단테의 영묘. 피렌체 시가 수차례 유해 반환을 요구했지만 라벤나가 거부. 신고전주의 소형 건물 내부에 대리석 석관. 입구에 영원의 불꽃 점등. 단테 박물관(Museo 영업시간     화~일 12:00~14:30 /                휴무', '매일 10:00~19:00', '무료', 'Via Dante Alighieri 9, 48121 Ravenna', '무료 입장. 관람 5~10분. 신곡 관련 관심 있으면 옆 단테 박물관(Museo Dantesco) 추가 방문.', 92),
  (67, '산 아폴리나레 인 클라세', '비용', '547년 완공. 초기 비잔틴 바실리카의 완벽한 보존 형태. 클라세(고대 항구 도시) 수호 성인 아폴리나레를 위한 성당. 외부: 원통형 종탑(캄파닐레)이 라벤나 평원에 우뚝. 내부 앱스: 황금빛 배경에 성인 아폴리나레가 12마리 양(사도)을 이끄는 대형 모자이크. 초기 기독교 미술의 최고봉 중 하나.', '월~토 08:30~19:30 / 일', '무료', 'Via Romea Sud 224, 48124 Ravenna', '라벤나 시내에서 차로 10분. 주차 완비(무료). 관광객이 산 비탈레보다 훨씬 적음 — 여유롭게 감상 가능. 내부 모자이크 조도 좋은 오전 10~11시 방문 추천.', 93),
  (67, '네오니아노 세례당', '비용', '5세기 초 건립. 라벤나 팔각형 세례당. 돔 천장 모자이크: 세례 요한이 예수를 세례하는 장면을 중심으로 사도 행진이 원형으로 배치. 비잔틴 이전 서로마 시대 모자이크 양식의 정수. 도심 내 위치로 접근 편리. 영업시간     목~화 12:00~14:30 /                   휴무', '매일 09:00~19:00', '무료', 'Piazza Arcivescovado 1, 48121', '구시가 중심에 위치. 도보 접근 가능. 관람 15~20분. 아리우스파 세례당(Battistero degli Ariani)과 같은 날 방문 추천 (도보 10분 거리).', 94),
  (67, '테오도리쿠스 영묘', '비용', '526년경 건립. 동고트 왕국의 왕 테오도리쿠스 대왕의 영묘. 지름 14m의 이스트리아 석회암 단일 블록으로 제작한 10각형 돔 — 고대 로마 이후 최대 규모의 단일 석재 지붕. 모르타르 없이 정밀하게 맞춘 석재 기술이 경이로움. 비잔틴 모자이크가 없음에도 건축 자체가 주는 강렬한 인상. 유네스코 세계유산.', '화~일 08:30~19:30, 월요일 휴무', '무료', 'Via delle Industrie 14, 48122 Ravenna', '일요일 오전 개관. 라벤나 시내에서 도보 또는 리스카로 10분. 주차 편리. 내부 2층 전실에 테오도리쿠스의 반암 석관 원형 보존.', 95),
  (67, '코마키오 트레폰티', '비용', '1638년 건립된 5개 아치를 가진 바로크 다리. 코마키오 구도심을 3방향으로 연결. 이탈리아에서 가장 아름다운 다리 중 하나로 선정. 운하 위 반영과 함께 촬영하면 압도적 풍경. 코마키오는 아드리아 해 석호(라구나)에 형성된 운하 도시 — ''작은 베네치아''로 불림.', '상시 개방', '무료', 'Piazzale Buonafede, 44022', '트레폰티 최적 사진 포인트: Via Agatopisto 방향 운하변. 오전 또는 석양 시 반영 최고. 코마키오 뱀장어 마리네이드(아길라 마리나타)는 현지 특산 — 진공 포장 기념 구입 가능.', 96),
  (67, '팔로리아 곤돌라', '비용', '코르티나 구시가에서 도보 5분. 팔로리아 산(2,123m)으로 연결하는 최신 곤돌라. 8분 만에 해발 2,000m 이상으로 상승. 정상에서 크리스탈로(3,221m)·토파나 디 로체스(3,244m)·마르몰라다 등 돌로미티 주요 봉우리 파노라마. 60대에 최적 — 케이블카로 고산 전망 접근.', '08:30~17:00 (여름 성수기)', '무료', 'Via del Castello 48, 32043 Cortina', '성수기 줄 있음 — 09:00 이전 탑승 권장. 정상 테라스 20분 전망 후 하산. 겉옷 필수 (정상 15~17도). 카페테리아 운영.', 97),
  (67, '친쿠에 토리 리프트 + 야외 박물관', '비용', '팔자레고 파소(2,192m) 인근. 의자식 2인 리프트로 5개의 수직 돌로미티 암봉(친쿠에 토리)에 접근. 1차 세계대전 당시 오스트리아-이탈리아 격전지. 당시 참호·포진지·군사 장비가 야외 박물관으로 보존. 암봉 사이 평탄한 트레일로 산책 — 60대에 적합한 수준.', '09:00~17:00', '무료', 'Passo Falzarego, 32043 Cortina', '팔자레고 파소 주차장(무료)에서 리프트 탑승. 코르티나에서 차로 15분. 리프트 탑승 전 방수 겉옷 착용 권장. 리푸지오 스코이아톨리에서 점심 추천.', 98),
  (67, '라가주오이 케이블카 + 정상', '비용', '팔자레고 파소(2,105m)에서 라가주오이 정상(2,778m)까지 5분. 코르티나 주변 최고 전망 포인트. 360도 파노라마: 마르몰라다 빙하·크리스탈로·토파나·친쿠에 토리·팔레 디 산 마르티노. 정상 리푸지오에서 전망 커피 가능. 케이블카 탑승소 팔자레고 파소에 무료 대형 주차장 완비. 1차 세계대전 당시', '08:30~17:00 (여름)', '무료', 'Passo Falzarego, 32043 Cortina', '오전 9~11시 구름 없어 시야 최적. 정상 기온 약 12~15도 — 두꺼운 겉옷 필수. 케이블카 대기 오전 15~20분. 팔자레고 주차 무료(넓음).', 99),
  (67, '미수리나 호수', '비용', '해발 1,756m. 이탈리아 돌로미티에서 가장 아름다운 호수 중 하나. 소라피스 산군(3,205m)이 수면에 반영되는 아침 조망 최고. 호수 둘레 약 2.8km의 완만한 산책로 — 60대에 최적. 트레 치메 진입로', '상시 개방', '무료', '32041 Auronzo di Cadore BL', '오전 8~10시 바람 없을 때 수면 반영 최고. 호수 남쪽 주차장 무료. 카페/레스토랑 호수변 위치. 트레 치메 유료도로 진입구가 호수에서 2km.', 100),
  (67, '트레 치메 디 라바레도', '비용', '세계적으로 유명한 돌로미티 3개의 수직 암봉 — 피콜라(2,857m)·그란데(2,999m)·오베스트(2,973m). 1935년 세계 최초 북벽 등반 이후 암벽 등반의 성지. 아우론조 산장(2,333m)까지 차량 진입 가능. 산장에서 북벽 정면 조망 포인트까지 평탄 트레일 약 30분 — 60대 가능. 돌로미티 최고 절경.', '유료도로 06:00~20:00 (여름)', '무료', 'Rifugio Auronzo, 32041 Auronzo di', '유료도로 입구: 미수리나 호수에서 2km. 차량 30 지불 후 진입. 아우론조 산장 주차 후 도보. 북벽 조망 포인트: 산장에서 반시계 방향 30분. 왕복 60분이면 충분.', 101),
  (67, '크리스탈로 케이블카', '비용', '코르티나 북쪽 크리스탈로 산군 접근 케이블카. Son Forca(1,843m)에서 Forcella Staunies(2,932m)까지 2단계. 정상에서 코르티나 담페초 분지 전체, 마르몰라다 빙하, 트레 치메 등 돌로미티 전방위 조망. 고도가 높아 시원하고 맑은 날 시야 최고. 코르티나 4일 중 마지막 하이라이트.', '08:30~17:00 (여름)', '무료', 'Via Cantore, 32043 Cortina', '코르티나 구시가에서 차로 5분. 주차 있음. 성수기 오전 일찍 방문 권장. 정상 기온 10~13도 — 겉옷 필수.', 102),
  (67, '세체다 케이블카 + 능선', '비용', '오르티세이에서 세체다 능선(2,519m)까지 2단계 케이블카. 이탈리아 돌로미티에서 가장 인상적인 능선 조망 중 하나. 사스 리가이스(3,025m) 등 가르데나 협곡 북쪽 암봉군이 파노라마로 펼쳐짐. 능선 상부는 완만한 고원으로 평탄 트레일 산책 가능 — 60대에 최적. 돌로미티 SNS 대표 사진 배경지.', '08:30~17:30 (여름 성수기)', '무료', 'Via Furines 38, 39046 Ortisei BZ', '일요일 성수기 — 오전 08:30~09:00 탑승 권장. 능선 기온 12~15도 — 겉옷 필수. 리푸지오 세체다까지 도보 15분 평탄. 점심 예약 불필요 (현장 착석).', 103),
  (67, '오르티세이 목조각 공방 거리', '비용', '오르티세이(St. Ulrich)는 알프스 목조각 공예의 세계적 중심지. Via Rezia를 중심으로 전통 목조각 공방·갤러리 집중. 성인상·동물·가구부터 현대 추상 작품까지 다양. 라딘어로 조각을 뜻하는 ''스쿨투라''가 마을 정체성. 고급 원목 조각품 기념품으로 최적.', '월~토 09:00~12:30 /', '무료', 'Via Rezia, 39046 Ortisei BZ', '일요일 일부 공방 휴무 가능 — 오전보다 오후 운영 많음. 소형 성인상 15~50, 대형 조각 100 이상. 오르티세이 마을 박물관(Museo della Val Gardena)에서 라딘 문화 전시 무료 관람 가능.', 104),
  (67, '알페 디 시우시 고원', '비용', '해발 1,800~2,350m, 면적 56km². 알프스에서 유럽 최대 규모의 고원 초원. 6월 말~7월 초 야생화 최성기 — 황금빛 미나리아재비 + 보라 아네모네 + 흰 데이지 가득. 남쪽으로 샤슬라(Schlern/Sciliar, 2,563m) 수직 암봉이 극적으로 대비. 소떼·목동·전통 산장(말가)이 그대로 운영. 차량 진입 금지(여름) — 곤돌라', '곤돌라 08:00~18:30 (여름)', '무료', 'Compatsch, 39040 Castelrotto BZ', '6월 29일 야생화 절정 시기. 콤파치 주변 평탄 트레일 — 60대 적합. 고원 내 전기 미니 트랙터 택시 운행(유료). 겉옷 필수 (고원 기온 12~16도).', 105),
  (67, '카스텔로또', '비용', '알토 아디제 대표 전통 남티롤 마을. 15세기 종탑이 있는 광장(Piazza Kraus)을 중심으로 알프스 목조 건물들이 늘어선 그림 같은 마을. 이탈리아이지만 완전한 독일어·오스트리아 문화권. 알페 디 시우시 접근 기지 마을로도 유명. 6월 말 마을 꽃장식(제라늄) 최성기.', '마을 상시 개방', '무료', '39040 Castelrotto BZ', '카스텔로또 종탑: 매시 정각 종소리 울림. 오전 방문 시 인파 적음. 제과점(베케라이)에서 구겔후프·아펠슈트루델 구입 추천.', 106),
  (67, '발 가르데나 SR242 드라이브', '비용', '오르티세이(St. Ulrich) → 산타 크리스티나(St. Christina) → 셀바(Wolkenstein) 약 15km의 돌로미티 협곡 드라이브. 협곡 양쪽으로 세체다 암봉·사스 리가이스 수직 암벽이 연속. 이탈리아 최고의 경관 드라이브 루트 중 하나. 셀바에서 가르데나 파소(2,121m)로 계속 연결.', '상시', '무료', 'SR242, Ortisei → Selva di Val Gardena', 'SR242 왕복 약 30km, 30분. 셀바 마을 광장에서 U턴. 도중 전망 포인트마다 주차 공간 있음.', 107),
  (67, '벨라조', '비용', '코모 호수 3개 지류의 분기점에 위치한 인구 2,000명의 마을. ''이탈리아 호수 지방의 진주''. 꽃이 가득한 계단 골목(살리타 세르포니), 호수변 카페, 빌라 멜치·세르벨로니 등 귀족 빌라 정원. 벨라조 페리 정착지에서 바라보는 호수 분기 조망이 압도적. 전통 코모 실크 제품 기념품.', '마을 상시 개방 / 빌라 세르벨로니 정원', '무료', '22021 Bellagio CO', '페리: 코모 → 벨라조 1시간. 빌라 세르벨로니 정원 투어: 10:00·11:00·15:00·16:00 출발 (영어·이탈리아어). 계단 골목 사진: 아침 일찍 또는 오후 늦게 관광객 적음.', 108),
  (67, '코모 두오모', '비용', '14세기~18세기에 걸쳐 완공. 고딕·르네상스·바로크 양식이 혼합된 독특한 파사드. 내부 르네상스 시대 태피스트리 14장 보존. 파사드 좌우에 로마 시대 작가 대플리니우스(코모 출신)와 소플리니우스 조각상. 영업시간     목~화 12:00~14:30 /                      휴무', '매일 09:00~17:30', '무료', 'Piazza del Duomo, 22100 Como CO', '코모 선착장에서 도보 3분. 이른 오전 방문 시 내부 조용. 태피스트리 감상 후 두오모 광장 카페에서 에스프레소.', 109),
  (67, '빌라 카를로타', '비용', '18세기 귀족 빌라. 1843년 프로이센 공주 카를로타에게 결혼 선물로 증여되어 ''빌라 카를로타''로 명명. 테라스식 4ha 정원: 진달래 500품종·장미·열대 식물원. 7월 장미 최성기. 내부: 안토니오 카노바의 ''사랑과 프시케'' 복제 조각 원본급 보존. 코모 호수 전망 계단식 테라스가 극적.', '매일 09:00~19:30 (3~10월)', '무료', 'Via Regina 2, 22016 Tremezzo CO', '7월 초 장미+진달래 동시 개화 (부분). 입장 후 정원 먼저 탐방 권장. 내부 조각 갤러리 30분. 빌라 카를로타 페리 정착지에서 하선.', 110),
  (67, '바레나', '비용', '코모 호수 동쪽 지류의 인구 800명 소마을. 분홍·노랑·오렌지색 건물들이 절벽에 매달린 모습이 코모 호수의 가장 아름다운 포토 포인트. 바레나 선착장에서 바라보는 맞은편 트레메조·카데나비아 전경도 압도적. 빌라 몬아스테로 정원(8)과 빌라 시르몬도 정원(6)도 인근.', '마을 상시 개방', '무료', '23829 Varenna LC', '바레나: 페리 하선 후 구시가 자유 탐방. 계단 골목은 좁고 계단 많음 — 짧게 30분 이내 추천. 선착장 바로 옆 호수변 카페에서 젤라토+에스프레소.', 111),
  (67, '그란 파라디소 국립공원', '비용', '1922년 설립. 이탈리아 최초 국립공원. 알프스 아이벡스(야생 염소) 최대 서식지 — 코냐 마을 주변에서 흔히 목격 가능. 그란 파라디소 산(4,061m)이 공원 중심. 코냐 마을 → 그란 프라도 완만 초원 산책로 — 60대에 적합. 7월 야생화 절정 시기.', '상시 개방', '무료', 'Frazione Valnontey, 11012 Cogne', '코냐 마을 주차 후 도보 탐방. 그란 프라도 초원(Prato di Sant''Orso) 방향 완만 트레일 30분. 알파인 동물원(Giardino Botanico Alpino Paradisia) 무료 방문 가능. 아이벡스 목격 확률: 이른 아침 높음.', 112),
  (67, '아오스타 로마 극장', '비용', '기원전 1세기 건립. 3,000석 규모 로마 야외 극장. 무대 벽면 3층 구조 일부 보존. 그란 파라디소 방향 알프스 배경과 어우러진 로마 유적 — 독특한 조합. 인근 성벽·아우구스투스 개선문과 묶어 탐방 가능. 영업시간      화~일 12:00~14:30 /                   휴무', '매일 09:00~19:00 (여름)', '무료', 'Via Arco d''Augusto 6, 11100 Aosta', '아오스타 구시가 동쪽 끝. 무료 주차 가능. 로마 극장 → 아우구스투스 개선문 도보 5분. 이른 오전 입장 시 빛 방향 최적.', 113),
  (67, '체르비니아 플라토 로사 케이블카', '비용', '체르비니아에서 2단계 케이블카로 3,488m 플라토 로사 빙하 고원 도달. 이탈리아와 스위스 국경 능선 위. 마터호른(4,478m) 이탈리아 면 정면 조망. 여름에도 스키 가능 빙하 지대. 스위스 체르마트 방향 레만 호수까지 조망 가능. 기온 0~5도 — 방풍·보온 의류 필수.', '08:30~16:30 (여름)', '무료', 'Via Guido Rey, 11021 Breuil-Cervinia', '케이블카 탑승소: 체르비니아 마을 중심. 2단계 연결: 쉬엘트론(2,500m) → 플라토 로사(3,488m). 합산 약 20분. 정상 리푸지오에서 따뜻한 음료 필수. 고산병 주의 — 두통 시 즉시 하산.', 114),
  (67, '라고 블루', '비용', '체르비니아 마을 바로 위 청록색 빙하 호수. 마터호른(체르비노) 수면 반영. 호수 한 바퀴 완만 산책로 약 20~30분 — 60대에 최적. 오전 바람 없을 때 반영 최고. 체르비니아 케이블카 하산 후 방문 추천. 영업시간    매일 12:00~14:30 / 19:00~21:30           휴무', '상시', '무료', '11021 Breuil-Cervinia AO', '체르비니아 마을에서 도보 15분 상행 (완만). 마터호른 반영 최적 포인트: 호수 북동쪽 끝. 오전 10~12시 바람 없는 맑은 날 반영 최고.', 115),
  (67, '스카이웨이 몽블랑 케이블카', '비용', '2015년 개통. 세계 최첨단 360도 회전 케이블카. 쿠르마이외르(1,224m) → 파비용(1,370m) → 피오나이(2,173m) → 폰테 달레 로니스(3,466m) 3단계. 각 곤돌라가 주행 중 360도 회전하며 전방위 파노라마 제공. 정상에서 몽블랑(4,808m) 빙하 벽 정면 조망. ''스카이웨이''라는 이름처럼 하늘 위에서', '08:00~16:30 (여름 / 요일별 차이)', '무료', 'Strada Statale 26 della Valle d''Aosta,', '사전 예약 강력 권장: monterosasky.it. 여름 성수기 매진 빈번. 정상 기온 -2~5도 — 패딩 재킷 필수. 고산병 주의 (3,466m). 맑은 날 마터호른·그랑드 조라스·쿠르마이외르 계곡 전체 조망 가능.', 116),
  (67, '쿠르마이외르 구시가', '비용', '이탈리아 최고급 알파인 리조트. Via Roma를 중심으로 명품 아웃도어 브랜드(몽클레르·아크테릭스·노스페이스 등)와 로컬 공방이 공존. 전통 석조 알파인 건물들이 잘 보존된 구시가. 중세 교회(Sant''Orso) + 알파인 박물관. 7월 여름 성수기 활기.', '마을 상시 개방', '무료', 'Via Roma, 11013 Courmayeur AO', '', 117),
  (67, '앙시 구시가 + 팔레 드 릴', '비용', '14세기 사부아 공국 수도. 티우 강 운하가 구시가를 가로질러 흐르며 운하 위 다리와 꽃으로 장식된 골목이 ''알프스의 베네치아'' 분위기. 팔레 드 릴은 운하 섬 위 12세기 건물로 감옥·법원·조폐국으로 사용됨 — 앙시 가장 유명한 포토 포인트. 목요일 아침 꽃·채소 시장 운영.', '구시가 상시 / 팔레 드 릴', '무료', 'Quai de l''le, 74000 Annecy, France', '팔레 드 릴 최고 사진 포인트: Pont Perrire 다리에서 바라보는 구도. 오전 9~10시 관광객 적음. 목요일 꽃 시장은 7시~12시 (Rue Sainte-Claire 일대).', 118),
  (67, '앙시 호수 유람선', '비용', '앙시 선착장에서 출발하는 1시간 또는 2시간 30분 호수 유람선. 에메랄드빛 알파인 호수 위에서 알프스 봉우리 파노라마 조망. 뒬리에(Duingt) 성채 + 탈루아르(Talloires) 마을 경유. 유럽에서 가장 깨끗한 호수 영업시간      화~일 12:00~14:00 /                     휴무', '10:00~18:00 (여름 1시간 간격', '무료', '2 Place aux Bois, 74000 Annecy,', '선착장: Place aux Bois (구시가 동쪽). 1시간 유람 충분. 선상 우측 자리가 알프스 조망 유리. 성수기 출발 15분 전 탑승 권장.', 119),
  (67, '탈루아르', '비용', '앙시 호수 남동쪽 끝 소마을. 10세기 베네딕트 수도원이 현재 호텔로 운영(오베르주 뒤 페르 아 슈발). 폴 세잔(1896), 폴 고갱, 사진가 알프레드 스티글리츠가 탈루아르를 사랑하여 작품에 담음. 앙시 호수를 향해 돌출된 반도 지형 — 호수 조망 3방향. 7월 수영객 많음.', '마을 상시 개방', '무료', '74290 Talloires-Montmin, France', '탈루아르 주차: 마을 입구 소형 주차장. 수도원 입구 정원은 호텔 투숙객 전용이지만 외부 조망 가능. 호수변 카페에서 커피 한 잔.', 120),
  (67, '고르주 뒤 포시', '비용', '74600 Lovagny, France 아르브 강 지류 포시 강이 수천 년에 걸쳐 석회암을 파낸 좁은 협곡. 최대 폭 1~2m, 깊이 20m의 수직 협곡. 350m 협곡을 철제 다리와 보행로로 통과하는 산책. 협곡 통과 후 ''자갈 바다(Mer de Rochers)'' — 빙하기', '10:00~18:00 (4~10월)', '무료', '305 Chemin des Gorges du Fier,', '로바니(Lovagny) 방향. 클루스에서 D1508 서쪽 30분. 협곡 내부 습하고 서늘 — 여름에도 재킷 권장. 산책 후 입구 카페에서 크레프+커피.', 121),
  (68, '팔레 뒤 뒤크 + 보자르 미술관', '비용', '11세기~18세기 부르고뉴 공국의 궁전. 현재 프랑스 주요 미술관 중 하나. 상설 전시: 필립 더 볼드(용담공)·장 상 퓌르(두려움 없는 자)의 묘비 조각 — 15세기 최고 조각 걸작. 플랑드르·네덜란드 화파 회화. 이집트 고고학 컬렉션. 무료 입장.', '수~월 09:30~18:00, 화요일 휴무', '무료', 'Place de la Libration, 21000 Dijon,', '부르고뉴 공작 묘소: 그랑 살 전시. 묘소 조각 세밀도 압도적. 무료. 투어 1~2시간 권장. 일요일 방문객 많음 — 오전 일찍 방문.', 0),
  (68, '노트르담 드 디종 + 올빼미', '비용', '13세기 고딕 성당. 파사드에 기괴한 가고일·동물 부조가 가득 — 노트르담 드 파리와는 다른 부르고뉴 방식. 성당 북쪽 외벽 구석에 숨겨진 올빼미(쿠에트) 조각 — 만지면 소원이 이루어진다는 전설. 디종 시민들이 영업시간    화~토 12:00~14:00 /                     휴무', '매일 09:00~19:00', '무료', 'Place Notre-Dame, 21000 Dijon,', '올빼미: 성당 북동쪽 외벽 모서리 낮은 위치. 안내판 있음. 구시가 산책 중 꼭 찾아볼 것. 인증 사진 필수.', 1),
  (68, '디종 마지막 아침 산책', '비용', '69일 여행의 대단원. 이른 아침 관광객 없는 리베라시옹 광장 + 팔레 뒤 뒤크 + 노트르담 성당 올빼미. 이탈리아의 로마 유적·시칠리아의 바로크·풀리아의 트룰리·돌로미티의 암봉·코모의 호수·프랑스 알프스의 몽블랑·앙시의 운하·부르고뉴의 와인 — 모든 기억을 안고 귀국.', '이른 아침', '무료', 'Place de la Libration, 21000 Dijon,', '마지막 아침 이른 7~9시: 디종 구시가 가장 조용하고 아름다운 시간. 기념 사진 최적. 이 여행의 마지막 사진.', 2)
) AS s(day_number, name, category, description, opening_hours, entrance_fee, address, tips, sort_order)
ON gd.day_number = s.day_number;

-- 식당 INSERT
INSERT INTO guide_restaurants (day_id, day_number, name, category, price_range, opening_hours, description, sort_order)
SELECT gd.id, r.day_number, r.name, r.category, r.price_range, r.opening_hours, r.description, r.sort_order
FROM guide_days gd
JOIN (VALUES
  (1, '공항 내 간단 식사 (선택)', '식사', 'EUR15~30 (W26,250~52,500) 예약', '공항 영업시간 내 휴무', '도착 첫날 밤 — 오후 10시 이후 외부 식당 영업 거의 없음. 공항 또는 편의점 활용 추천.', 0),
  (2, 'Trattoria Milanese', '식사', 'EUR65~75 (W113,750~131,250) 예약 +39 02 8645 1991', '12:00~14:30, 19:00~22:30 휴무 토요일 점심, 일요일', '1933년 창업. 라 스칼라에서 도보 5분. 목요일 점심 영업 확인. 밀라노 3대 전통 요리 한 번에 경험.', 0),
  (2, 'Luini Panzerotti', '식사', 'EUR10~16 (W17,500~28,000) 예약 +39 02 8646 1917', '10:00~20:00 휴무 일요일', '두오모 바로 옆. 밀라노 명물 간식. 줄 서서 먹는 현지 경험. 트라토리아 대신 가볍게 먹고 싶을 때 대안.', 1),
  (2, 'Mag Cafe (나빌리오 아페리티보)', '식사', 'EUR14~22 (W24,500~38,500) 예약 +39 02 8940 9439', '18:00~02:00 휴무 월요일', '운하변 최고 위치. 아페리티보 뷔페 안주 푸짐. 목요일 성수기 17:30 도착 권장.', 2),
  (3, 'Ratana', '식사', '- 예약 +39 02 8712 8855', '월~금 12:30~14:30, 휴무', 'Porta Garibaldi 재개발 지구 내 현지인 애용 로컬 레스토랑. 수십 년 된 레시피로 만드는 정통 밀라노 가정식.', 0),
  (4, 'Trattoria Sant''Anna', '식사', '- 예약 +39 035 236 899', '화~일 12:00~14:30, 휴무', '100년 가족 경영 트라토리아. 치타 알타 성벽 근처 위치. 현지인과 관광객 모두 즐겨 찾는 정통 베르가모 가정식 전문점.', 0),
  (6, 'Focaccia Riviera', '식사', '- 예약 +39 0185 230900', '매일 07:30~19:30 (월요일 영업) 휴무', '라팔로 최고 평점 포카차 전문점. 월요일도 정상 영업. 점심 가볍게 즐기기에 최적.', 0),
  (6, 'Da Mario', '식사', '- 예약 +39 0185 231118', '화~일 12:00~14:30, 휴무', '룽고마레 해변 도로 위치, 라팔로 만을 바라보며 식사. 월요일 휴무 가능성이 있으므로 출발 전 전화 확인 권장.', 1),
  (7, 'Ristorante Belvedere (Monterosso)', '식사', '- 예약 +39 0187 817543', '매일 12:00~15:00, 19:00~22:00 휴무', '페지나 해변 바로 앞 위치, 바다 전망 테라스 좌석 가능. 몬테로소 앤초비 전문 요리 제공.', 0),
  (7, 'Rosa Bianca (Rapallo 저녁)', '식사', '- 예약 +39 0185 231338', '화~일 12:00~14:30, 휴무', '라팔로 구시가지 중심 위치. 화요일 정상 영업. 친퀘 테레 여행 후 가볍게 즐기기 좋은 합리적 가격대.', 1),
  (9, 'Ristorante San Giuseppe', '식사', '- 예약 +39 0577 42286', '12:30~14:30, 19:30~22:00 휴무', '라팔로 최고 평점 ★4.8. 캄포 광장 도보 5분. 점심 예약 없이도 입장 가능하나 목요일 혼잡 주의.', 0),
  (9, 'Osteria le Logge', '식사', '- 예약 +39 0577 48013', '12:30~14:30, 19:30~22:30 휴무', '캄포 광장 도보 2분 최접근. 현지 미슐랭 추천. 키아니나 스테이크는 시에나 여행 하이라이트 식사.', 1),
  (10, 'Latte di Luna', '식사', '- 예약 +39 0578 748606', '수~월 12:30~14:30, 휴무', '피엔차 구시가지 중심 위치, 현지인 단골 트라토리아. 페코리노 치즈 요리와 피치 파스타 전문.', 0),
  (10, 'Ristorante San Giuseppe (저녁, 시에나)', '식사', '- 예약 +39 0577 42286', '19:30~22:00 (금요일 영업) 휴무', '시에나 최고 평점 ★4.8. 발도르차 드라이브 후 시에나 복귀해 저녁 식사.', 1),
  (11, 'Osteria delle Catene', '식사', '- 예약 +39 0577 941966', '매일 12:00~15:00, 19:00~22:00 휴무', '산 지미냐노 구시가지 중심 위치. 토스카나 전통 요리와 베르나차 와인 페어링.', 0),
  (12, 'Ristorante Porta al Castello', '식사', '- 예약 +39 0577 849196', '매일 12:00~15:00, 19:00~22:00 휴무', '몬탈치노 성문 바로 앞 위치. 일요일 영업. 현지 정통 요리와 몬탈치노 와인 최적 조합.', 0),
  (14, 'Ristorante Il Principe (리스토란테 일 프린치페)', '식사', '- 예약 +39 081 850 5566', '화~일 12:30~14:30 / 휴무', '폼페이 고고학 공원에서 도보 5분. 고대 로마 레시피 재현 요리로 미쉐린 가이드 소개.', 0),
  (14, 'Pizzeria da Michele Pagani (피제리아 다 미켈레 파가니)', '식사', '- 예약 +39 081 916 0000', '매일 12:00~15:00 / 19:00~23:00 휴무', '나폴리 피자 성지 L''Antica Pizzeria da Michele 계열. 파가니 숙소 근처.', 1),
  (15, 'Ristorante La Caravella (라 카라벨라)', '식사', '- 예약 +39 089 871029', '수~월 12:00~14:30 / 휴무', '1959년 창업, 아말피 코스트 최고 식당 중 하나. 두오모 광장 2분 거리.', 0),
  (16, 'Pizzeria Starita a Materdei (스타리타)', '식사', '- 예약 +39 081 557 3682', '화~일 12:00~15:30 / 휴무', '1910년 창업 114년 역사. 나폴리 최고 피자리아 반열. 국립 고고학박물관에서 도보 15분.', 0),
  (17, 'Da Paolino Lemon Trees (다 파울리노)', '식사', '- 예약 +39 081 837 6102', '매일 12:00~15:00 / 19:30~23:00 휴무', '레몬 나무 정원에서 식사하는 카프리 최고 경험. 음식보다 분위기가 특별. 예약 필수.', 0),
  (19, 'Osteria del Corso (오스테리아 델 코르소)', '식사', '- 예약 +39 0963 600 000', '매일 12:30~15:00 / 19:30~22:30 휴무', '트로페아 중심가 위치. 자색 양파 요리 전문. 가성비 우수.', 0),
  (20, 'Lido Azzurro (리도 아주로, 니코테라 마리나)', '식사', '- 예약 +39 0966 000 000', '매일 12:00~15:30 / 19:30~22:30 휴무', '니코테라 마리나 해변 바로 앞. 신선한 지역 해산물. 관광객 없는 로컬 분위기.', 0),
  (22, 'Osteria Manieri (오스테리아 마니에리)', '식사', '- 예약 +39 091 612 0025', '화~일 12:30~15:00 / 휴무', '팔레르모 시내 중심. 시칠리아 향토 요리 전문. 수요일 정상 영업.', 0),
  (23, 'Trattoria I Vitti (트라토리아 이 비스티)', '식사', '- 예약 +39 091 617 3040', '화~일 12:30~15:00 / 휴무', '팔레르모 구시가 정통 시칠리아 가정식. 목요일 정상 영업.', 0),
  (24, 'Ristorante Pingua (리스토란테 핑쿠아)', '식사', '- 예약 +39 091 332 880', '화~일 12:30~15:00 / 휴무', '팔레르모 현대 시칠리아 퀴진 레스토랑. 금요일 정상 영업.', 0),
  (25, 'Osteria di Venere (오스테리아 디 베네레, 에리체)', '식사', '- 예약 +39 0923 869 362', '매일 12:00~15:00 / 19:00~22:00 휴무', '에리체 마을 내 향토 요리 레스토랑. 트라파니 지역 특색 요리.', 0),
  (26, 'Kokalos Restaurant (코칼로스, 아그리젠토)', '식사', '- 예약 +39 0922 600 100', '매일 12:00~15:30 / 19:00~22:30 휴무', '신전의 계곡 입구 인근. 신전 조망하며 점심 가능한 레스토랑.', 0),
