-- 결과 확인
SELECT
  (SELECT COUNT(*) FROM guide_days)          AS days,
  (SELECT COUNT(*) FROM guide_schedules)     AS schedules,
  (SELECT COUNT(*) FROM guide_spots)         AS spots,
  (SELECT COUNT(*) FROM guide_restaurants)   AS restaurants,
  (SELECT COUNT(*) FROM guide_accommodations) AS accommodations,
  (SELECT COUNT(*) FROM guide_tips)          AS tips;
